// v10.72.0 — Distribución: nueva columna jsonb `distribution` en orders + checkbox MUY visible en el
// OrderForm (normal y maquila) que despliega una lista de lugares/direcciones; se imprime como sección
// "🚚 Distribución" en ambas versiones. Toggle Sencillo/Avanzado rediseñado a control segmentado visible.
// Persistencia: distribution agregado a empty, dbCols (saveOrder), editableFields (update) y replicaFields.
// v10.71.7/.8 — impresión: los detalles de Plastificado/Blocks/Folio salen como chip/etiqueta gris
// (.fin-tag) en vez de "(texto)" en negritas; .8 le sube padding (2px 7px) y separación (6px) al chip.
// v10.71.6 — BLOCKER fix (scan de bugs): los sub-inputs libres de Blocks/Folio no aceptaban espacios
// (value={finGetDetail} trimea por tecla). Ahora cada uno tiene su buffer crudo (blocksRaw/folioRaw),
// re-sincronizado al editar/replicar y reseteado al togglear el chip. + "Otro" rastrea su texto previo
// (no acumula colisiones de prefijo) + dedup de submit por string exacto (sin perder customs distintos).
// v10.71.5 — impresión: (1) "fit to one page" — el contenido se reduce con zoom si excede una hoja
// Carta para no partirse en 2 páginas; (2) firmas = Diseño / Preprensa / Producción / Calidad;
// (3) Blocks pasa a detalle de texto libre ("EN BLOCKS DE 100"), ya no "(N pzas)". Coma protegida.
// v10.71.4 — Folio es casilla de pleno derecho en la rejilla de acabados impresa (paridad con Blocks:
// casilla + detalle inline "(del 1000 al 2000)"); se quita la fila suelta del fondo. Antes Folio no
// figuraba como opción en la rejilla impresa, solo aparecía como fila al fondo si estaba seleccionado.
// v10.71.3 — fix: clasificación custom-vs-estándar de acabados ahora canonicaliza con finBase
// en los 3 sitios del OrderForm (seed/replicate/edit) + filtro "Otros" de impresión startsWith-aware,
// para que un acabado con sub-detalle ("Plastificado Brillante") NO se duplique en "Otro"/"Otros".
const SPECIAL_FIN=["Plastificado","Blocks","Folio"];
const finBase=x=>{const m=SPECIAL_FIN.find(b=>x.toLowerCase()===b.toLowerCase()||x.toLowerCase().startsWith(b.toLowerCase()+" "));return m||x};
const finList=s=>String(s||"").split(",").map(x=>x.trim()).filter(Boolean);
// v10.72.49: comparación canónica case-INSENSITIVE (alinea chips, rehidratación e impresión).
// Antes el clause exacto era `x===base` (case-sensitive): un canónico en minúscula (ej. "doblez"
// tecleado en "Otro") palomeaba en la impresión pero NO encendía el chip ni se reconocía al rehidratar.
const finIsCanon=x=>{const b=finBase(x).toLowerCase();return FINISHES.some(f=>f.toLowerCase()===b);};
const finHas=(s,base)=>finList(s).some(x=>x.toLowerCase()===base.toLowerCase()||x.toLowerCase().startsWith(base.toLowerCase()+" "));
const finGetDetail=(s,base)=>{const e=finList(s).find(x=>x.toLowerCase().startsWith(base.toLowerCase()+" "));return e?e.slice(base.length).trim():""};
const finWith=(s,base,detail)=>{const arr=finList(s).filter(x=>!(x.toLowerCase()===base.toLowerCase()||x.toLowerCase().startsWith(base.toLowerCase()+" ")));arr.push(detail?base+" "+detail:base);return arr.join(", ")};
const finWithout=(s,base)=>finList(s).filter(x=>!(x.toLowerCase()===base.toLowerCase()||x.toLowerCase().startsWith(base.toLowerCase()+" "))).join(", ");
// v10.73.4 — equivalencia en kg para productos vendidos por kilo (client_products.specs.sell_unit='kg').
// Convierte un conteo de UNIDADES a kg (units/units_per_kg). Devuelve null si el producto NO es 'kg' (default seguro).
const kgEquiv=(units,specs)=>{const upk=Number(specs&&specs.units_per_kg);if(!specs||specs.sell_unit!=="kg"||!(upk>0))return null;return (Math.abs(Number(units)||0)/upk).toLocaleString(undefined,{maximumFractionDigits:1})+" kg";};
const INT_FLOW=[{id:"draft",l:"📝 Validar",lt:"Validar",Icon:NotePencilIcon,c:"#aeaeb2",who:"both"},{id:"design",l:"🎨 Diseño",lt:"Diseño",Icon:PaletteIcon,c:"#b3567f",who:"preprensa"},{id:"proof_printing",l:"🖨️ Prueba",lt:"Prueba",Icon:PrinterIcon,c:"#6f6cc0",who:"german"},{id:"proof_client",l:"👤 Aprobación",lt:"Aprobación",Icon:UserIcon,c:"#b8902f",who:"preprensa"},{id:"ctp",l:"💿 CTP",lt:"CTP",Icon:DiscIcon,c:"#2c8395",who:"german"},{id:"placas_listas",l:"📋 Placas Listas",lt:"Placas Listas",Icon:ClipboardTextIcon,c:"#2f9aad",who:"produccion"},{id:"ready",l:"✅ Lista para imprimir",lt:"Lista p/ imprimir",Icon:CheckCircleIcon,c:"#3a9e6a",who:"produccion"},{id:"in_production",l:"⚙️ Máquina",lt:"Máquina",Icon:GearIcon,c:"#c07d2e",who:"produccion"},{id:"maquila_out",l:"🚚 Enviada a Maquila (parcial)",lt:"Enviada a Maquila (parcial)",Icon:TruckIcon,c:"#b06a34",who:"produccion"},{id:"maquila_in",l:"📥 Recibida de Maquila (parcial)",lt:"Recibida de Maquila (parcial)",Icon:DownloadSimpleIcon,c:"#4187b5",who:"produccion"},{id:"packaging",l:"📦 Empaque",lt:"Empaque",Icon:PackageIcon,c:"#9c5fb8",who:"produccion"},{id:"salidas",l:"📤 Salidas",lt:"Salidas",Icon:ExportIcon,c:"#2f9a5c",who:"karla"},{id:"delivered",l:"✅ Entregada",lt:"Entregada",Icon:CheckCircleIcon,c:"#3a9e6a",who:null}];
// v10.73.36 — nombres de las etapas de maquila auto-descriptivos ("... a/en/de Maquila") para distinguir el proceso EN CUALQUIER contexto (badge fuera del flujo, Torre, En espera, listas). Los IDs de stage NO cambian (datos intactos); solo l/lt.
const MAQ_FLOW=[{id:"maq_created",l:"📋 Creada (Maquila)",lt:"Creada (Maquila)",Icon:ClipboardTextIcon,c:"#aeaeb2",who:"secretaria"},{id:"maq_sent",l:"🚚 Enviada a Maquila",lt:"Enviada a Maquila",Icon:TruckIcon,c:"#b06a34",who:"secretaria"},{id:"maq_in_progress",l:"⚙️ Proceso en Maquila",lt:"Proceso en Maquila",Icon:GearIcon,c:"#c07d2e",who:"secretaria"},{id:"maq_received",l:"📥 Recibida de Maquila",lt:"Recibida de Maquila",Icon:DownloadSimpleIcon,c:"#4187b5",who:"karla"},{id:"maq_delivered",l:"✅ Entregada (Maquila)",lt:"Entregada (Maquila)",Icon:CheckCircleIcon,c:"#3a9e6a",who:null}];
const ALL_S=[...INT_FLOW,...MAQ_FLOW,{id:"cancelled",l:"❌ Cancelada",lt:"Cancelada",Icon:XCircleIcon,c:"#c84a3f",who:null},{id:"maq_cancelled",l:"❌ Cancelada",lt:"Cancelada",Icon:XCircleIcon,c:"#c84a3f",who:null},{id:"web_pending",l:"🌐 Pedido Web",lt:"Pedido Web",Icon:GlobeIcon,c:"#2f9aad",who:null},{id:"web_rejected",l:"❌ Web Rechazado",lt:"Web Rechazado",Icon:XCircleIcon,c:"#c84a3f",who:null},{id:"stocked",l:"📦 En Stock",lt:"En Stock",Icon:PackageIcon,c:"#2f9e7a",who:null}];
const SM=Object.fromEntries(ALL_S.map(s=>[s.id,s]));
// v10.73.21 — Autor de notas/eventos = la PERSONA (display_name), no el rol genérico. Mapa central rol→persona+color,
// con doble clave: por ROL (notas viejas que guardaban "vendedor"/"produccion") y por NOMBRE (notas nuevas que ya
// guardan "Genaro"/"Gerardo"), para que ambas rendericen igual. Si hay 2ª persona en un rol, su nombre real se
// muestra vía fallback (AUTHOR_NAME[nombre]||nombre). Fuente de verdad al escribir = userName (display_name de la BD).
const ROLE_PEOPLE={produccion:{n:"Gerardo",c:C.ios},preprensa:{n:"Noemí",c:C.dsn},german:{n:"Germán",c:C.ctp},secretaria:{n:"Lupita",c:C.fac},vendedor:{n:"Genaro",c:"#d97706"},karla:{n:"Karla",c:"#a855f7"},admin:{n:"Administrador",c:C.ok},sistema:{n:"Sistema",c:C.t3}};
const AUTHOR_NAME={},AUTHOR_COLOR={};
Object.entries(ROLE_PEOPLE).forEach(([r,m])=>{AUTHOR_NAME[r]=m.n;AUTHOR_NAME[m.n]=m.n;AUTHOR_COLOR[r]=m.c;AUTHOR_COLOR[m.n]=m.c;});
// v10.73.24 — también por USERNAME (login): resuelve a persona los valores viejos guardados como userLogin
// (snoozed_by, eventos de timeline). Solo los usernames que difieren de su rol (el resto ya quedó por rol).
const USER_LOGIN_NAMES={genaro:"Genaro",gerardo:"Gerardo",noemi:"Noemí"};
Object.entries(USER_LOGIN_NAMES).forEach(([lg,nm])=>{if(!AUTHOR_NAME[lg])AUTHOR_NAME[lg]=nm;if(!AUTHOR_COLOR[lg])AUTHOR_COLOR[lg]=AUTHOR_COLOR[nm]||C.t3;});
// v10.61.0 — Badge de etapa/prioridad con icono Phosphor. `l` (con emoji) se conserva
// para contextos de string (toasts, CSV, impresión, timeline, opciones); el badge JSX
// usa Icon+lt vía estos helpers.
const StageLbl=({stage,size=11})=>{const s=SM[stage];const I=s?.Icon;return <>{I?<I size={size} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>:null}{s?.lt||stage}</>;};
const PrioLbl=({priority,size=10})=>{const p=PM[priority];const I=p?.Icon;return <>{I?<I size={size} weight={priority==="urgente"?"fill":"bold"} style={{verticalAlign:"-1px",marginRight:2}}/>:null}{p?.lt||priority}</>;};
// v10.26.0 — Devuelve órdenes de una máquina ordenadas por position (0=activa, 1+=cola)
const getMachineQueue=(orders,machineId)=>orders.filter(o=>o.current_machine===machineId&&o.machine_queue_position!=null).sort((a,b)=>(a.machine_queue_position??999)-(b.machine_queue_position??999));
// v10.27.0 — Zonas del workflow para WIPDashboard (Dinero en Proceso)
// v10.40.0 — Secuencia lineal del workflow para "Regresar al stage anterior".
// Maquila externa es ramificación lateral: maquila_out se considera fuera del flujo lineal;
// si se devuelve algo desde maquila_in se trata como una orden recibida (handler especial).
const STAGE_SEQUENCE=["draft","design","proof_printing","proof_client","ctp","placas_listas","ready","in_production","packaging","salidas","delivered"];

// Áreas (stages que cada rol "controla"). Karla extendida: hasta 2 stages atrás desde salidas.
const ROLE_AREAS={
  preprensa:["design","proof_printing","proof_client"],
  german:["ctp","placas_listas"],
  produccion:["ready","in_production","packaging"],
  karla:["salidas"],
};

// v10.40.0 — Calcular opciones de "Regresar" para un stage actual y rol.
// Devuelve hasta 2 stages destino:
//   1) Stage anterior inmediato (1 atrás en SEQUENCE)
//   2) Stage justo antes del área del rol (último stage del área anterior)
// Si coinciden, devuelve 1 sola opción.
// Filtrado por permisos:
//   - admin: todos los stages, incluido reversiones desde delivered
//   - karla en salidas: permite hasta 2 stages atrás (caso especial confirmado)
//   - otros roles: solo cuando el stage actual está EN su área
//   - delivered → reverso solo admin
function getRevertOptions(currentStage,role){
  if(!currentStage)return [];
  // Stages que nunca son revertibles desde UI
  if(["cancelled","maq_cancelled","maq_delivered","web_pending","web_rejected"].includes(currentStage))return [];
  // Maquila externa: ramificación lateral, no aplicar revert genérico
  if(["maquila_out","maq_sent","maq_in_progress","maquila_in","maq_received","maq_created"].includes(currentStage))return [];
  const idx=STAGE_SEQUENCE.indexOf(currentStage);
  if(idx<=0)return [];
  // delivered: solo admin
  if(currentStage==="delivered"&&role!=="admin")return [];
  // Verificación de área (admin pasa siempre)
  if(role!=="admin"){
    const area=ROLE_AREAS[role];
    if(!area||!area.includes(currentStage))return [];
  }
  const prev=STAGE_SEQUENCE[idx-1];
  let twoBefore=null;
  if(role==="admin"){
    // Admin: ofrecer también el anterior al anterior (2 atrás) si existe
    twoBefore=idx>=2?STAGE_SEQUENCE[idx-2]:null;
  }else if(role==="karla"){
    // Karla en salidas: explícitamente 2 stages atrás (packaging y in_production)
    twoBefore=idx>=2?STAGE_SEQUENCE[idx-2]:null;
  }else{
    // Otros roles: "1 proceso antes de su área" = stage anterior al primer stage del área
    const area=ROLE_AREAS[role];
    if(area&&area.length>0){
      const firstAreaIdx=STAGE_SEQUENCE.indexOf(area[0]);
      const beforeArea=firstAreaIdx>0?STAGE_SEQUENCE[firstAreaIdx-1]:null;
      if(beforeArea&&beforeArea!==prev)twoBefore=beforeArea;
    }
  }
  const opts=[prev];
  if(twoBefore&&twoBefore!==prev)opts.push(twoBefore);
  return opts;
}

// v10.41.0 — Filtros tipo chip para "Mis Pendientes" con counts en vivo.
// `predicate(o, ctx)` recibe la orden y un ctx con utilidades comunes (hoy, etc.).
// Para admin, los filtros base están disponibles + filtro por rol (separado).
function getTaskFilters(role){
  // v10.43.21 — Chips comunes para todos los roles
  // v10.54.6 — Limpieza de ruido visual: 🐢 Estancadas y 💰 Sin precio se muestran
  // condicionalmente según el rol que realmente actúa sobre esa info.
  const common=[
    {key:"urgent",Icon:FireIcon,label:"Urgentes",color:"#dc2626",predicate:o=>o.priority==="urgente"}, // v10.43.20 FIX A9 — lowercase consistente con PRIOS/BD
    // v10.41.1 #5 — defensive slice por si due_date trae tiempo (patrón usado en fD/fDT)
    {key:"late",Icon:AlarmIcon,label:"Retrasos",color:"#f59e0b",predicate:o=>{if(!o.due_date)return false;const due=new Date(String(o.due_date).slice(0,10)+"T23:59:59");return !isNaN(due.getTime())&&due<new Date()}},
  ];
  const isOperative=role==="produccion"||role==="preprensa"||role==="german";
  // v10.54.6 — 🐢 Estancadas: solo roles que actúan sobre WIP atorado (no Lupita ni vendedor).
  // Lupita captura nuevas órdenes y no monitorea WIP; vendedor solo observa, no desatora.
  const showStale = !isSec(role) && role !== "vendedor";
  // v10.43.21 + v10.54.6 — 💰 Sin precio: solo roles que capturan precios.
  // Excluidos: operativos (producción/preprensa/germán) y Lupita (precio lo pone Karla).
  const showPrice = !isOperative && !isSec(role);
  const baseWithStale = showStale ? [...common, {key:"stale",Icon:HourglassIcon,label:"Estancadas",color:"#ea580c",predicate:o=>!!getStale(o)}] : common;
  const base = showPrice ? [...baseWithStale, {key:"no_price",Icon:CurrencyDollarIcon,label:"Sin precio",color:C.sal,predicate:o=>!o.price||Number(o.price)===0}] : baseWithStale;
  if(role==="karla")return[...base,
    {key:"salidas",Icon:ExportIcon,label:"Salidas",color:C.sal,predicate:o=>o.stage==="salidas"},
    {key:"maq_received",Icon:DownloadSimpleIcon,label:"Recibida de Maquila",color:C.maqin,predicate:o=>o.stage==="maq_received"},
    {key:"oc_pending",Icon:ClipboardTextIcon,label:"OC pendiente folio",color:C.prf,predicate:o=>!!o.purchase_order_id&&!o.invoice_folio&&o.stage==="salidas"},
    {key:"pre_assigned",Icon:LockIcon,label:"Pre-asignados",color:C.cart,predicate:o=>!!o.invoice_pre_assigned},
  ];
  if(role==="produccion")return[...base,
    {key:"no_machine",Icon:MouseIcon,label:"Sin máquina",color:C.ios,predicate:o=>o.stage==="ready"&&!o.current_machine},
    {key:"in_production",Icon:GearIcon,label:"En máquina",color:C.amb,predicate:o=>o.stage==="in_production"},
    {key:"maquila_in",Icon:DownloadSimpleIcon,label:"Recibida de Maquila (parcial)",color:C.maqin,predicate:o=>o.stage==="maquila_in"},
    {key:"packaging",Icon:PackageIcon,label:"Empaque pendiente",color:C.emp,predicate:o=>o.stage==="packaging"},
  ];
  if(role==="preprensa")return[...base,
    {key:"drafts",Icon:NotePencilIcon,label:"Drafts",color:"#aeaeb2",predicate:o=>o.stage==="draft"},
    {key:"design",Icon:PaletteIcon,label:"En diseño",color:C.dsn,predicate:o=>o.stage==="design"},
    {key:"waiting_client",Icon:UserIcon,label:"Esperando cliente",color:C.dsn,predicate:o=>o.stage==="proof_client"},
  ];
  // v10.43.19 — Germán: chips de su flujo CTP/placas
  if(role==="german")return[...base,
    {key:"proof_printing",Icon:PrinterIcon,label:"Imprimir prueba",color:C.fac,predicate:o=>o.stage==="proof_printing"},
    {key:"ctp",Icon:WrenchIcon,label:"CTP pendiente",color:C.ctp,predicate:o=>o.stage==="ctp"},
    {key:"placas",Icon:CheckCircleIcon,label:"Placas listas",color:C.live,predicate:o=>o.stage==="placas_listas"},
  ];
  // v10.43.19 — Secretaria (Lupita): captura + esperar cliente + salida
  // v10.54.8 — agregado 🚚 Maquilas (pedido de Marcelo): todas las maquila activas
  // para que Lupita coordine con proveedores externos sin tener que filtrar manualmente.
  if(isSec(role))return[...base,
    {key:"drafts",Icon:NotePencilIcon,label:"Borradores",color:"#aeaeb2",predicate:o=>o.stage==="draft"||o.stage==="maq_created"},
    {key:"maquilas",Icon:TruckIcon,label:"Maquilas",color:C.maq,predicate:o=>o.order_type==="maquila"&&!o.stage.includes("cancelled")&&!o.stage.includes("delivered")&&!o.stage.includes("stocked")},
    {key:"proof_client",Icon:TargetIcon,label:"Prueba cliente",color:C.dsn,predicate:o=>o.stage==="proof_client"},
    {key:"salidas",Icon:ExportIcon,label:"En salida",color:C.sal,predicate:o=>o.stage==="salidas"},
  ];
  // v10.43.19 — Vendedor: por estado agrupado de sus órdenes
  if(role==="vendedor")return[...base,
    {key:"design_zone",Icon:PaletteIcon,label:"En diseño",color:C.dsn,predicate:o=>["design","proof_printing","proof_client","ctp","placas_listas"].includes(o.stage)},
    {key:"production_zone",Icon:GearIcon,label:"En producción",color:C.amb,predicate:o=>["ready","in_production"].includes(o.stage)},
    {key:"delivery_zone",Icon:ExportIcon,label:"Lista entrega",color:C.sal,predicate:o=>["packaging","salidas"].includes(o.stage)},
  ];
  if(role==="admin")return[...base,
    {key:"maquila_ext",Icon:TruckIcon,label:"Maquila externa",color:C.maq,predicate:o=>["maquila_out","maq_sent","maq_in_progress","maquila_in"].includes(o.stage)},
    {key:"proof_client",Icon:TargetIcon,label:"Esperando cliente",color:C.dsn,predicate:o=>o.stage==="proof_client"},
    {key:"in_production",Icon:GearIcon,label:"En máquina",color:C.amb,predicate:o=>o.stage==="in_production"},
    {key:"salidas",Icon:ExportIcon,label:"Salidas",color:C.sal,predicate:o=>o.stage==="salidas"},
  ];
  return base;
}

