  // 🛒 v10.10.0 — Crea OC explícita (compleja) vía RPC atómico
  // Total inicia en 0 y se auto-calcula via trigger conforme se agregan productos
  async createPurchaseOrder({client, client_id, client_email, client_phone, client_rfc, vendedor, deliveryDate, notes, byUser}) {
    const {data, error}=await supabase.rpc("create_purchase_order",{
      p_client: client,
      p_vendedor: vendedor||null,
      p_delivery_date: deliveryDate||null,
      p_notes: notes||null,
      p_total: 0,
      p_created_by: byUser,
      p_client_id: client_id||null,
      p_client_email: client_email||null,
      p_client_phone: client_phone||null,
      p_client_rfc: client_rfc||null
    });
    if(error)throw new Error(error.message);
    return data;
  },
  // ↔️ v10.11.0 Sub-fase A — Mueve orden entre OCs vía RPC atómica
  // El RPC valida invoice_folio, stage, OC destino (no simple/cancelled/folios_locked) y limpia OC origen vacía
  // 🆕 v10.58.22 — forceCrossClient: override CFDI para grupos corporativos multi-razón-social (ej. Hotsson)
  // 🆕 v10.58.23 P1 — el RPC retorna {ok:false, error} en rechazos de negocio SIN lanzar excepción SQL;
  //                  antes el wrapper resolvía silencioso → toast falso de éxito + notifs spam.
  async moveOrderToOC(orderId, targetOCId, actor, forceCrossClient=false) {
    const {data, error}=await supabase.rpc("move_order_to_oc",{
      p_order_id: orderId,
      p_target_oc_id: targetOCId,
      p_actor: actor,
      p_force_cross_client: forceCrossClient
    });
    if(error)throw new Error(error.message);
    if(data && data.ok===false) throw new Error(data.error||"Movimiento rechazado por el servidor");
    return data;
  },
  // 🆕 v10.7.0 — Asigna folio fiscal interno (D-XXXX factura, R-XXXX remisión) y marca entregada
  // Llama RPC atómico que incrementa contador y actualiza orden en una sola transacción
  // ⚠️ DEPRECATED en v10.9.0 — usar assignInvoice. Esta función queda como wrapper de compatibilidad.
  async deliverWithInvoice(orderId, invoiceType, byUser) {
    const {data, error} = await supabase.rpc("deliver_with_invoice", {
      p_order_id: orderId,
      p_invoice_type: invoiceType,
      p_user: byUser
    });
    if(error) throw new Error(error.message);
    return data; // devuelve el folio asignado, ej. "D-5745"
  },
  // 🆕 v10.9.0 — Asignación de folio con captura MANUAL.
  // Maneja tanto el flujo normal (al entregar) como el anticipado (antes de producir).
  // El folio lo escribe Karla; el sistema valida formato, unicidad y stage permitido.
  async assignInvoice(orderId, invoiceType, folio, preAssigned, reason, byUser, paymentStatus, paymentMethod, paymentAmount, bankReference, allowNoPrice, paymentRefs) {
    // v10.49.0 — allowNoPrice (boolean default false)
    // v10.50.0 — paymentRefs (array opcional). Si pasa, NO se mandan campos viejos (method/amount/bankRef).
    const usingMulti = Array.isArray(paymentRefs) && paymentRefs.length > 0;
    const {data, error} = await supabase.rpc("assign_invoice", {
      p_order_id: orderId,
      p_invoice_type: invoiceType,
      p_folio: folio,
      p_pre_assigned: preAssigned,
      p_reason: reason || null,
      p_user: byUser,
      p_payment_status: paymentStatus || null,
      p_payment_method: usingMulti ? null : (paymentMethod || null),
      p_payment_amount: usingMulti ? null : (paymentAmount || null),
      p_bank_reference: usingMulti ? null : (bankReference || null),
      p_allow_no_price: !!allowNoPrice,
      p_payment_refs: usingMulti ? paymentRefs : null
    });
    if(error) throw new Error(error.message);
    return data;
  },
  // 🔗 v10.73.45 · Opción A · Fase 2 — Ligar un folio INDIVIDUAL que ya existe en cobranza (factura de Alpha ERP importada por
  // conciliación/manual) a esta orden, en vez de bloquear con "ya registrado en cobranza". El RPC link_invoice_to_order
  // valida estado de la orden + 4 guards (mismo cliente, sin ligar previo, monto ±0.02 con IVA, existe la factura),
  // estampa el folio (el puente sync_invoice_from_orders salta el duplicado), liga la factura existente
  // (source_order_id) y deja la orden entregada. Espejo del flujo de split (assign_invoice_splits p_allow_link).
  // v10.73.47 — paymentMethod/bankReference: la factura ligada mirror-ea su pago en la orden. El check
  // orders_payment_method_required_if_paid_or_partial EXIGE payment_method si la factura está pagada/parcial;
  // el RPC normaliza (default 'otro' si no viene) pero pasamos el método/ref reales que Karla capturó para exactitud.
  async linkInvoiceToOrder(orderId, folio, actor, paymentMethod, bankReference) {
    const {data, error} = await supabase.rpc("link_invoice_to_order", {
      p_order_id: orderId, p_folio: folio, p_actor: actor,
      p_payment_method: paymentMethod || null, p_bank_reference: bankReference || null
    });
    if(error) throw new Error(error.message);
    return data; // { invoice_status, amount, payment_status, payment_method, ... }
  },
