// v10.58.54: vendedores de ventas CON usuario en PrintFlow — las órdenes de agentes
// fuera de esta lista (Manuel) las persigue/captura Lupita. Si un vendedor nuevo recibe
// usuario, agregarlo aquí (en minúsculas).
const VENDEDORES_CON_USUARIO = new Set(["genaro"]);

// v10.58.67: nombre CANÓNICO de un vendedor (capitaliza la 1ª letra del nombre en el
// Set) — la detección es case-insensitive pero el display/agrupación/semáforo deben usar
// la MISMA forma siempre, si no una maquila capturada con 'genaro' minúscula (vía campo
// "Otro...") salía en un grupo aparte y el chip "Genaro" mostraba falso verde.
function vendorDisplayName(ag){
  const low=String(ag||"").trim().toLowerCase();
  return low ? low.charAt(0).toUpperCase()+low.slice(1) : "";
}
// v10.58.65 (decisión de Marcelo): responsable EFECTIVO de una orden. Igual que
// STAGE_RESPONSIBLE, salvo que el pendiente de una MAQUILA con proveedor externo
// (maq_created/sent/in_progress) le toca al VENDEDOR que la vendió si tiene usuario en
// la app (Genaro conoce a su proveedor y su costo); si el agente no tiene usuario
// (Manuel) o no hay, queda en Lupita. maq_received (Karla asigna folio) NO cambia.
// Fuente ÚNICA de verdad — la usan diagnoseOrder, el strip de las cards, los nudges
// y Salud Operativa, para que la atribución sea consistente en todo el app.
function orderResponsible(o){
  const base = STAGE_RESPONSIBLE[o?.stage];
  if(base && o?.order_type==="maquila" && base.role==="secretaria"){
    const ag=(o?.agent||"").trim();
    if(ag && VENDEDORES_CON_USUARIO.has(ag.toLowerCase())) return {role:"vendedor", name:vendorDisplayName(ag)};
  }
  return base;
}

// v10.64.1 fix — destino de notificación del responsable. Si el responsable efectivo es un
// vendedor con usuario (maquila→vendedor en orderResponsible), la notif debe ir a su USERNAME
// (o.agent, p.ej. "genaro"), NO al literal "vendedor" que ningún usuario escucha
// (loadNotifications filtra .eq(target_role, username)). Para roles reales devuelve el rol tal cual.
function responsibleNotifyTarget(o, role){
  if(role==="vendedor") return (o?.agent||"").trim().toLowerCase() || null;
  return role;
}

const TERMINAL_STAGES = ["delivered","maq_delivered","cancelled","maq_cancelled","web_pending","web_rejected"];

function getTopPriority(activeOrders) {
  let topScore = -1, topOrder = null;
  activeOrders.forEach(o => {
    let score = 0;
    if (o.due_date && isOverdue(o.due_date)) score += 1000;
    else if (o.due_date && new Date(String(o.due_date).slice(0,10) + "T12:00:00") <= new Date(Date.now() + 2*86400000)) score += 500;
    const st = getStale(o);
    if (st?.lv === "critical") score += 300;
    else if (st?.lv === "warning") score += 100;
    const money = o.order_type === "maquila" ? Number(o.maq_price) || 0 : Number(o.price) || 0;
    score += Math.min(money / 1000, 500);
    if (score > topScore) { topScore = score; topOrder = o; }
  });
  return topOrder;
}

function getIncompleteData(orders) {
  const active = orders.filter(o => !TERMINAL_STAGES.includes(o.stage));
  const fileStages = ["proof_printing","proof_client","ctp","placas_listas","ready","in_production","packaging","salidas"];
  return {
    vencidas: active.filter(o => o.due_date && isOverdue(o.due_date)),
    sinFecha: active.filter(o => !o.due_date),
    sinPrecio: active.filter(o => o.order_type === "maquila" ? (!o.maq_price || Number(o.maq_price) === 0) : (!o.price || Number(o.price) === 0)),
    sinCantidad: active.filter(o => !o.quantity || Number(o.quantity) === 0),
    sinArchivoStageAvanzado: active.filter(o => fileStages.includes(o.stage) && !o.file_url && !o.image_url && !o.image_url_2),
    sinTelefono: active.filter(o => !o.client_phone),
    sinEmail: active.filter(o => !o.client_email),
    sinAgente: active.filter(o => !o.agent),
    maquilaSinProveedor: active.filter(o => o.order_type === "maquila" && !o.maq_provider),
    // v10.73.5 — maquilas sin COSTO de proveedor capturado (maq_cost). Distinto de "Sin precio"
    // (que en maquila mira maq_price, el precio al cliente). El costo se necesita para el margen y para recibir.
    maquilaSinCosto: active.filter(o => o.order_type === "maquila" && (!o.maq_cost || Number(o.maq_cost) === 0))
  };
}

function getOrphanOCs(purchaseOrders, orders) {
  if (!purchaseOrders || !Array.isArray(purchaseOrders)) return [];
  return purchaseOrders.filter(po =>
    po.status !== "cancelled" &&
    !orders.some(o => o.purchase_order_id === po.id && !["cancelled","maq_cancelled"].includes(o.stage))
  );
}
const getProgress=o=>{if(o.stage==="stocked"){const flow=o.order_type==="maquila"?MAQ_FLOW:INT_FLOW;return{cur:flow.length,tot:flow.length,pct:100}}const flow=o.order_type==="maquila"?MAQ_FLOW:INT_FLOW;const idx=flow.findIndex(s=>s.id===o.stage);return{cur:idx+1,tot:flow.length,pct:Math.round(((idx+1)/flow.length)*100)}};

// Calcula fecha de entrega para pedidos web según reglas de negocio.
// Reglas: Digital=4d hábiles · Offset=8d · Acabados (cualquiera) +3d
// Días hábiles = lun-vie (saltea sábados y domingos).
// startDate: Date object o ISO string. Default: hoy.
// method: "digital" | "offset" | null/undefined (asume "offset" por seguridad).
// finishes: string del campo finishes ("Laminado, Barniz UV") o vacío.
// Returns: string YYYY-MM-DD.
const calcDeliveryDate=(startDate,method,finishes)=>{
  const start=startDate?new Date(startDate):new Date();
  const baseDays=method==="digital"?4:8;
  const hasFinishes=!!(finishes&&finishes.trim());
  const totalDays=baseDays+(hasFinishes?3:0);
  const d=new Date(start);d.setHours(12,0,0,0);
  let added=0;
  while(added<totalDays){
    d.setDate(d.getDate()+1);
    const day=d.getDay(); // 0=dom, 6=sáb
    if(day!==0&&day!==6)added++;
  }
  return d.toISOString().slice(0,10);
};

