// v10.16.0 — Helper para comprimir imágenes ANTES de subir.
// SOLO se usa en el campo "📷 Imagen" (image_url). NUNCA en archivos de producción (file_url).
// Estrategia conservadora:
//   - Si la imagen ya es pequeña (<500KB) y de dimensiones razonables (<=1920px), retorna el original sin tocar.
//   - Si es grande, hace resize a max 1920px (manteniendo aspect ratio) + re-encode JPEG quality 0.92.
//   - Si por algún motivo la compresión NO reduce tamaño, retorna el original.
//   - Solo procesa JPG/PNG/WEBP. GIF, BMP, etc. pasan sin tocar.
const compressImg = (file, maxDim=1920, q=0.92) => new Promise((resolve) => {
  // v10.24.1 — null-check de file.type y file.name (algunos navegadores no los setean siempre)
  if (!file.type || !/^image\/(jpe?g|png|webp)$/i.test(file.type)) { resolve(file); return; }
  const img = new Image();
  const url = URL.createObjectURL(file);
  img.onload = () => {
    URL.revokeObjectURL(url);
    let { width:w, height:h } = img;
    if (file.size < 500*1024 && w <= maxDim && h <= maxDim) { resolve(file); return; }
    if (w > maxDim || h > maxDim) {
      const r = Math.min(maxDim/w, maxDim/h);
      w = Math.round(w*r); h = Math.round(h*r);
    }
    const canvas = document.createElement("canvas");
    canvas.width = w; canvas.height = h;
    canvas.getContext("2d").drawImage(img, 0, 0, w, h);
    canvas.toBlob(blob => {
      if (!blob || blob.size >= file.size) { resolve(file); return; }
      const safeName = (file.name || "image").replace(/\.[^.]+$/, ".jpg");
      resolve(new File([blob], safeName, { type: "image/jpeg" }));
    }, "image/jpeg", q);
  };
  img.onerror = () => { URL.revokeObjectURL(url); resolve(file); };
  img.src = url;
});
// v10.72.70 — Comprime AGRESIVO un Blob de imagen YA subido (archivado >30 días): resize a maxDim px + JPEG
// calidad baja, para conservar la imagen de la orden ocupando lo mínimo (suficiente para identificarla/repetirla;
// el print la muestra a ≤180px). A diferencia de compressImg, recibe un Blob (descargado de Storage) y NO conserva
// el original: si no es imagen procesable o la compresión no reduce tamaño, devuelve null (el llamador deja el original).
const compressBlobHard = (blob, maxDim=640, q=0.45) => new Promise((resolve) => {
  try {
    if (!blob || !/^image\/(jpe?g|png|webp)$/i.test(blob.type||"")) { resolve(null); return; }
    const url = URL.createObjectURL(blob);
    const img = new Image();
    img.onload = () => {
      try {
        let { width:w, height:h } = img;
        if (!w || !h) { URL.revokeObjectURL(url); resolve(null); return; }
        // Si ya está dentro del target (p.ej. una imagen YA archivada que se reprocesa porque su hermana falla red),
        // NO re-encodear: evita generation loss acumulativo. Una imagen ≤maxDim ya cumple el objetivo de espacio.
        if (w <= maxDim && h <= maxDim) { URL.revokeObjectURL(url); resolve(null); return; }
        const r = Math.min(maxDim/w, maxDim/h); w = Math.round(w*r); h = Math.round(h*r);
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        canvas.getContext("2d").drawImage(img, 0, 0, w, h);
        canvas.toBlob(out => { URL.revokeObjectURL(url); resolve(out && out.size < blob.size ? out : null); }, "image/jpeg", q);
      } catch { URL.revokeObjectURL(url); resolve(null); }
    };
    img.onerror = () => { URL.revokeObjectURL(url); resolve(null); };
    img.src = url;
  } catch { resolve(null); }
});
const lbl={display:"block",fontSize:10,fontWeight:600,color:C.t2,textTransform:"uppercase",letterSpacing:.3,marginBottom:6};
const bt=(bg,c="#fff")=>({background:bg,color:c,border:"none",borderRadius:10,padding:"10px 18px",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"'Geist',sans-serif",display:"inline-flex",alignItems:"center",gap:6});
const bs=(bg,c="#fff")=>({...bt(bg,c),padding:"6px 14px",fontSize:11,borderRadius:10,minHeight:40}); // v10.72.18 — touch target ~40px de ALTO (solo minHeight: no cambia el ancho → no rompe las filas densas de íconos; además alinea con los bt de la misma fila)
// v10.72.39 — /impeccable polish: handlers de hover compartidos (leve elevación) para los botones de acción del header. El transition global de box-shadow lo anima; en leave vuelve a sin sombra.
const hoverLift={onMouseEnter:e=>{e.currentTarget.style.boxShadow="0 2px 8px -2px rgba(26,26,31,.22)"},onMouseLeave:e=>{e.currentTarget.style.boxShadow="none"}};
// v10.72.40 — /impeccable craft (command palette): plataforma para el hint de teclado (⌘ en Mac, Ctrl en Windows) + estilo de keycap.
const isMac=typeof navigator!=="undefined"&&/mac/i.test(navigator.userAgent||"");
const kbdSt={fontFamily:"'Geist',sans-serif",fontSize:10,fontWeight:700,lineHeight:1,color:C.t3,background:C.sf,border:"0.5px solid "+C.bd,borderRadius:5,padding:"2px 5px",minWidth:16,display:"inline-flex",alignItems:"center",justifyContent:"center"};
// v10.72.30 — /impeccable extract: vocabulario ÚNICO de badges. Reemplaza decenas de <span> inline con estilos
// derivados (cada uno con padding/radio/peso ligeramente distinto). `tone` da el rol semántico: context=gris
// (recede), danger=rojo, warn=ámbar, success, info, identity=slate. `color` permite un tinte puntual (ej. color
// de etapa). `strong` sube el peso (excepción fuerte). Migrado el badge-row del OCard; el resto puede migrar
// incremental (DetailModal, vistas de lista) reusando este mismo componente.
const BADGE_TONES={context:{bg:C.sf,fg:C.t2,fw:600},identity:{bg:C.acL,fg:C.ac,fw:600},danger:{bg:C.dn+"15",fg:C.dn,fw:700},warn:{bg:C.amb+"15",fg:C.amb,fw:700},success:{bg:C.ok+"12",fg:C.ok,fw:700},info:{bg:C.ios+"12",fg:C.ios,fw:700}};
function Badge({tone="context",color,icon,title,strong,children,style}){const t=BADGE_TONES[tone]||BADGE_TONES.context;return <span title={title} style={{display:"inline-flex",alignItems:"center",gap:children!=null?4:0,padding:"2px 8px",borderRadius:6,fontSize:10,fontWeight:strong?800:(t.fw||600),lineHeight:1.45,whiteSpace:"nowrap",background:color?color+"15":t.bg,color:color||t.fg,...style}}>{icon}{children}</span>;}
// v10.61.5 — input de búsqueda con icono Phosphor (lupa) a la izquierda en vez de
// emoji en el placeholder. wrapStyle controla el layout del contenedor (flex/width).
function SearchInput({style={},wrapStyle={},iconSize=13,...rest}){
  return <div style={{position:"relative",display:"flex",alignItems:"center",...wrapStyle}}>
    <MagnifyingGlassIcon size={iconSize} weight="bold" style={{position:"absolute",left:11,top:"50%",transform:"translateY(-50%)",color:C.ph,pointerEvents:"none"}}/>
    <input {...rest} data-pf-search="1" style={{...style,paddingLeft:32,boxSizing:"border-box"}}/>
  </div>;
}

// v10.65.0 — bloque skeleton (shimmer .pf-skel) para estados de carga con forma del contenido
const Skel=({w="100%",h=12,r=8,style={}})=><div className="pf-skel" style={{width:w,height:h,borderRadius:r,flexShrink:0,...style}}/>;
// lista skeleton: n filas tipo registro (avatar + 2 líneas + monto) para listas que cargan
const SkelRows=({n=5})=><div style={{display:"flex",flexDirection:"column",gap:6,padding:"4px 0"}}>{Array.from({length:n}).map((_,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px"}}><Skel w={34} h={34} r={9}/><div style={{flex:1,display:"flex",flexDirection:"column",gap:6}}><Skel w="55%" h={11}/><Skel w="32%" h={9}/></div><Skel w={52} h={14} r={6}/></div>)}</div>;
// v10.66.0 — empty state compuesto reutilizable (icono + título + hint que guía + acción opcional).
// Unifica el patrón ya existente en varias vistas. tone "positive" = estado sano (icono verde fill).
const EmptyState=({icon:Ic,title,hint,action,tone="neutral"})=>{const pos=tone==="positive";return <div style={{textAlign:"center",padding:"40px 20px"}}>{Ic&&<div style={{display:"flex",justifyContent:"center",marginBottom:10}}><Ic size={46} weight={pos?"fill":"regular"} color={pos?C.ok:C.ph}/></div>}<div style={{fontSize:15,fontWeight:700,color:C.tx}}>{title}</div>{hint&&<div style={{fontSize:12,color:C.t2,marginTop:4,maxWidth:330,marginLeft:"auto",marginRight:"auto",lineHeight:1.45}}>{hint}</div>}{action&&<button onClick={action.onClick} style={{...bt(C.sf,C.t2),marginTop:14,border:"0.5px solid "+C.bd}}>{action.icon&&<action.icon size={12} weight="bold" style={{verticalAlign:"-2px",marginRight:4}}/>}{action.label}</button>}</div>;};

