              <div style={{fontSize:13,color:C.tx,lineHeight:1.5,paddingTop:3,display:"flex",alignItems:"flex-start",gap:6}}>{SIcon?<SIcon size={15} weight="bold" style={{flexShrink:0,marginTop:1,color:C.ac}}/>:null}<span>{s.t}</span></div>
