// ─── FLOW DIAGRAM ──────────────────────────────────
function FlowDiagram({currentStage,orderType,onClose}) {
  useEscClose(onClose);
  const flow=orderType==="maquila"?MAQ_FLOW:INT_FLOW;
  const ci=flow.findIndex(s=>s.id===currentStage);
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}} onClick={onClose}>
      <div style={{background:C.bg,borderRadius:20,padding:28,maxWidth:460,width:"90%",maxHeight:"80vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>
        <h3 style={{fontSize:16,fontWeight:800,margin:"0 0 16px",textAlign:"center"}}>{orderType==="maquila"?<><TruckIcon size={16} weight="bold" style={{verticalAlign:"-2px",marginRight:4}}/>Flujo Maquila</>:<><FactoryIcon size={16} weight="bold" style={{verticalAlign:"-2px",marginRight:4}}/>Flujo Producción</>}</h3>
        {flow.map((s,i) => {
          const done=i<ci, active=i===ci;
          return (
            <div key={s.id} style={{display:"flex",alignItems:"center",gap:12,marginBottom:i<flow.length-1?4:0}}>
              <div style={{display:"flex",flexDirection:"column",alignItems:"center",width:32}}>
                <div style={{width:28,height:28,borderRadius:"50%",background:done?C.ok:active?s.c:C.sf,color:done||active?"#fff":C.t3,display:"flex",alignItems:"center",justifyContent:"center",fontSize:done?14:12,fontWeight:700,border:active?"3px solid "+s.c:"none",boxShadow:active?"0 0 0 4px "+s.c+"20":"none"}}>{done?<CheckIcon size={14} weight="bold"/>:i+1}</div>
                {i<flow.length-1 && <div style={{width:2,height:20,background:done?C.ok:C.bd}}/>}
              </div>
              <div style={{flex:1,padding:"6px 0"}}>
                <div style={{fontSize:13,fontWeight:active?700:500,color:active?s.c:done?C.ok:C.tx,display:"inline-flex",alignItems:"center"}}><StageLbl stage={s.id} size={13}/></div>
                {active && <div style={{fontSize:11,color:C.t2}}>← Estás aquí</div>}
              </div>
            </div>
          );
        })}
        <button onClick={onClose} style={{...bt(C.sf,C.t2),width:"100%",justifyContent:"center",marginTop:16,border:"0.5px solid "+C.bd}}>Cerrar</button>
      </div>
    </div>
  );
}

// ─── SMALL COMPONENTS ──────────────────────────────
function FC({label:lb,children,req,rec,br}) {
  return <div style={{padding:"12px 20px",...(br?{borderRight:"0.5px solid "+C.bd}:{})}}><label style={lbl}>{lb}{req && <span style={{color:C.ac}}> *</span>}{rec && <span style={{color:C.wn,fontSize:9,fontWeight:500}}> (recomendado)</span>}</label>{children}</div>;
}
function GuideBanner({text,color=C.ac}) {
  return <div style={{background:color+"08",border:"1px solid "+color+"20",borderRadius:12,padding:"10px 14px",marginBottom:10,fontSize:12,color:C.tx,fontWeight:500}}>{text}</div>;
}
function ProgressBar({order}) {
  const {cur,tot,pct:p}=getProgress(order); const s=SM[order.stage];
  return <div style={{marginTop:6}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}><span style={{fontSize:9,color:C.t2}}>Progreso</span><span style={{fontSize:9,color:s?.c,fontWeight:600}}>{cur}/{tot}</span></div><div style={{background:C.sf,borderRadius:4,height:6,overflow:"hidden"}}><div style={{width:"100%",height:"100%",background:s?.c||C.ac,borderRadius:4,transformOrigin:"left",transform:"scaleX("+(p/100)+")",transition:"transform .5s cubic-bezier(.22,1,.36,1)"}}/></div></div>;
}
function LiveTimer({started}) {
  const [el,setEl]=useState(0);
  // v10.28.2 — guard NaN si started es inválido; evita render "⏱ NaNm"
  useEffect(()=>{if(!started)return;const t=new Date(started);if(isNaN(t.getTime()))return;const c=()=>Math.round((Date.now()-t.getTime())/60000);setEl(c());const iv=setInterval(()=>setEl(c()),30000);return ()=>clearInterval(iv)},[started]);
  if(!started) return null;
  const t=new Date(started);if(isNaN(t.getTime())) return null;
  return <span style={{fontSize:10,color:C.ios,fontWeight:700,fontFamily:"'Geist Mono',monospace",background:C.ios+"10",padding:"2px 6px",borderRadius:6,display:"inline-flex",alignItems:"center",gap:3}}><ClockIcon size={10} weight="bold"/>{fmtM(el)}</span>;
}
function Timeline({tl=[]}) {
  const [op,setOp]=useState(false);
  if(!tl?.length) return null;
  const show=op?tl:tl.slice(-3);
  return <div style={{marginTop:6}}><button onClick={()=>setOp(!op)} style={{...bs(C.sf,C.t2),boxShadow:"0 0 0 0.5px "+C.bd,padding:"4px 10px",fontSize:10}}><ClockCounterClockwiseIcon size={11} weight="bold"/>({tl.length}) {op?<CaretUpIcon size={10} weight="bold"/>:<CaretDownIcon size={10} weight="bold"/>}</button>{(op||tl.length<=3)&&<div style={{marginTop:6,borderLeft:"2px solid "+C.bd,paddingLeft:12}}>{show.map((e,i)=><div key={i} style={{marginBottom:5}}><div style={{fontSize:10,color:C.tx,fontWeight:500}}>{e.action}</div><div style={{fontSize:10,color:C.t3}}><span style={{color:AUTHOR_COLOR[e.by]||C.t3,fontWeight:600}}>{AUTHOR_NAME[e.by]||e.by||""}</span>{e.by?" · ":""}{fDT(e.date)}</div></div>)}</div>}</div>;
}
// 🆕 v10.58.41 — Historial campo-a-campo de cambios (lee order_change_log).
// Carga on-demand al expandir. Muestra: campo · antes → después · quién · cuándo.
function OrderChangeHistory({orderId}) {
  const [open,setOpen]=useState(false);
  const [rows,setRows]=useState(null);
  const [loading,setLoading]=useState(false);
  const load=async()=>{
    // v10.58.43 #34: refetch en cada apertura — antes cacheaba para siempre y las
    // ediciones posteriores no aparecían al re-expandir.
    setLoading(true);
    try{const data=await db.getOrderChangeLog(orderId);setRows(data);}
    catch(e){console.error("[OrderChangeHistory]",e);setRows([]);}
    finally{setLoading(false);}
  };
  const toggle=()=>{const n=!open;setOpen(n);if(n)load();};
  const fmtV=(field,v)=>{
    if(v===null||v===undefined||v==="")return "(vacío)";
    if(field==="price"||field==="maq_cost"||field==="maq_price"){const n=Number(v);return isNaN(n)?v:fmt(n);}
    if(field==="due_date")return fD(v);
    if(field==="standard_size")return ssLabel(v)||v;
    if(typeof v==="string"&&v.length>50)return v.substring(0,50)+"…";
    return String(v);
  };
  return <div onClick={e=>e.stopPropagation()} style={{marginTop:6}}>
    <button onClick={toggle} style={{...bs(C.sf,C.t2),boxShadow:"0 0 0 0.5px "+C.bd,padding:"4px 10px",fontSize:10}}>
      <ClockIcon size={11} weight="bold"/>Historial de cambios {open?<CaretUpIcon size={10} weight="bold"/>:<CaretDownIcon size={10} weight="bold"/>}
    </button>
    {open&&<div style={{marginTop:6}}>
      {loading?<div style={{fontSize:10,color:C.t3,padding:"6px 0"}}>Cargando…</div>:
       (rows&&rows.length>0)?<div style={{borderLeft:"2px solid "+C.bd,paddingLeft:12,display:"flex",flexDirection:"column",gap:6}}>
        {rows.map((r,i)=><div key={i} style={{fontSize:10}}>
          <div style={{color:C.tx,fontWeight:600}}>{r.field_label||r.field}</div>
          <div style={{color:C.t2}}>
            <span style={{color:C.dn}}>{fmtV(r.field,r.value_before)}</span>
            {" → "}
            <span style={{color:C.ok}}>{fmtV(r.field,r.value_after)}</span>
          </div>
          <div style={{color:C.t3,fontSize:9}}>
            <span style={{color:AUTHOR_COLOR[r.changed_by]||C.t3,fontWeight:600}}>{AUTHOR_NAME[r.changed_by]||r.changed_by}</span>
            {" · "}{fDT(r.changed_at)}
            {r.stage_at_change&&<span> · <StageLbl stage={r.stage_at_change} size={9}/></span>}
          </div>
        </div>)}
      </div>:<div style={{fontSize:10,color:C.t3,padding:"6px 0"}}>Sin cambios registrados todavía.</div>}
    </div>}
  </div>;
}
// v10.58.53: día LOCAL (México) — toISOString() cambia de día a las 6pm hora MX y
// rompía el despertador (doble en la tarde, ausente a la mañana siguiente).
function localDayStr(d=new Date()){const p=x=>String(x).padStart(2,"0");return d.getFullYear()+"-"+p(d.getMonth()+1)+"-"+p(d.getDate());}
// v10.58.53: días HÁBILES desde una fecha (los lunes la Torre marcaba 🐢 todo lo
// avanzado el viernes — consistente con calcDeliveryDate que ya usa días hábiles).
function bizDaysSince(date){
  const from=new Date(date); if(isNaN(from.getTime()))return 0;
  // v10.58.55 REG#1: contar por LÍMITES de día-calendario (no time-of-day) — una
  // orden que entró HOY da 0, no 1. El conteo viejo avanzaba al día siguiente ANTES
  // de evaluar y sumaba +1 a toda entrada del mismo día (falsos "hace 1 día").
  const cur=new Date(from.getFullYear(),from.getMonth(),from.getDate());
  const n=new Date(); const end=new Date(n.getFullYear(),n.getMonth(),n.getDate());
  let d=0;
  while(cur<end){ cur.setDate(cur.getDate()+1); const dow=cur.getDay(); if(dow!==0&&dow!==6)d++; if(d>365)break; }
  return d;
}
// 🗼 v10.58.52 — TORRE DE CONTROL: motor de diagnóstico central.
// snoozeActive: la orden está marcada "en espera" (Torre) — se auto-desactiva si
// cambia de etapa o si pasa la fecha límite.
// v10.73.19 (F2) — Historial de tiempos por etapa: reconstruye del timeline cuánto estuvo la orden en cada etapa
// (neteando pausas "En espera" y fines de semana), el día/hora de cada paso, quién la movió, y las regresiones.
// Vuelve objetivo el "se echan la bolita": el registro muestra exactamente cuándo entró/salió de cada etapa y quién.
function StageFlowHistory({order:o}){
  const [open,setOpen]=useState(false);
  const data=useMemo(()=>{
    const tl=(o?.timeline||[]).filter(t=>t?.date&&!isNaN(new Date(t.date).getTime())).slice().sort((a,b)=>new Date(a.date)-new Date(b.date));
    const nowISO=new Date().toISOString();
    const isFinal=s=>/delivered|cancelled|stocked|maq_delivered|maq_cancelled|web_rejected/.test(s||"");
    // ventana de pausa: desde "🔕 En espera" hasta el 1er evento posterior que sea "🔔 Reactivada" o una transición real
    // (los eventos neutros —edición/merma/precio— NO la cortan); si sigue abierta cierra en el vencimiento (si ya pasó) o ahora.
    // v10.73.44b — tope de una pausa AÚN ABIERTA: el más TEMPRANO entre (a) vencimiento snooze_until y (b) auto-lift far_due
    // (due − 5 días hábiles, v10.73.44). Si el instante de lift es futuro (aún lejana), no topa (falla el test <end=ahora) → la
    // pausa sigue corriendo hasta ahora, correcto. Espeja en el timeline lo que snoozeActive ya hace computado.
    const _capUntil=o?.snooze_until?new Date(String(o.snooze_until).slice(0,10)+"T23:59:59").toISOString():null;
    const _capFarDue=(o?.snooze_kind==="far_due"&&o?.due_date)?bizDaysBefore(o.due_date,5).toISOString():null;
    const snoozeCapISO=(_capUntil&&_capFarDue)?(_capUntil<_capFarDue?_capUntil:_capFarDue):(_capUntil||_capFarDue);
    const pauses=[]; tl.forEach((t,i)=>{ if(!/En espera/i.test(t.action||""))return; let end=null; for(let j=i+1;j<tl.length;j++){ if(/Reactivada|En espera/i.test(tl[j].action||"")||tl[j].to){ end=tl[j].date; break; } } if(!end){ end=nowISO; if(snoozeCapISO&&new Date(snoozeCapISO)<new Date(end))end=snoozeCapISO; } if(new Date(end)<new Date(t.date))end=t.date; pauses.push({start:t.date,end}); });
    // el evento "📋 Orden creada" YA trae to=etapa inicial + by=creador → NO lo tratamos como transición (evita fila duplicada)
    const created=tl.find(t=>/Orden creada/i.test(t.action||""));
    const trans=tl.filter(t=>t.to&&!/Orden creada/i.test(t.action||""));
    const seqIdx=s=>STAGE_SEQUENCE.indexOf(s);
    let segs=[];
    if(trans.length===0){
      if(o?.created_at&&!isFinal(o.stage)) segs=[{stage:o.stage,at:o.created_at,by:created?.by||o.created_by,current:true,isReg:false,hours:bizHoursBetween(o.created_at,nowISO,pauses)}];
    } else {
      const initStage=created?.to||(o.order_type==="maquila"?"maq_created":"draft");
      if(o.created_at&&new Date(o.created_at)<new Date(trans[0].date)) segs.push({stage:initStage,at:o.created_at,by:created?.by||o.created_by,current:false,isReg:false,hours:bizHoursBetween(o.created_at,trans[0].date,pauses)});
      trans.forEach((t,i)=>{ const last=i===trans.length-1; const endpoint=last&&isFinal(t.to); const end=last?(endpoint?t.date:nowISO):trans[i+1].date; const prev=segs.length?segs[segs.length-1].stage:null; const isReg=/^↩️/.test(t.action||"")||(!!prev&&seqIdx(t.to)>=0&&seqIdx(prev)>=0&&seqIdx(t.to)<seqIdx(prev)); segs.push({stage:t.to,at:t.date,by:t.by,current:last&&!endpoint,endpoint,isReg,hours:bizHoursBetween(t.date,end,pauses)}); });
    }
    return {segs,regs:segs.filter(s=>s.isReg).length};
  },[o]);
  if(!data.segs.length) return null;
  const fmtDur=h=>{ if(h==null)return "—"; if(h<1)return Math.max(1,Math.round(h*60))+"m"; if(h<9.95)return h.toFixed(1)+"h"; const H=Math.round(h); if(H<24)return H+"h"; const d=Math.floor(H/24),hr=H%24; return d+"d"+(hr?" "+hr+"h":""); };
  return <div onClick={e=>e.stopPropagation()} style={{marginTop:6}}>
    <button onClick={()=>setOpen(!open)} style={{...bs(C.sf,C.t2),boxShadow:"0 0 0 0.5px "+C.bd,padding:"4px 10px",fontSize:10,gap:4}}><FastForwardIcon size={11} weight="bold"/>Tiempo por etapa{data.regs>0?<span style={{color:C.dn,fontWeight:700}}> · {data.regs} regresi{data.regs===1?"ón":"ones"}</span>:null} {open?<CaretUpIcon size={10} weight="bold"/>:<CaretDownIcon size={10} weight="bold"/>}</button>
    {open&&<div style={{marginTop:8}}>
      {data.segs.map((s,i)=>{ const st=SM[s.stage]; const c=s.isReg?C.dn:(st?.c||C.t3); const durC=s.hours>=48?C.dn:s.hours>=24?C.amb:C.t2;
        return <div key={i} style={{display:"flex",gap:10,alignItems:"stretch"}}>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",flexShrink:0,paddingTop:3}}>
            <div style={{width:10,height:10,borderRadius:"50%",background:c,flexShrink:0,boxShadow:s.current?"0 0 0 3px "+c+"22":"none"}}/>
            {i<data.segs.length-1&&<div style={{width:2,flex:1,minHeight:16,background:C.bd,marginTop:2}}/>}
          </div>
          <div style={{flex:1,minWidth:0,paddingBottom:i<data.segs.length-1?10:0}}>
            <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
              {s.isReg&&<span title="Regresión (retrocedió de etapa)" style={{display:"inline-flex"}}><ArrowUUpLeftIcon size={11} weight="bold" color={C.dn}/></span>}
              <span style={{fontSize:12,fontWeight:700,color:c}}><StageLbl stage={s.stage}/></span>
              {!s.endpoint&&<span style={{fontSize:11,fontWeight:700,color:durC,background:durC+"14",padding:"1px 7px",borderRadius:5}}>{s.current?"en curso · ":""}{fmtDur(s.hours)}{s.current&&snoozeActive(o)?" · en espera":""}</span>}
            </div>
            <div style={{fontSize:10,color:C.t3,marginTop:2}}><CalendarDotsIcon size={9} weight="bold" style={{verticalAlign:"-1px",marginRight:3}}/>{fDT(s.at)}{s.by?" · "+(AUTHOR_NAME[s.by]||s.by):""}{s.current?" · aquí ahora":(s.endpoint?" · fin":"")}</div>
          </div>
        </div>;
      })}
      <div style={{fontSize:9,color:C.t3,marginTop:4,fontStyle:"italic"}}>Tiempo hábil (sin fines de semana ni pausas "En espera")</div>
    </div>}
  </div>;
}
function snoozeActive(o){
  if(!o?.snooze_reason) return false;
  if(o.snooze_stage && o.snooze_stage !== o.stage) return false;
  // v10.58.63: expira al FIN del día indicado (23:59), no al mediodía — parseDate ancla
  // a T12:00 y revivía la orden medio día antes (igual que el fix de vencidas v10.58.53).
  if(o.snooze_until){ const end=new Date(String(o.snooze_until).slice(0,10)+"T23:59:59"); if(end < new Date()) return false; }
  // v10.73.44 — una pausa "entrega lejana" (far_due) existe PORQUE la entrega está lejos; debe AUTO-REACTIVARSE en cuanto la
  // entrega deja de ser lejana (≤5 días hábiles o ya vencida) para que JAMÁS quede "olvidada" pausada pasada su fecha (el
  // problema real: 7/7 far_due estaban vencidas >7d, nadie las revisaba). Es COMPUTADO, como la expiración de snooze_until:
  // la orden re-entra sola al flujo cuando toca programarla — sin cron ni acción manual; getStale la re-evalúa (si sigue
  // atorada se marca estancada). Solo far_due (las otras causas —material/autorización/factura— no dependen de la fecha).
  if(o.snooze_kind==="far_due" && o.due_date && (isOverdue(o.due_date) || bizDaysUntil(o.due_date)<=5)) return false;
  return true;
}
// Días REALES en la etapa actual (la última entrada de timeline que LLEGÓ a este
// stage — doAdv escribe {to}); una edición ya no "des-estanca" la orden.
function daysInStage(o){
  const tl=o?.timeline||[];
  for(let i=tl.length-1;i>=0;i--){
    if(tl[i]?.to===o.stage && tl[i]?.date){
      return bizDaysSince(tl[i].date);
    }
  }
  // v10.58.55 REG#2: fallback = created_at (sobre-cuenta = seguro). El fallback viejo
  // ("última entrada de timeline") sub-contaba: una "✏️ Editada" reciente des-estancaba
  // una orden vieja → falso NEGATIVO. Tras el backfill de to_stage (v10.58.55) toda
  // orden activa tiene match real, así que este fallback casi nunca se usa.
  return o?.created_at?bizDaysSince(o.created_at):0;
}
// diagnoseOrder: POR QUÉ una orden no avanza → {key, text, respRole, respName,
// external, sev, days, action, snoozed} o null si está sana. ÚNICA fuente de
// verdad — la consume la Torre (Marcelo, desde arriba) y el Despertador (cada
// quien, desde abajo). Reglas en orden de prioridad: la primera que aplica gana.
function diagnoseOrder(o){
  const stage=String(o?.stage||"");
  if(!o||o.cancelled_at||stage.includes("cancelled")||stage.includes("delivered")||stage==="stocked"||["web_pending","web_rejected"].includes(stage)) return null;
  const d=daysInStage(o);
  // v10.58.53: vencida = pasadas las 23:59 del día pactado (antes acusaba desde el
  // mediodía del MISMO día de entrega — contradecía las KPIs de on-time)
  const dueEnd=o.due_date?new Date(String(o.due_date).slice(0,10)+"T23:59:59"):null;
  const late=dueEnd&&dueEnd<new Date();
  const lateDays=late?Math.max(1,Math.floor((Date.now()-dueEnd.getTime())/86400000)+1):0;
  const worst=Math.max(d,lateDays);
  const mkSev=(money)=>(worst>=3||money)?"red":(worst>=1?"orange":"yellow");
  const R=(key,text,role,name,opts={})=>({key,text,respRole:role,respName:name,
    external:!!opts.external,sev:opts.sev||mkSev(!!opts.money),days:worst,
    action:opts.action||"nudge",snoozed:snoozeActive(o)});
  const isMaqStage=["maq_created","maq_sent","maq_in_progress"].includes(stage);
  const noPrice=o.order_type==="maquila"?(!Number(o.maq_price)||Number(o.maq_price)<=0):(!Number(o.price)||Number(o.price)<=0);
  const noCost=o.order_type==="maquila"&&(!Number(o.maq_cost)||Number(o.maq_cost)<=0);
  // v10.58.65 (decisión de Marcelo): el pendiente de una MAQUILA le toca al VENDEDOR que
  // la vendió si tiene usuario en la app (conoce a su proveedor y el costo); si no
  // (Manuel/sin agente), a Lupita. P-3562 (agente Genaro) → Genaro, no Lupita.
  const _maqAg=(o.agent||"").trim();
  const _maqByVendor=!!_maqAg && VENDEDORES_CON_USUARIO.has(_maqAg.toLowerCase());
  const _maqRole=_maqByVendor?"vendedor":"secretaria";
  const _maqName=_maqByVendor?vendorDisplayName(_maqAg):"Lupita"; // v10.58.67: nombre canónico
  if(isMaqStage&&(noPrice||noCost))
    return R("maq_cost","💸 Falta "+[noPrice&&"precio cliente",noCost&&"costo proveedor"].filter(Boolean).join(" y ")+((o.maq_provider||"").trim()?" — proveedor "+o.maq_provider.trim():"")+" · sin esto NO se puede recibir",_maqRole,_maqName,{money:true,action:"edit"});
  // v10.73.9 (Marcelo) — maquila recibida sin COSTO de proveedor. FOLIO PRIMERO: se avisa en la Torre SOLO si
  // el folio ya está resuelto (invoice_folio||has_splits), para NO tapar el aviso "sin folio → Karla" (facturar
  // = flujo de caja, prioridad). El caso típico (recibida sin folio) lo atiende Karla vía la regla no_folio de
  // abajo; el costo faltante queda visible en ROJO en Salud Operativa ("Maquila sin costo", que ya incluye
  // maq_received). Toca al vendedor (o Lupita). [Antes v10.73.7 disparaba siempre y enmascaraba el folio: wb3zfw71a C3-1.]
  if(stage==="maq_received"&&noCost&&(o.invoice_folio||o.has_splits))
    return R("maq_cost","💸 Recibida SIN costo de proveedor capturado"+((o.maq_provider||"").trim()?" — proveedor "+o.maq_provider.trim():"")+" · captúralo para el margen",_maqRole,_maqName,{money:true,action:"edit"});
  if(isMaqStage&&!(o.maq_provider||"").trim())
    return R("maq_prov","🏭 Maquila sin proveedor asignado",_maqRole,_maqName,{action:"edit"});
  if(stage==="draft"&&!(o.validated_by_production&&o.validated_by_preprensa)){
    const fP=!o.validated_by_production,fN=!o.validated_by_preprensa;
    return R("validation","✋ Falta validación de "+(fP&&fN?"Gerardo y Noemí":(fP?"Gerardo (producción)":"Noemí (pre-prensa)")),
      fP&&fN?"both":(fP?"produccion":"preprensa"),fP&&fN?"Gerardo y Noemí":(fP?"Gerardo":"Noemí"),{});
  }
  if(o.source==="web"&&!o.file_url&&["draft","design"].includes(stage))
    return R("web_file","🌐 El cliente no manda su archivo — pagado y parado","secretaria","Lupita",{external:true});
  if(stage==="proof_client"&&d>=3)
    return R("proof","⏳ El cliente no aprueba la prueba desde hace "+d+" días","secretaria","Lupita",{external:true,sev:d>=6?"red":"orange"});
  if(["maq_sent","maq_in_progress"].includes(stage)&&d>=7)
    // v10.58.65: perseguir al proveedor lento es del vendedor (Genaro) si tiene usuario;
    // external solo cuando cae a Lupita (ella da seguimiento al externo en ese caso).
    return R("maq_sleep","🚚 En maquila con "+((o.maq_provider||"el proveedor").trim())+" hace "+d+" días sin recibirse",_maqRole,_maqName,{external:!_maqByVendor,sev:d>=14?"red":"orange"});
  if(stage==="ready"&&!o.current_machine&&d>=1&&!(o.due_date&&bizDaysUntil(o.due_date)>5)) // v10.73.27 — misma exención far-due que la regla stale/getStale (entrega lejana no toca máquina aún)
    return R("no_machine","🖱️ Sin máquina asignada hace "+d+" día"+(d===1?"":"s"),"produccion","Gerardo",{});
  if(o.needs_reprint)
    return R("reprint","🔁 Marcada para REIMPRIMIR","produccion","Gerardo",{sev:"red"});
  if(["salidas","maq_received"].includes(stage)&&!o.invoice_folio&&!o.has_splits&&!o.has_matrix_lines&&!o.grouped_invoice_folio&&!o.return_covered_by_folio&&d>=3)
    return R("no_folio","🧾 Sin folio de factura hace "+d+" días","karla","Karla",{}); // v10.73.45 (scan) — excluye plan matriz/agrupada/cubierta: sus botones de folio están ocultos → el nag quedaba sin acción posible para Karla
  // v10.58.63: 'vencida' se evalúa ANTES que no_price/no_date — una orden atorada Y
  // vencida es más urgente como retraso (→ responsable de la etapa) que como dato
  // faltante; antes una orden sin precio + vencida se atribuía a Karla y desaparecía
  // del bloque de su área en la Torre.
  // v10.59.5 (Marcelo): un trabajo MONTADO EN MÁQUINA (in_production + current_machine) está
  // avanzando — NO es un "bloqueo" para Gerardo aunque esté vencido (mismo criterio que la regla
  // 🐢 estancada, que ya excluye current_machine). Evita el ruido de vencidas en producción.
  const onMachine = !!o.current_machine && stage==="in_production";
  if(late && !onMachine){
    const resp=orderResponsible(o); // v10.58.65: maquila vencida → vendedor (no Lupita)
    return R("late","⚠️ Vencida hace "+lateDays+" día"+(lateDays===1?"":"s")+" · está en "+(SM[stage]?.l||stage),
      resp?.role||"admin",resp?.role==="both"?"Gerardo y Noemí":(resp?.name||"—"),{sev:lateDays>=3?"red":"orange"});
  }
  // v10.58.53: una orden MONTADA EN MÁQUINA no está estancada (paridad con getStale v10.49.4)
  if(d>=2&&!o.current_machine&&!["proof_client","maq_sent","maq_in_progress","maq_created"].includes(stage)&&!((stage==="ready"||stage==="placas_listas")&&o.due_date&&bizDaysUntil(o.due_date)>5)){
    const resp=orderResponsible(o); // v10.58.65: consistente con la regla maquila→vendedor
    if(resp)return R("stale","🐢 "+d+" días sin avanzar en "+(SM[stage]?.l||stage),
      resp.role,resp.role==="both"?"Gerardo y Noemí":resp.name,{sev:d>=4?"red":"orange"});
  }
  // v10.58.63: datos faltantes (no bloqueantes de flujo) al final — después de vencida/estancada
  if(o.order_type!=="maquila"&&noPrice&&stage!=="salidas")
    return R("no_price","💰 Sin precio capturado","karla","Karla",{action:"edit"});
  if(!o.due_date)
    // v10.70.2 (Marcelo): la fecha de entrega la compromete QUIEN VENDIÓ la orden. Si es de un
    // vendedor con usuario (agent, ej. Genaro) le toca a él, NO a Lupita. _maqRole/_maqName ya
    // resuelven vendedor-con-usuario↔Lupita desde o.agent; responsibleNotifyTarget rutea el
    // "Recordar"/Telegram al username del agente. Caso H-3683 (interna de Genaro, sin fecha).
    return R("no_date","📅 Sin fecha de entrega comprometida",_maqRole,_maqName,{action:"edit"});
  return null;
}

// ☀️ v10.58.51 — DESPERTADOR: bienvenida diaria con los bloqueos del usuario.
// Pedido de Marcelo: ventana GRANDE al entrar al app; solo se cierra escribiendo
// "SI ENTIENDO" (queda registro vía log_wakeup_ack). Aplica a todos; Gerardo
// (producción) NO se despierta por trabajo en máquinas (ready/in_production/
// packaging = su flujo normal del tablero), solo por bloqueos fuera de máquinas.
function getWakeupItems(role, userLogin, orders){
  const maqMissing = o => o.order_type==="maquila" &&
    ["maq_created","maq_sent","maq_in_progress"].includes(o.stage) &&
    (!Number(o.maq_price) || Number(o.maq_price)<=0 || !Number(o.maq_cost) || Number(o.maq_cost)<=0);
  // v10.58.56: instrucción concreta por etapa — el paso que destraba la orden.
  const STAGE_ACT = {
    draft:"Ábrela, valídala (✅ Producción / ✅ Pre-prensa) o edítala si algo está mal",
    design:"Trabaja el diseño o mándala a aprobación del cliente",
    proof_printing:"Imprime la prueba para el cliente",
    proof_client:"Llama al cliente para que apruebe la prueba",
    ctp:"Procesa el CTP / quema la placa",
    placas_listas:"Pásala a producción",
    ready:"Asígnala a una máquina en el Tablero",
    in_production:"Avanza la producción en el Tablero",
    maquila_out:"Recíbela de la maquila externa → 📥 Recibido de Maquila",
    maquila_in:"Llévala a acabados o empaque en el Tablero",
    packaging:"Empácala y mándala a Salidas",
    salidas:"Asigna folio fiscal y entrégala",
    maq_created:"Envíala al proveedor (🚚 Marcar Enviada)",
    maq_sent:"Confirma que el proveedor ya está trabajando",
    maq_in_progress:"Cuando regrese el trabajo: 📥 Recibimos el Trabajo",
    maq_received:"Asigna folio fiscal y entrégala",
  };
  const maqMissingAct = o => "Abre la orden → ✏️ Editar Maquila → captura " +
    [(!Number(o.maq_price)||Number(o.maq_price)<=0)&&"el precio del cliente",
     (!Number(o.maq_cost)||Number(o.maq_cost)<=0)&&"el costo del proveedor"].filter(Boolean).join(" y ") +
    " → 📥 Recibimos el Trabajo";
  const stageAct = o => STAGE_ACT[o.stage] || "Ábrela y avánzala a la siguiente etapa";
  const baseAct = o => maqMissing(o) ? maqMissingAct(o) : stageAct(o);
  // v10.58.63: el Despertador ahora consume diagnoseOrder (el MISMO motor de la Torre)
  // — antes era un motor paralelo que solo despertaba por vencidas/maqMissing y dejaba
  // ciegos al responsable los bloqueos no-vencidos (sin folio, validación, estancada,
  // sin máquina...). Omitimos no_price/no_date (nudges de datos, no alarma de la mañana;
  // ya viven en la Torre y en Datos Pendientes) para no inundar.
  const SKIP_KEYS = new Set(["no_price","no_date"]);
  const items = [];
  for(const o of orders){
    if(snoozeActive(o)) continue;
    const diag = diagnoseOrder(o);
    if(!diag || SKIP_KEYS.has(diag.key)) continue;
    // v10.58.64 M1: Gerardo NO se despierta por trabajo MONTADO EN MÁQUINA (su tablero
    // normal) — restaura la regla v61 que se perdió al delegar a diagnoseOrder. Una
    // orden en 'ready' SIN máquina (no_machine) o estancada sí lo despierta.
    if(role==="produccion" && o.current_machine && ["ready","in_production","packaging"].includes(o.stage)) continue;
    const ag = (o.agent||"").trim();
    // v10.58.64 M2: el rescate de Manuel (agente sin usuario → Lupita persigue) se basa
    // en el VENCIMIENTO real, no en diag.key==='late' (no_folio/validation ganaban antes
    // y Lupita perdía las vencidas más viejas de Manuel).
    const overdue = o.due_date && new Date(String(o.due_date).slice(0,10)+"T23:59:59") < new Date();
    const viaManuel = isSec(role) && overdue && ag && !VENDEDORES_CON_USUARIO.has(ag.toLowerCase());
    let mine=false;
    if(role==="admin") mine=true;
    else if(role==="vendedor") mine = isVendedorOwnerByAgent(role, userLogin, o);
    else if(diag.external) mine = isSec(role); // cliente/proveedor → Lupita da seguimiento
    else {
      const r=diag.respRole;
      mine = r===role || (r==="both"&&(role==="produccion"||role==="preprensa")) || (r==="secretaria"&&isSec(role));
      if(!mine && viaManuel) mine=true; // Manuel (sin usuario) → Lupita persigue
    }
    if(!mine) continue;
    let action;
    if(role==="admin") action = "Ve con " + diag.respName + ": " + baseAct(o);
    else if(role==="vendedor") action = "Apura con " + diag.respName + " o avísale al cliente del retraso";
    else if(viaManuel) action = "Apura con " + diag.respName + " o avísale al cliente (tú llevas lo de " + ag + ")";
    else if(diag.external) action = "Dale seguimiento " + (diag.key==="maq_sleep" ? ("al proveedor " + ((o.maq_provider||"").trim()||"externo")) : "al cliente") + " para destrabarla";
    else action = baseAct(o);
    items.push({o, why:diag.text, action, late:diag.days});
  }
  items.sort((a,b)=>b.late-a.late);
  return items;
}

function WakeupModal({user, userLogin, items, onAck}){
  const [text,setText]=useState("");
  const norm=s=>String(s||"").toUpperCase().normalize("NFD").replace(/[.,;:!¡?¿]+\s*$/,"").replace(/[̀-ͯ]/g,"").replace(/\s+/g," ").trim();
  const matched=norm(text)==="SI ENTIENDO";
  useEffect(()=>{ if(matched) onAck(); },[matched,onAck]);
  const today=new Date().toLocaleDateString("es-MX",{weekday:"long",day:"numeric",month:"long"});
  return <div style={{position:"fixed",inset:0,background:"rgba(10,10,20,0.78)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:3000,padding:16,backdropFilter:"blur(3px)"}}>
    <div style={{background:C.bg,borderRadius:20,padding:28,maxWidth:680,width:"100%",maxHeight:"88vh",display:"flex",flexDirection:"column",boxShadow:C.sh3}}>
      <div style={{fontSize:30,fontWeight:900,color:C.tx,lineHeight:1.15,display:"flex",alignItems:"center",gap:10}}><SunIcon size={28} weight="fill" color="#f59e0b"/>Buenos días, {userDisplayName(user)}</div>
      <div style={{fontSize:12,color:C.t2,marginTop:4,textTransform:"capitalize"}}>{today}</div>
      <div style={{fontSize:14,fontWeight:700,color:"#b45309",background:"#f59e0b12",border:"1px solid #f59e0b30",borderRadius:12,padding:"10px 14px",marginTop:14}}>
        {items.length===1?"Hay 1 pendiente esperando TU acción antes de empezar el día:":"Hay "+items.length+" pendientes esperando TU acción antes de empezar el día:"}
      </div>
      <div style={{overflowY:"auto",marginTop:10,flex:1,minHeight:0,display:"flex",flexDirection:"column",gap:8,paddingRight:4}}>
        {items.map(({o,why,action,late},i)=>(
          <div key={o.id} style={{border:"1.5px solid "+(late>3?C.dn:"#f59e0b")+"66",borderRadius:10,padding:"10px 14px",background:late>3?C.dn+"06":C.bg}}>
            <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
              <span style={{fontSize:13,fontWeight:800,color:C.tx}}>{o.production_number||o.id}</span>
              <span style={{fontSize:12,fontWeight:600,color:C.t2}}>{o.client}</span>
              {o.invoice_folio&&<span style={{fontSize:10,fontWeight:700,color:C.fac,background:C.fac+"12",padding:"1px 6px",borderRadius:5,fontFamily:"'Geist Mono',monospace"}}>{o.invoice_folio}</span>}
              {o.due_date&&<span style={{fontSize:10,color:late>0?C.dn:C.t3,fontWeight:late>0?700:400,marginLeft:"auto",display:"inline-flex",alignItems:"center",gap:3}}><CalendarDotsIcon size={10} weight="bold"/>{fD(o.due_date)}</span>}
            </div>
            <div style={{fontSize:11,color:C.t2,marginTop:2}}>{(o.product_type||o.product||"").trim()}{o.maq_provider?<> · <TruckIcon size={11} weight="bold" style={{verticalAlign:"-1px"}}/> {o.maq_provider.trim()}</>:""}</div>
            <div style={{fontSize:12,fontWeight:700,color:late>3?C.dn:"#b45309",marginTop:4}}><WarningIcon size={12} weight="fill" style={{verticalAlign:"-2px",marginRight:3}}/>{why}</div>
            {action&&<div style={{fontSize:12,fontWeight:700,color:C.ok,marginTop:5,background:C.ok+"0e",border:"1px solid "+C.ok+"30",borderRadius:8,padding:"6px 10px"}}><HandPointingIcon size={12} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Qué hacer: <span style={{fontWeight:600,color:C.tx}}>{action}</span></div>}
          </div>
        ))}
      </div>
      <div style={{marginTop:16,borderTop:"1px solid "+C.bd,paddingTop:14}}>
        <div style={{fontSize:12,color:C.t2,marginBottom:8}}>Para continuar, escribe <b style={{color:C.tx,letterSpacing:1}}>SI ENTIENDO</b> — la ventana se cierra sola y queda registrada tu confirmación.</div>
        <input autoFocus value={text} onChange={e=>setText(e.target.value)}
          placeholder="Escribe aquí..."
          style={{...inp,fontSize:16,fontWeight:700,letterSpacing:1,textAlign:"center",padding:"12px 16px",border:"2px solid "+(matched?C.ok:C.bd)}}/>
      </div>
    </div>
  </div>;
}

// v10.72.20 / DB v3.7.7.22 — "Nombre interno" (alias): chips de los nombres con que el equipo conoce a un
// cliente + captura inline (agregar/quitar) gateada a admin/secretaria. Ayuda a reconocer la razón social
// correcta. Los chips se ven para todos; agregar/quitar solo admin/secretaria. Feedback inline (sin showToast).
function ClientAliasManager({clientId, role, userLogin}){
  const [aliases,setAliases]=useState(null); // null = cargando
  const [val,setVal]=useState("");
  const [busy,setBusy]=useState(false);
  const [err,setErr]=useState("");
  const canManage = role==="admin"||role==="secretaria";
  useEffect(()=>{
    if(!clientId){setAliases([]);return}
    let alive=true;
    supabase.rpc("get_client_aliases",{p_client_id:clientId})
      .then(({data,error})=>{if(alive)setAliases(error?[]:(data||[]))})
      .catch(()=>{if(alive)setAliases([])});
    return()=>{alive=false};
  },[clientId]);
  const add=async()=>{
    const a=val.trim(); if(!a||busy)return;
    setBusy(true);setErr("");
    try{ const prevLen=(aliases||[]).length; const {data,error}=await supabase.rpc("add_client_alias",{p_client_id:clientId,p_alias:a,p_actor:userLogin||role}); if(error)throw error; setAliases(data||[]); if((data||[]).length===prevLen){setErr("Ese nombre interno ya existe")}else{setVal("")} }
    catch(e){ setErr(e?.message||"No se pudo agregar"); }
    finally{setBusy(false)}
  };
  const remove=async(a)=>{
    if(busy)return; setBusy(true);setErr("");
    try{ const {data,error}=await supabase.rpc("remove_client_alias",{p_client_id:clientId,p_alias:a,p_actor:userLogin||role}); if(error)throw error; setAliases(data||[]); }
    catch(e){ setErr(e?.message||"No se pudo quitar"); }
    finally{setBusy(false)}
  };
  if(aliases===null) return null;                     // cargando
  if(!canManage && aliases.length===0) return null;   // no-admin sin alias: nada que mostrar
  return <div style={{margin:"6px 0 10px",padding:"8px 10px",background:C.sf,borderRadius:10,border:"0.5px solid "+C.bd}}>
    <div style={{fontSize:9,fontWeight:700,color:C.t3,textTransform:"uppercase",letterSpacing:.4,marginBottom:5,display:"inline-flex",alignItems:"center",gap:4}}><TagIcon size={10} weight="bold"/>Nombre interno</div>
    <div style={{display:"flex",flexWrap:"wrap",gap:5,alignItems:"center"}}>
      {aliases.map(a=><span key={a} style={{display:"inline-flex",alignItems:"center",gap:4,background:C.ac+"12",color:C.ac,border:"1px solid "+C.ac+"25",borderRadius:20,padding:"2px 8px",fontSize:11,fontWeight:600}}>{a}{canManage&&<button onClick={()=>remove(a)} disabled={busy} aria-label={"Quitar "+a} style={{background:"none",border:"none",cursor:busy?"wait":"pointer",color:C.ac,padding:0,display:"inline-flex",opacity:busy?.5:1}}><XIcon size={10} weight="bold"/></button>}</span>)}
      {canManage&&<span style={{display:"inline-flex",alignItems:"center",gap:4}}>
        <input value={val} onChange={e=>setVal(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"){e.preventDefault();add()}}} placeholder="+ nombre interno" disabled={busy} style={{...inp,padding:"3px 8px",fontSize:11,width:150,minHeight:0,borderRadius:8}}/>
        {val.trim()&&<button onClick={add} disabled={busy} style={{background:C.ac,color:"#fff",border:"none",borderRadius:8,padding:"4px 9px",fontSize:10,fontWeight:700,cursor:busy?"wait":"pointer",fontFamily:"'Geist',sans-serif"}}>Agregar</button>}
      </span>}
    </div>
    {err&&<div style={{fontSize:10,color:C.dn,marginTop:4}}>{err}</div>}
  </div>;
}

// 🆕 v10.13.0 — Typeahead contra cobranza.clients (RPC search_clients_typeahead)
function ClientInput({value,onChange,onSelect,clients}) {
  const [show,setShow]=useState(false);
  const [matches,setMatches]=useState([]);
  const [searching,setSearching]=useState(false);
  const debounceRef=useRef(null);
  useEffect(()=>{
    if(debounceRef.current)clearTimeout(debounceRef.current);
    const q=(value||"").trim();
    if(q.length<2){setMatches([]);return}
    debounceRef.current=setTimeout(async()=>{
      setSearching(true);
      try{
        const {data,error}=await supabase.rpc("search_clients_typeahead",{p_query:q,p_limit:10});
        if(error)throw error;
        setMatches(data||[]);
      }catch(e){console.error("typeahead error:",e);setMatches([])}
      finally{setSearching(false)}
    },250);
    return()=>debounceRef.current&&clearTimeout(debounceRef.current);
  },[value]);
  return <div style={{position:"relative"}}><input style={inp} value={value} onChange={e=>{onChange(e.target.value);setShow(true)}} placeholder="Cliente (escribe para buscar)" onFocus={()=>setShow(true)} onBlur={()=>setTimeout(()=>setShow(false),200)}/>{show&&(matches.length>0||searching)&&<div style={{position:"absolute",top:"100%",left:0,right:0,background:C.bg,borderRadius:10,boxShadow:C.sh3,zIndex:50,border:"0.5px solid "+C.bd,marginTop:4,maxHeight:320,overflowY:"auto"}}><div style={{padding:"5px 12px",fontSize:10,color:C.t2,fontWeight:600,textTransform:"uppercase",borderBottom:"0.5px solid "+C.bd}}>{searching?"Buscando...":`Clientes (${matches.length})`}</div>{matches.map((c,i)=><div key={c.id} onMouseDown={()=>{onSelect(c);setShow(false)}} style={{padding:"8px 12px",cursor:"pointer",borderBottom:i<matches.length-1?"0.5px solid "+C.bd:"none"}} onMouseEnter={e=>e.currentTarget.style.background=C.sf} onMouseLeave={e=>e.currentTarget.style.background=C.bg}><div style={{fontSize:12,fontWeight:600}}>{c.name}</div><div style={{fontSize:10,color:C.t2}}>{[c.rfc,c.whatsapp,c.dias_credito?`${c.dias_credito}d crédito`:null].filter(Boolean).join(" · ")}</div>{Array.isArray(c.aliases)&&c.aliases.length>0&&<div style={{fontSize:10,color:C.ac,marginTop:1,display:"flex",alignItems:"center",gap:3,flexWrap:"wrap"}}><TagIcon size={9} weight="bold"/>{c.aliases.join(", ")}</div>}</div>)}</div>}</div>;
}

// 🆕 v10.13.0 — Modal de confirmación de cliente similar (typeahead)
// v10.72.2 — un solo modal in-app para dos casos: (a) hay clientes similares ("¿quisiste decir?"),
// (b) sin similares -> confirmar NUEVA razón social mostrando nombre/RFC/contacto + aviso de duplicado.
// Reemplaza el window.confirm nativo en el momento de más riesgo (crear cliente en el ERP compartido).
function ClientConfirmModal({open,typed,matches,rfc,contact,onResolve}) {
  if(!open)return null;
  const hasMatches=Array.isArray(matches)&&matches.length>0;
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}} onClick={()=>onResolve("cancel")}>
    <div role="dialog" aria-modal="true" aria-label={hasMatches?"Confirmar cliente similar":"Confirmar cliente nuevo"} style={{background:C.bg,borderRadius:20,padding:24,maxWidth:520,width:"90%",boxShadow:C.sh3}} onClick={e=>e.stopPropagation()}>
      {hasMatches?<>
        <div style={{fontSize:16,fontWeight:700,marginBottom:8}}>¿Quisiste decir alguno de estos clientes?</div>
        <div style={{fontSize:12,color:C.t2,marginBottom:16}}>Escribiste: <strong>"{typed}"</strong></div>
        <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:16}}>
          {matches.map(c=><button key={c.id} onClick={()=>onResolve(c.id)} style={{background:C.sf,border:"1px solid "+C.bd,borderRadius:10,padding:12,textAlign:"left",cursor:"pointer",transition:"background 0.1s",fontFamily:"'Geist',sans-serif"}} onMouseEnter={e=>e.currentTarget.style.background=C.bg} onMouseLeave={e=>e.currentTarget.style.background=C.sf}>
            <div style={{fontSize:13,fontWeight:600}}>{c.name}</div>
            <div style={{fontSize:11,color:C.t2,marginTop:2}}>{[c.rfc,c.dias_credito?`${c.dias_credito}d crédito`:null].filter(Boolean).join(" · ")||"—"}</div>
            {Array.isArray(c.aliases)&&c.aliases.length>0&&<div style={{fontSize:10,color:C.ac,marginTop:2,display:"flex",alignItems:"center",gap:3,flexWrap:"wrap"}}><TagIcon size={9} weight="bold"/>{c.aliases.join(", ")}</div>}
          </button>)}
        </div>
      </>:<>
        <div style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,color:C.tx,marginBottom:6}}><UserPlusIcon size={18} weight="bold"/>Crear cliente nuevo</div>
        <div style={{fontSize:12.5,color:C.t2,lineHeight:1.5,marginBottom:14}}><strong style={{color:C.tx}}>"{typed}"</strong> no está registrado. Se creará como una <strong style={{color:C.ac}}>NUEVA razón social</strong> en CobranzaFlow.</div>
        <div style={{background:C.sf,borderRadius:12,padding:"12px 14px",marginBottom:14,display:"flex",flexDirection:"column",gap:9}}>
          <div style={{display:"flex",justifyContent:"space-between",gap:12,fontSize:12.5}}><span style={{color:C.t3,fontWeight:600,flexShrink:0}}>Razón social</span><span style={{fontWeight:700,color:C.tx,textAlign:"right"}}>{typed}</span></div>
          <div style={{display:"flex",justifyContent:"space-between",gap:12,fontSize:12.5}}><span style={{color:C.t3,fontWeight:600,flexShrink:0}}>RFC</span><span style={{fontWeight:700,color:rfc?C.tx:C.ph,textAlign:"right"}}>{rfc||"sin RFC"}</span></div>
          <div style={{display:"flex",justifyContent:"space-between",gap:12,fontSize:12.5}}><span style={{color:C.t3,fontWeight:600,flexShrink:0}}>Contacto</span><span style={{fontWeight:700,color:contact?C.tx:C.ph,textAlign:"right"}}>{contact||"sin contacto"}</span></div>
        </div>
        <div style={{display:"flex",alignItems:"flex-start",gap:8,background:C.amb+"12",border:"1px solid "+C.amb+"40",borderRadius:10,padding:"10px 12px",fontSize:11,color:"#9a3412",lineHeight:1.45}}><WarningIcon size={15} weight="fill" color={C.amb} style={{flexShrink:0,marginTop:1}}/><span>Verifica que no sea un <strong>duplicado</strong> escrito de otra forma (acentos, abreviaturas, S.A. de C.V.). Si ya existe, cancela y búscalo por su nombre registrado.</span></div>
      </>}
      <div style={{borderTop:"0.5px solid "+C.bd,paddingTop:14,marginTop:14,display:"flex",gap:8,justifyContent:"flex-end"}}>
        <button onClick={()=>onResolve("cancel")} style={{...bs(C.sf,C.t2),padding:"8px 16px"}}>Cancelar</button>
        <button onClick={()=>onResolve("new")} style={{...bs(C.ac),padding:"8px 16px"}}><PlusIcon size={13} weight="bold"/>{hasMatches?`Crear "${typed}" como nuevo`:"Sí, crear cliente nuevo"}</button>
      </div>
    </div>
  </div>;
}
// 🆕 v10.72.87 — "Facturar a un tercero": el destinatario fiscal/cobranza puede diferir del cliente de la orden.
// Reusa ClientInput (búsqueda inteligente nombre/RFC/alias) + alta de razón social nueva. Avisa al padre vía onChange:
//   null (apagado) | {incomplete:true} (encendido sin completar) | {client_id,name,rfc} | {name,rfc,email,whatsapp,isNew}
function BillToSection({invoiceType, onChange, accent=C.ac}){
  const LBL={fontSize:11,fontWeight:600,color:C.t2,display:"block",marginBottom:3};
  const [on,setOn]=useState(false);
  const [picked,setPicked]=useState(null);
  const [mode,setMode]=useState("pick");
  const [q,setQ]=useState("");
  const [nf,setNf]=useState({name:"",rfc:"",email:"",whatsapp:""});
  const [pickErr,setPickErr]=useState("");
  const [simMatches,setSimMatches]=useState([]);
  const isFactura=invoiceType==="factura";
  useEffect(()=>{
    if(!on){ onChange(null); return; }
    if(picked){
      if(isFactura && !(picked.rfc && String(picked.rfc).trim())){ onChange({incomplete:true}); return; } // v10.72.88 (#3): factura exige RFC también en tercero EXISTENTE
      onChange({client_id:picked.id, name:picked.name, rfc:picked.rfc}); return;
    }
    if(mode==="new"){
      const name=nf.name.trim(), rfc=nf.rfc.trim();
      if(name && (!isFactura || rfc)){ onChange({name, rfc:rfc||null, email:nf.email.trim()||null, whatsapp:nf.whatsapp.trim()||null, isNew:true}); return; }
    }
    onChange({incomplete:true});
  },[on,picked,mode,nf.name,nf.rfc,nf.email,nf.whatsapp,isFactura]);
  // v10.72.87 — elegir tercero: bloquea Corona/anticipo (lo rechaza set_order_bill_to) con aviso inmediato.
  const pick=c=>{ if(c?.billing_mode==='anticipo'){ setPickErr((c.name||"Esa razón social")+" es Corona/anticipo — no se puede facturar como tercero (Fase 1)."); return; } setPickErr(""); setPicked({id:c.id,name:c.name,rfc:c.rfc}); setQ(c.name); };
  // v10.72.87 — nudge anti-duplicado: al crear razón social nueva, avisa si ya hay parecidas (paridad con el alta de cliente).
  useEffect(()=>{
    if(!on||mode!=="new"){ setSimMatches([]); return; }
    const name=nf.name.trim();
    if(name.length<3){ setSimMatches([]); return; }
    const t=setTimeout(async()=>{ try{ const {data}=await supabase.rpc("search_clients_typeahead",{p_query:name,p_limit:5}); setSimMatches(data||[]); }catch{ setSimMatches([]); } },350);
    return ()=>clearTimeout(t);
  },[on,mode,nf.name]);
  const reset=()=>{ setPicked(null); setQ(""); setNf({name:"",rfc:"",email:"",whatsapp:""}); setPickErr(""); setSimMatches([]); };
  return (
    <div style={{padding:"12px 20px",borderBottom:"0.5px solid "+C.bd}}>
      <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",userSelect:"none"}}>
        <input type="checkbox" checked={on} onChange={e=>{setOn(e.target.checked); if(!e.target.checked) reset();}} style={{width:16,height:16,accentColor:accent,cursor:"pointer"}}/>
        <span style={{fontSize:12.5,fontWeight:700,color:C.tx,display:"inline-flex",alignItems:"center",gap:6}}><UsersIcon size={13} weight="bold" color={accent}/>Facturar a un tercero <span style={{fontSize:10.5,fontWeight:500,color:C.t2}}>(razón social distinta a la de la orden)</span></span>
      </label>
      {on&&<div style={{marginTop:10}}>
        {!picked&&<>
          <div style={{display:"flex",gap:6,marginBottom:8}}>
            <button type="button" onClick={()=>setMode("pick")} style={{...bs(mode==="pick"?accent+"15":C.sf,mode==="pick"?accent:C.t2),fontSize:11,border:"1px solid "+(mode==="pick"?accent+"40":C.bd)}}><MagnifyingGlassIcon size={11} weight="bold"/>Buscar existente</button>
            <button type="button" onClick={()=>setMode("new")} style={{...bs(mode==="new"?accent+"15":C.sf,mode==="new"?accent:C.t2),fontSize:11,border:"1px solid "+(mode==="new"?accent+"40":C.bd)}}><UserPlusIcon size={11} weight="bold"/>Crear nueva</button>
          </div>
          {mode==="pick"
            ? <ClientInput value={q} onChange={setQ} onSelect={pick} clients={[]}/>
            : <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                <div style={{gridColumn:"1 / -1"}}><label style={LBL}>Razón social *</label><input style={inp} value={nf.name} onChange={e=>setNf(v=>({...v,name:e.target.value}))} placeholder="Nombre / empresa"/></div>
                <div><label style={LBL}>RFC{isFactura?" *":" (opcional)"}</label><input style={{...inp,...(isFactura&&!nf.rfc.trim()?{borderColor:C.dn+"66"}:{})}} value={nf.rfc} onChange={e=>setNf(v=>({...v,rfc:e.target.value.toUpperCase()}))} placeholder={isFactura?"Requerido para factura":"Opcional"}/></div>
                <div><label style={LBL}>Celular</label><input style={inp} value={nf.whatsapp} onChange={e=>setNf(v=>({...v,whatsapp:e.target.value}))} placeholder="WhatsApp"/></div>
                <div style={{gridColumn:"1 / -1"}}><label style={LBL}>Correo</label><input style={inp} value={nf.email} onChange={e=>setNf(v=>({...v,email:e.target.value}))} placeholder="correo@…"/></div>
                {isFactura&&!nf.rfc.trim()&&<div style={{gridColumn:"1 / -1",fontSize:10.5,color:C.dn,fontWeight:600}}>El RFC es obligatorio para factura.</div>}
              </div>}
          {pickErr&&<div style={{fontSize:10.5,color:C.dn,fontWeight:600,marginTop:6,display:"flex",alignItems:"center",gap:4}}><WarningIcon size={11} weight="fill"/>{pickErr}</div>}
          {mode==="new"&&simMatches.length>0&&<div style={{marginTop:8,background:C.amb+"10",border:"1px solid "+C.amb+"40",borderRadius:10,padding:"8px 10px"}}>
            <div style={{fontSize:10.5,color:"#9a3412",fontWeight:700,marginBottom:5,display:"flex",alignItems:"center",gap:4}}><WarningIcon size={11} weight="fill"/>Ya existe(n) razón(es) parecida(s) — ¿es alguna? (evita duplicar en el ERP)</div>
            <div style={{display:"flex",flexDirection:"column",gap:4}}>{simMatches.map(c=><button key={c.id} type="button" onClick={()=>pick(c)} style={{...bs(C.bg,C.tx),fontSize:11,textAlign:"left",justifyContent:"flex-start",border:"1px solid "+C.bd,padding:"5px 9px"}}><span style={{fontWeight:700}}>{c.name}</span>{c.rfc?<span style={{color:C.t2,marginLeft:6}}>· {c.rfc}</span>:null}</button>)}</div>
          </div>}
        </>}
        {picked&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"9px 12px",background:accent+"0e",border:"1px solid "+accent+"40",borderRadius:10}}>
          <UsersIcon size={14} weight="bold" color={accent}/>
          <div style={{flex:1,minWidth:0}}><div style={{fontSize:12.5,fontWeight:700,color:C.tx,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{picked.name}</div>{picked.rfc?<div style={{fontSize:10.5,color:C.t2}}>{picked.rfc}</div>:<div style={{fontSize:10.5,fontWeight:700,color:isFactura?C.dn:C.t2}}>{isFactura?"Sin RFC — requerido para factura":"sin RFC"}</div>}</div>
          <button type="button" onClick={()=>{setPicked(null);setQ("");}} style={{...bs(C.sf,C.t2),fontSize:10.5,padding:"4px 9px",border:"1px solid "+C.bd}}><XIcon size={11} weight="bold"/>Cambiar</button>
        </div>}
        <div style={{fontSize:10.5,color:C.t2,marginTop:8,lineHeight:1.4}}>La factura/remisión y su cobranza quedan a nombre de este tercero; la producción sigue a nombre del cliente de la orden.</div>
      </div>}
    </div>
  );
}
function CommentLog({comments=[],onAdd,role}) {
  const [text,setText]=useState("");const [show,setShow]=useState(false);
  const add=()=>{if(!text.trim())return;onAdd({text:text.trim(),by:role,date:new Date().toISOString()});setText("")};
  return <div style={{marginTop:6}}>{comments.length>0&&<div style={{maxHeight:80,overflowY:"auto",marginBottom:4}}>{comments.map((c,i)=><div key={i} style={{padding:"2px 0",fontSize:10,borderBottom:i<comments.length-1?"0.5px solid "+C.bd:"none"}}><span style={{fontWeight:600,color:AUTHOR_COLOR[c.by]||C.t3}}>{AUTHOR_NAME[c.by]||c.by}</span> {c.text} <span style={{color:C.t3,fontSize:10}}>{fDT(c.date)}</span></div>)}</div>}{!show?<button onClick={()=>setShow(true)} style={{...bs(C.sf,C.t2),boxShadow:"0 0 0 0.5px "+C.bd,padding:"4px 10px",fontSize:10}}><ChatCircleIcon size={12} weight="bold"/>Nota</button>:<div style={{display:"flex",gap:4}}><input style={{...inp,flex:1,padding:"6px 10px",fontSize:11}} value={text} onChange={e=>setText(e.target.value)} placeholder="Nota..." onKeyDown={e=>e.key==="Enter"&&add()}/><button onClick={add} style={bs(C.ac)}>↑</button><button onClick={()=>setShow(false)} style={bs(C.sf,C.t2)}>✕</button></div>}</div>;
}

// ─── QUICK NOTES (mini-chat between roles) ────────
function QuickNotes({notes=[],onAdd,role}) {
  const [text,setText]=useState("");const [open,setOpen]=useState(false);
  const send=()=>{if(!text.trim())return;onAdd(text.trim());setText("")};
  const hasNotes=notes.length>0;
  return <div style={{marginTop:6}}>
    <button onClick={()=>setOpen(!open)} style={{...bs(hasNotes?C.ios+"12":C.sf,hasNotes?C.ios:C.t2),boxShadow:"0 0 0 0.5px "+C.bd,padding:"4px 10px",fontSize:10,gap:4}}>
      <ChatCircleIcon size={12} weight="bold"/>Notas Rápidas{hasNotes?" ("+notes.length+")":""}
    </button>
    {open&&<div style={{marginTop:6,background:"#f0f4f8",borderRadius:12,border:"0.5px solid "+C.bd,overflow:"hidden"}}>
      {hasNotes&&<div style={{maxHeight:140,overflowY:"auto",padding:"8px 10px"}}>
        {notes.map((n,i)=>{
          const isMe=n.by===role||n.by===AUTHOR_NAME[role];
          return <div key={i} style={{display:"flex",flexDirection:"column",alignItems:isMe?"flex-end":"flex-start",marginBottom:6}}>
            <div style={{fontSize:9,color:AUTHOR_COLOR[n.by]||C.t3,fontWeight:600,marginBottom:1}}>{AUTHOR_NAME[n.by]||n.by}</div>
            <div style={{background:isMe?C.ios:"#fff",color:isMe?"#fff":C.tx,padding:"6px 10px",borderRadius:10,fontSize:11,maxWidth:"85%",lineHeight:1.4,boxShadow:C.sh1}}>{n.text}</div>
            <div style={{fontSize:8,color:C.t3,marginTop:1}}>{fDT(n.date)}</div>
          </div>;
        })}
      </div>}
      <div style={{display:"flex",gap:4,padding:"6px 8px",borderTop:hasNotes?"0.5px solid "+C.bd:"none",background:"#fff"}}>
        <input style={{...inp,flex:1,padding:"6px 10px",fontSize:11,boxShadow:"none",background:"#f8f8fa"}} value={text} onChange={e=>setText(e.target.value)} placeholder="Escribe una nota rápida..." onKeyDown={e=>e.key==="Enter"&&send()}/>
        <button onClick={send} style={bs(C.ios)} disabled={!text.trim()}>↑</button>
      </div>
    </div>}
  </div>;
}

// ─── NOTIFICATIONS ────────────────────────────────
function NotificationBell({count,onClick}) {
  // v10.72.39 — /impeccable polish: alto 40px (alinea con los bs vecinos del cluster + touch target),
  // badge anclado al ícono (no a la esquina del botón) con anillo para separarlo del fondo, hover ghost, aria-label con conteo.
  return <button onClick={onClick} aria-label={count>0?"Notificaciones, "+count+" sin leer":"Notificaciones"} title="Notificaciones" onMouseEnter={e=>{e.currentTarget.style.background=C.bd+"55"}} onMouseLeave={e=>{e.currentTarget.style.background="transparent"}} style={{background:"transparent",border:"none",cursor:"pointer",minHeight:40,padding:"0 9px",borderRadius:10,display:"inline-flex",alignItems:"center",justifyContent:"center",color:C.tx,flexShrink:0}}>
    <span style={{position:"relative",display:"inline-flex"}}><BellRingingIcon size={18} weight={count>0?"fill":"regular"}/>{count>0&&<div style={{position:"absolute",top:-6,right:-7,background:C.dn,color:"#fff",minWidth:16,height:16,padding:"0 3px",boxSizing:"border-box",borderRadius:8,fontSize:8,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 0 0 1.5px "+C.card}}>{count>9?"9+":count}</div>}</span>
  </button>;
}

// v10.72.40 — /impeccable craft: command palette (Ctrl/⌘+K). Navega a las vistas del rol + dispara acciones, 100% teclado.
// Patrón combobox+listbox: el foco vive SIEMPRE en el input; ↑↓ mueven una selección virtual (aria-activedescendant);
// Enter ejecuta; Esc/backdrop cierra. No necesita focus-trap porque el foco nunca sale del input.
function CommandPalette({open,onClose,groups}){
  const [q,setQ]=useState("");
  const [sel,setSel]=useState(0);
  const inputRef=useRef(null);
  const norm=s=>(s||"").normalize("NFD").replace(/[̀-ͯ]/g,"").toLowerCase();
  const nq=norm(q.trim());
  const visGroups=groups.map(g=>({...g,items:g.items.filter(it=>!nq||norm(it.label).includes(nq))})).filter(g=>g.items.length);
  const flat=visGroups.flatMap(g=>g.items);
  useEffect(()=>{ if(open){ setQ(""); setSel(0); const id=requestAnimationFrame(()=>inputRef.current&&inputRef.current.focus()); return ()=>cancelAnimationFrame(id); } },[open]);
  useEffect(()=>{ setSel(s=>Math.min(s,Math.max(0,flat.length-1))); },[nq,flat.length]);
  useEffect(()=>{ if(open){const el=document.getElementById("cmdk-opt-"+sel); if(el&&el.scrollIntoView)el.scrollIntoView({block:"nearest"});} },[sel,open]);
  if(!open) return null;
  const run=it=>{ onClose(); it.run(); };
  const onKey=e=>{
    if(e.key==="ArrowDown"){e.preventDefault();setSel(s=>Math.min(s+1,Math.max(0,flat.length-1)));}
    else if(e.key==="ArrowUp"){e.preventDefault();setSel(s=>Math.max(s-1,0));}
    else if(e.key==="Home"){e.preventDefault();setSel(0);}
    else if(e.key==="End"){e.preventDefault();setSel(Math.max(0,flat.length-1));}
    else if(e.key==="Enter"){e.preventDefault(); if(flat[sel])run(flat[sel]);}
    else if(e.key==="Escape"){e.preventDefault(); onClose();}
  };
  let gi=-1;
  return (
    <div onMouseDown={e=>{if(e.target===e.currentTarget)onClose();}} style={{position:"fixed",inset:0,zIndex:2000,background:"rgba(26,26,31,.34)",display:"flex",justifyContent:"center",alignItems:"flex-start",paddingTop:"13vh"}}>
      <div role="dialog" aria-modal="true" aria-label="Paleta de comandos" onMouseDown={e=>e.stopPropagation()} style={{width:"min(560px,94vw)",maxHeight:"68vh",display:"flex",flexDirection:"column",background:C.bg,borderRadius:16,border:"0.5px solid "+C.bd,boxShadow:C.sh3,overflow:"hidden"}}>
        <div style={{display:"flex",alignItems:"center",gap:11,padding:"13px 16px",borderBottom:"0.5px solid "+C.bd,flexShrink:0}}>
          <MagnifyingGlassIcon size={18} color={C.t3} weight="bold" style={{flexShrink:0}}/>
          <input ref={inputRef} value={q} onChange={e=>setQ(e.target.value)} onKeyDown={onKey} role="combobox" aria-expanded={flat.length>0} aria-controls="cmdk-list" aria-activedescendant={flat[sel]?("cmdk-opt-"+sel):undefined} aria-label="Buscar vista o acción" placeholder="Buscar vista o acción…" autoComplete="off" spellCheck={false} style={{flex:1,minWidth:0,border:"none",outline:"none",background:"transparent",fontFamily:"'Geist',sans-serif",fontSize:15,color:C.tx}}/>
          <kbd style={kbdSt}>esc</kbd>
        </div>
        <div id="cmdk-list" role="listbox" aria-label="Comandos" style={{flex:1,overflowY:"auto",overflowX:"hidden",padding:"6px"}}>
          {flat.length===0&&<div style={{padding:"30px 16px",textAlign:"center",color:C.t3,fontSize:13}}>Sin resultados para “{q}”</div>}
          {visGroups.map(g=>(<div key={g.key} role="group" aria-label={g.label}>
            <div aria-hidden="true" style={{fontSize:9.5,fontWeight:700,color:C.t3,textTransform:"uppercase",letterSpacing:".06em",padding:"9px 10px 4px"}}>{g.label}</div>
            {g.items.map(it=>{gi++;const i=gi;const active=i===sel;const Ic=it.icon||SquaresFourIcon;return (
              <button key={it.key} id={"cmdk-opt-"+i} role="option" aria-selected={active} onMouseMove={()=>{if(i!==sel)setSel(i);}} onClick={()=>run(it)} style={{display:"flex",alignItems:"center",gap:11,width:"100%",textAlign:"left",border:"none",cursor:"pointer",borderRadius:9,padding:"9px 11px",background:active?C.acL:"transparent",color:active?C.ac:C.tx,fontFamily:"'Geist',sans-serif",fontSize:13.5,fontWeight:active?700:500}}>
                <Ic size={17} weight={active?"fill":"regular"} style={{flexShrink:0,color:active?C.ac:C.t2}}/>
                <span style={{flex:1,minWidth:0,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{it.label}</span>
                {it.current&&<span style={{fontSize:10,color:active?C.ac:C.t3,fontWeight:600,flexShrink:0}}>actual</span>}
              </button>);})}
          </div>))}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:16,padding:"8px 14px",borderTop:"0.5px solid "+C.bd,fontSize:10.5,color:C.t3,flexShrink:0}}>
          <span style={{display:"inline-flex",alignItems:"center",gap:5}}><kbd style={kbdSt}>↑</kbd><kbd style={kbdSt}>↓</kbd>navegar</span>
          <span style={{display:"inline-flex",alignItems:"center",gap:5}}><kbd style={kbdSt}>↵</kbd>abrir</span>
          <span style={{display:"inline-flex",alignItems:"center",gap:5}}><kbd style={kbdSt}>esc</kbd>cerrar</span>
        </div>
      </div>
    </div>
  );
}
function NotificationTray({notifications,onClose,onRead,onReadAll,onDelete,onDeleteAll,role}) {
  useEscClose(onClose);
  return <div style={{position:"fixed",inset:0,zIndex:998}} onClick={onClose}>
    <div style={{position:"absolute",top:48,right:16,background:C.bg,borderRadius:16,boxShadow:C.sh3,width:360,maxHeight:"70vh",overflow:"hidden",border:"0.5px solid "+C.bd}} onClick={e=>e.stopPropagation()}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"14px 16px",borderBottom:"0.5px solid "+C.bd}}>
        <span style={{fontSize:14,fontWeight:800,display:"inline-flex",alignItems:"center",gap:6}}><BellRingingIcon size={15} weight="fill"/>Notificaciones</span>
        <div style={{display:"flex",gap:4}}>
          <button onClick={onReadAll} style={{...bs(C.sf,C.t2),boxShadow:"0 0 0 0.5px "+C.bd}}>Leídas</button>
          {notifications.length>0&&<button onClick={onDeleteAll} style={{...bs(C.sf,C.dn),boxShadow:"0 0 0 0.5px "+C.bd}}><TrashIcon size={12} weight="bold"/>Borrar todas</button>}
        </div>
      </div>
      <div style={{overflowY:"auto",maxHeight:"calc(70vh - 56px)"}}>
        {notifications.length===0?<div style={{textAlign:"center",padding:"40px 20px",color:C.t3}}><div style={{display:"flex",justifyContent:"center"}}><CheckCircleIcon size={32} weight="fill" color={C.ok}/></div><div style={{fontSize:12,marginTop:8}}>Sin notificaciones</div></div>
        :notifications.map(n=><div key={n.id} onClick={()=>!n.read&&onRead(n.id)} style={{padding:"12px 16px",borderBottom:"0.5px solid "+C.bd,background:n.read?"transparent":C.ios+"06",cursor:n.read?"default":"pointer"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
            <div style={{flex:1}}>
              <div style={{fontSize:12,fontWeight:n.read?500:700,color:C.tx}}>{n.message}</div>
              {n.reason&&<div style={{fontSize:11,color:C.wn,marginTop:2,fontStyle:"italic"}}><ChatCircleIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Motivo: {n.reason}</div>}
              <div style={{fontSize:9,color:C.t3,marginTop:3}}>
                <span style={{color:AUTHOR_COLOR[n.by_user]||C.t3,fontWeight:600}}>{AUTHOR_NAME[n.by_user]||n.by_user}</span> · {fDT(n.created_at)}
              </div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
              {!n.read&&<div style={{width:8,height:8,borderRadius:"50%",background:C.ios}}/>}
              <button onClick={e=>{e.stopPropagation();onDelete(n.id)}} style={{background:"none",border:"none",cursor:"pointer",fontSize:14,color:C.t3,padding:"2px 4px",display:"inline-flex",alignItems:"center"}} title="Borrar"><XIcon size={13} weight="bold"/></button>
            </div>
          </div>
        </div>)}
      </div>
    </div>
  </div>;
}

// ─── MODALS ────────────────────────────────────────
function PrintOrder({order:o,onClose,role,userLogin,onPrintError}) {
  useEscClose(onClose);
  const [printing,setPrinting]=useState(false);
  // v10.53.1 M2 — mountedRef previene setState/callback en componente desmontado
  const mountedRef=useRef(true);
  useEffect(()=>()=>{mountedRef.current=false},[]);
  // v10.34.2 fix #9 — escape para interpolaciones de standard_size en HTML template (defensa contra IDs corruptos en BD)
  const esc=s=>String(s||"").replace(/[<>&"]/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;'}[c]));
  const pDate=o.created_at?new Date(o.created_at):new Date();
  const dDate=o.due_date?new Date(o.due_date+"T12:00:00"):null;
  const months=["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];
  const isUrg=o.priority==="urgente";const isNorm=o.priority==="normal"||(!o.priority);const isBaja=o.priority==="baja";
  const isMaq=o.order_type==="maquila";
  // v10.72.65 — Venta de stock (Cuadra, stock_role='sale') que consumió un folio de PRODUCCIÓN P- por el bug
  // ya corregido (43 históricas). Su copia impresa lleva marca de agua CANCELADO + leyenda: el folio P se tomó
  // por error y queda anulado (no es una orden de producción real; la venta se cobra por su folio fiscal D-/R-).
  // Las ventas nuevas ya nacen sin P- (trigger), así que NO matchean (production_number NULL).
  const isVoidStockSale=o.stock_role==="sale"&&/^P-/.test(String(o.production_number||""));
  // mode: "full" = con precio y contacto (secretaría/admin), "production" = sin precio ni contacto (para piso)
  // v10.53.0 — async: registra la impresión ANTES de abrir el window para incluir versión + hash en la hoja.
  // v10.53.1 C1 — try/finally global para garantizar setPrinting(false) en TODOS los paths.
  const printIt=async(mode)=>{
    if(printing) return;
    setPrinting(true);
    try{
      // v10.58.59 — "peek" de solo lectura: la hoja muestra la PRÓXIMA versión pero NO
      // la graba. El registro real (incremento + audit + needs_reprint=false) ocurre
      // cuando el usuario presiona "🖨️ Imprimir ahora" en la ventana (postMessage →
      // listener del root → db.registerPrint). Un misclick que cierra la ventana NO cuenta.
      let printInfo=null;
      try{
        const peek=await db.peekPrint(o.id);
        printInfo={version:peek.version, content_hash:peek.content_hash, is_reprint:peek.is_reprint, printed_at:new Date().toISOString(), printed_by:userLogin||"sistema", failed:false};
      }catch(e){
        // Si falla el peek (network, permisos), igual permitimos imprimir pero la hoja
        // saldrá "SIN REGISTRO" (y el commit posterior también fallaría).
        console.warn("[peek_print] falló, imprimiendo sin versión:", e?.message);
        if(onPrintError) onPrintError("⚠️ No se pudo leer la versión ("+(e?.message||"red caída")+"). La hoja saldrá con etiqueta SIN REGISTRO.");
        printInfo={version:o.print_version||"?", printed_at:new Date().toISOString(), printed_by:userLogin||"sistema", content_hash:"NO-REG", failed:true};
      }

      const w=window.open("","_blank","width=800,height=900");
      // v10.58.63: popup bloqueado — antes retornaba en silencio (el usuario creía que
      // imprimió). Ahora avisa. (try/finally garantiza setPrinting(false).)
      if(!w){ if(onPrintError) onPrintError("⚠️ El navegador bloqueó la ventana de impresión. Permite ventanas emergentes para este sitio y reintenta."); return; }
      const isProd=mode==="production";
      // v10.53.2 m2 — etiquetas claras cuando register_print falla (no más "v?" críptico)
      const pvFailed=!!printInfo.failed;
      const pvVersionLabel=pvFailed?"SIN REGISTRO":("v"+printInfo.version);
      const pvHash=printInfo.content_hash;
      const pvWhen=new Date(printInfo.printed_at);
      const pvWhenStr=pvWhen.getDate()+"-"+months[pvWhen.getMonth()].slice(0,3).toLowerCase()+" "+
        String(pvWhen.getHours()).padStart(2,"0")+":"+String(pvWhen.getMinutes()).padStart(2,"0");
      const pvWho=printInfo.printed_by;
      // v10.58.60 — REIMPRESO = mismo contenido ya impreso antes (is_reprint del backend),
      // no "version>1" (la versión ahora es por contenido, no por # de impresiones)
      const isReprint=!pvFailed && !!printInfo.is_reprint;
    let h=`<html><head><title>Orden ${o.production_number||o.id}</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:Arial,Helvetica,sans-serif;padding:18px 22px;font-size:11px;color:#1a1a1a}
table{width:100%;border-collapse:collapse}
td,th{border:1px solid #444;padding:5px 7px;vertical-align:top}
.header{display:flex;align-items:stretch;border:2.5px solid #222;margin-bottom:0}
.header-logo{width:160px;padding:8px 10px;text-align:center;border-right:2.5px solid #222;display:flex;align-items:center;justify-content:center}
.header-title{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:8px 10px}
.header-title .main{font-size:20px;font-weight:800;letter-spacing:1px;text-transform:uppercase}
.header-title .sub{font-size:9px;color:#666;margin-top:2px;letter-spacing:.5px}
.header-title .copy-badge{font-size:8px;color:#fff;background:#c00;padding:2px 8px;border-radius:3px;margin-top:4px;letter-spacing:1px;text-transform:uppercase;display:inline-block}
.vbanner{padding:7px 10px;text-align:center;border:2.5px solid #222;border-top:none}
.vbanner .vt{font-size:15px;font-weight:800;letter-spacing:3px;text-transform:uppercase;line-height:1.1}
.vbanner .vs{display:block;font-size:8px;font-weight:600;letter-spacing:1.2px;margin-top:2px;text-transform:uppercase}
.vbanner.admin{background:#1a1a1a;color:#fff}
.vbanner.prod{background:#fff;color:#111}
.vcancel-wm{position:fixed;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none;z-index:9;overflow:hidden;-webkit-print-color-adjust:exact;print-color-adjust:exact}
.vcancel-wm span{font-size:128px;font-weight:900;letter-spacing:10px;color:rgba(178,0,0,.26);border:9px solid rgba(178,0,0,.26);border-radius:14px;padding:4px 46px;transform:rotate(-26deg);text-transform:uppercase;white-space:nowrap;line-height:1;font-family:Arial,Helvetica,sans-serif}
.vcancel-note{margin-top:6px;border:3px solid #111;background:#fff;border-radius:4px;padding:9px 13px;-webkit-print-color-adjust:exact;print-color-adjust:exact}
.vcancel-note .vct{font-size:14px;font-weight:900;color:#111;letter-spacing:.6px;text-transform:uppercase;line-height:1.2}
.vcancel-note .vcd{font-size:9.5px;color:#222;margin-top:3px;line-height:1.55}
.header-folio{width:140px;border-left:2.5px solid #222;padding:8px 10px;text-align:center;display:flex;flex-direction:column;align-items:center;justify-content:center}
.header-folio .lbl{font-size:8px;font-weight:700;text-transform:uppercase;color:#666;margin-bottom:4px;letter-spacing:1px}
.header-folio .num{font-size:26px;font-weight:800;color:#c00;line-height:1}
.header-folio .cart{font-size:10px;font-weight:700;color:#0891b2;margin-top:4px;letter-spacing:.5px}
.header-folio .webf{font-size:8px;font-weight:600;color:#94a3b8;margin-top:1px;letter-spacing:.3px}
.header-folio .date{font-size:8px;color:#888;margin-top:4px}
.section-title{background:#e0e0e0;font-size:8px;font-weight:800;text-transform:uppercase;text-align:center;padding:4px;letter-spacing:1.5px;color:#333}
.field-lbl{font-size:7px;font-weight:700;color:#777;text-transform:uppercase;letter-spacing:.3px}
.field-val{font-size:12px;font-weight:600;min-height:16px;margin-top:1px}
.check{display:inline-block;width:11px;height:11px;border:1.5px solid #aaa;margin-right:3px;vertical-align:middle;text-align:center;font-size:9px;line-height:11px;color:transparent}
.check.on{color:#000;font-weight:bold;border-color:#000}
.fin-tag{display:inline-block;background:#ededed;border:0.75px solid #b0b0b0;border-radius:4px;padding:2px 7px;margin-left:6px;font-size:7.5px;font-weight:700;color:#1a1a1a;letter-spacing:.4px;vertical-align:1px;text-transform:uppercase;line-height:1.3}
.sig-row{display:flex;gap:16px;margin-top:28px;page-break-inside:avoid}
.sig-box{flex:1;border-top:1.5px solid #000;padding-top:5px;text-align:center;font-size:7px;color:#999;text-transform:uppercase;letter-spacing:.5px}
.imp-table td{height:20px}
.imp-table .hdr{font-size:7px;font-weight:800;text-align:center;background:#f0f0f0;text-transform:uppercase;letter-spacing:.5px}
.otros-row{font-size:10px;padding:3px 7px;border-top:none}
.product-images{display:flex;gap:8px;margin-top:-1px;border:1px solid #444;padding:6px;background:#fafafa;page-break-inside:avoid}
.product-images .ptitle{font-size:7px;font-weight:800;color:#777;text-transform:uppercase;letter-spacing:.3px;margin-bottom:4px}
.product-images img{max-width:100%;max-height:180px;object-fit:contain;border:1px solid #ddd;background:#fff}
.pay-badge{display:inline-block;padding:3px 9px;border-radius:4px;font-size:9px;font-weight:800;letter-spacing:.5px;text-transform:uppercase}
.pay-paid{background:#dcfce7;color:#15803d;border:1px solid #16a34a}
.pay-partial{background:#fef3c7;color:#a16207;border:1px solid #ca8a04}
.pay-unpaid{background:#fee2e2;color:#b91c1c;border:1px solid #dc2626}
.print-version-corner{position:fixed;top:6mm;right:6mm;font-size:10px;font-weight:800;color:#fff;background:#111;padding:4px 10px;border-radius:4px;letter-spacing:.5px;z-index:10}
.print-version-corner.reprint{background:#dc2626}
.print-version-corner.unregistered{background:#a16207}
.print-footer{margin-top:24px;padding-top:8px;border-top:1px dashed #999;font-size:8px;color:#666;letter-spacing:.3px;display:flex;justify-content:space-between;align-items:center}
.print-footer .pv-hash{font-family:Courier,monospace;font-weight:700;color:#222;font-size:9px;background:#f0f0f0;padding:2px 6px;border-radius:3px}
.print-footer .pv-reprint-tag{color:#dc2626;font-weight:800;text-transform:uppercase}
.pf-toolbar{position:sticky;top:0;left:0;right:0;background:#1a1a1a;color:#fff;padding:10px 16px;display:flex;gap:10px;align-items:center;justify-content:center;z-index:99;box-shadow:0 2px 8px rgba(0,0,0,.3)}
.pf-toolbar button{font-family:inherit;cursor:pointer;border:none;border-radius:8px}
.pf-toolbar .pf-go{font-size:15px;font-weight:700;padding:10px 26px;background:#16a34a;color:#fff}
.pf-toolbar .pf-close{font-size:13px;padding:10px 18px;background:#444;color:#fff}
.pf-toolbar .pf-ver{font-size:12px;font-weight:800;color:#fbbf24;letter-spacing:.5px;margin-left:6px}
.pf-toolbar .pf-note{font-size:11px;color:#bbb;margin-left:4px}
@media screen{.print-version-corner{top:60px}}
@media print{body{padding:10px 14px}@page{margin:8mm}.page-break{page-break-after:always}.print-version-corner{top:3mm!important;right:3mm}.no-print{display:none!important}}
</style></head><body>
<div class="pf-toolbar no-print">
  <button class="pf-go" onclick="pfPrint()">🖨️ Imprimir ahora</button>
  <button class="pf-close" onclick="window.close()">Cerrar</button>
  <span class="pf-ver">${pvVersionLabel}${isReprint?" · REIMPRESO":""}</span>
  <span class="pf-note">${pvFailed?"⚠️ No se pudo registrar — saldrá SIN REGISTRO":"Se registra al imprimir"}</span>
</div>
<script>
  var __pfCommitted=false, __pfAcked=false, __pfAckTimer=null;
  var __pfFailed=${pvFailed?"true":"false"};
  // v10.58.64 M4: el padre confirma (ack) que SÍ registró; si no llega (padre recargado
  // o con sesión cerrada mientras esta ventana seguía abierta) avisamos.
  // v10.58.67 Bug 7: al llegar el ack cancelamos el timer (red lenta legítima ya no
  // dispara falso aviso) y el umbral sube a 8s.
  window.addEventListener("message", function(e){
    if(e.data && e.data.type==="pf-print-ack"){
      __pfAcked=true;
      if(__pfAckTimer){ clearTimeout(__pfAckTimer); __pfAckTimer=null; }
      if(e.data.ok===false) alert("⚠️ "+(e.data.reason||"La impresión NO se registró. Reimprime desde la app."));
    }
  });
  // v10.71.5 — "fit to one page": si el contenido excede una hoja Carta, se reduce (zoom)
  // proporcionalmente para que NO se parta en 2 páginas. #pf-pageref mide 1 hoja imprimible en mm
  // (ratio independiente del DPI). Solo encoge cuando hace falta; las órdenes de 1 hoja no se tocan.
  function pfFit(){
    try{
      var s=document.getElementById('pf-sheet'); if(!s) return;
      s.style.zoom='';
      var ref=document.getElementById('pf-pageref'); if(!ref) return;
      var pageH=ref.offsetHeight, h=s.offsetHeight;
      if(pageH>0 && h>pageH){ s.style.zoom=(pageH/h*0.97).toFixed(4); }
    }catch(e){}
  }
  window.addEventListener('load', pfFit);
  function pfPrint(){
    pfFit();
    if(__pfFailed){ window.print(); return; }
    // v10.58.64 #1: si esta versión YA se registró en esta ventana, reimprimir el mismo
    // papel no necesita opener (antes el check de abajo bloqueaba un reimpreso legítimo).
    if(__pfCommitted){ window.print(); return; }
    if(!window.opener || window.opener.closed){
      alert("⚠️ No se puede registrar la impresión porque PrintFlow se cerró o recargó.\\n\\nVuelve a abrir la orden desde la app e imprime de nuevo para que la versión quede registrada.");
      return;
    }
    if(!__pfCommitted){
      __pfCommitted=true;
      try{ window.opener.postMessage({type:"pf-print-commit",orderId:${JSON.stringify(o.id)},user:${JSON.stringify(userLogin||"sistema")},hash:${JSON.stringify(pvHash)}},${JSON.stringify(window.location.origin)}); }catch(e){}
      __pfAckTimer=setTimeout(function(){ if(!__pfAcked) alert("⚠️ No se confirmó el registro de esta impresión (¿PrintFlow se recargó o cerró sesión?). Reimprime la orden desde la app para que quede registrada."); }, 8000);
    }
    window.print();
  }
</script>
<div class="print-version-corner${pvFailed?" unregistered":(isReprint?" reprint":"")}">${pvVersionLabel}${isReprint?" — REIMPRESO":""}${pvFailed?" ⚠️":""}</div>
${isVoidStockSale?'<div class="vcancel-wm"><span>CANCELADO</span></div>':''}
<div id="pf-pageref" style="position:absolute;top:0;left:0;width:1px;height:257mm;visibility:hidden;pointer-events:none"></div>
<div id="pf-sheet">`;

    // ═══ HEADER ═══
    // v10.52.0 — logo desde /public/sygma-logo.png con fallback a SYGMA_LOGO data URL
    // v10.52.1 — badge web + indicador OC split
    const logoSrc=window.location.origin+"/sygma-logo.png";
    // v10.72.23 — "Sin empaque SYGMA": ocultar el logo en la orden impresa (white-label para imprenta externa)
    const logoHtml=o.sin_empaque_sygma?'<div style="font-size:9px;font-weight:700;color:#9ca3af;text-align:center;line-height:1.4;letter-spacing:.5px">SIN<br>LOGO</div>':`<img src="${logoSrc}" onerror="this.onerror=null;this.src='${SYGMA_LOGO}'" style="max-width:140px;max-height:80px;height:auto;width:auto;"/>`;
    const isWebOrder=o.source==="web";
    const isOcSplit=!!o.oc_invoice_group_id; // orden pertenece a grupo OC split (v10.51.0)
    h+=`<div class="header">
      <div class="header-logo">${logoHtml}</div>
      <div class="header-title"><div class="main">Orden de Producción</div><div class="sub">Padilla Hnos. Impresora · León, Gto.</div>${isWebOrder?'<div style="font-size:8px;color:#fff;background:#06b6d4;padding:2px 8px;border-radius:3px;margin-top:4px;letter-spacing:1px;text-transform:uppercase;display:inline-block">🌐 Pedido Web</div>':''}</div>
      <div class="header-folio"><div class="lbl">Folio</div><div class="num"${isVoidStockSale?' style="text-decoration:line-through;text-decoration-thickness:3px;color:#888"':''}>${o.production_number||o.id}</div>${o.cart_folio?'<div class="cart">🛒 '+esc(o.cart_folio)+'</div>':''}${o.web_folio?'<div class="webf">'+esc(o.web_folio)+'</div>':''}${o.purchase_order_id?'<div class="webf" style="color:#7c3aed;margin-top:2px;font-weight:700">📦 '+esc(o.purchase_order_id)+'</div>':''}${o.invoice_folio?'<div class="invf" style="font-size:14px;font-weight:800;color:'+(o.invoice_type==="factura"?"#5856d6":"#34c759")+';margin-top:4px;">'+(o.invoice_type==="factura"?"📄":"📋")+' '+esc(o.invoice_folio)+'</div>':''}${isOcSplit?'<div style="font-size:7px;color:#7c3aed;margin-top:2px;font-weight:700;font-style:italic">↳ Folio compartido (OC dividida)</div>':''}<div class="date">${pDate.getDate()} ${months[pDate.getMonth()].slice(0,3)} ${pDate.getFullYear()}</div></div>
    </div>`;

    // v10.72.62 — banner de VERSIÓN, muy visible y B&N-proof: ADMINISTRATIVA = barra negra sólida (invertida);
    // PRODUCCIÓN = barra blanca con borde. Reemplaza el badge rojo de 8px (que en fotocopia B&N era ilegible).
    h+=`<div class="vbanner ${isProd?'prod':'admin'}"><span class="vt">${isProd?'Copia de Producción':'Copia Administrativa'}</span><span class="vs">${isProd?'Para taller · sin precios ni datos fiscales':'Completa · con precios y datos fiscales'}</span></div>`;

    // v10.72.65 — leyenda de venta de stock que tomó folio P- por el bug (ver isVoidStockSale arriba)
    if(isVoidStockSale){
      const pf=esc(o.production_number||"");
      const ff=o.invoice_folio?esc(o.invoice_folio):null;
      h+=`<div class="vcancel-note"><div class="vct">⚠ Folio de producción ${pf} CANCELADO — error del sistema</div><div class="vcd">Esta hoja es una <b>VENTA DE STOCK</b> que consumió el folio de producción <b>${pf}</b> por un <b>error del sistema</b>, ya corregido. Las ventas de stock <b>no deben llevar folio de producción</b>: el folio <b>${pf}</b> queda <b>CANCELADO / anulado</b> y esta <b>NO es una orden de producción real</b>.${ff?` El cobro de esta venta corresponde a su folio fiscal <b>${ff}</b>.`:""}</div></div>`;
    }

    // v10.72.23 — recuadro de aviso "sin logo SYGMA" (white-label) — muy visible, debajo del header
    if(o.sin_empaque_sygma){
      h+=`<div style="margin-top:6px;border:2.5px solid #b91c1c;background:#fef2f2;border-radius:4px;padding:7px 12px;display:flex;align-items:center;gap:9px">
        <div style="font-size:19px;line-height:1">⚠️</div>
        <div><div style="font-size:12.5px;font-weight:800;color:#b91c1c;letter-spacing:.5px">EMPACAR SIN LOGOS DE SYGMA</div><div style="font-size:9px;color:#7f1d1d;margin-top:1px">Trabajo para imprenta externa. Empacar SIN logotipos ni identificación de SYGMA / Padilla Hnos.</div></div>
      </div>`;
    }

    // ═══ FECHAS + TIPO PROCESO ═══
    h+=`<table style="margin-top:-1px"><tr>
      <td style="width:33%"><div class="field-lbl">Fecha de Pedido</div><div class="field-val">${pDate.getDate()} / ${months[pDate.getMonth()]} / ${pDate.getFullYear()}</div></td>
      <td style="width:34%;text-align:center"><div class="field-lbl">Tipo de Proceso</div><div style="display:flex;gap:14px;justify-content:center;margin-top:3px">
        <span><span class="check${isNorm?" on":""}">✓</span> Normal</span>
        <span><span class="check${isUrg?" on":""}">✓</span> Urgente</span>
        <span><span class="check${isBaja?" on":""}">✓</span> Baja</span>
      </div></td>
      <td style="width:33%"><div class="field-lbl">Fecha de Entrega</div><div class="field-val" style="color:${isUrg?"#c00":"inherit"};font-weight:800">${dDate?dDate.getDate()+" / "+months[dDate.getMonth()]+" / "+dDate.getFullYear():"—"}</div></td>
    </tr></table>`;

    // ═══ DATOS DEL CLIENTE ═══
    if(isProd){
      // Production copy: client name + agente (contacto del cliente). Sin teléfono/email (datos de contacto sensibles).
      h+=`<table style="margin-top:-1px"><tr><td colspan="2" class="section-title">Cliente</td></tr>
      <tr><td style="width:62%"><div class="field-lbl">Nombre</div><div class="field-val" style="font-size:14px">${esc(o.client||"—")}</div></td>
      <td style="width:38%"><div class="field-lbl">Agente</div><div class="field-val">${esc(o.client_agent||"—")}</div></td></tr></table>`;
    } else {
      // Full copy: all client data
      h+=`<table style="margin-top:-1px"><tr><td colspan="4" class="section-title">Datos del Cliente</td></tr>
      <tr><td style="width:35%"><div class="field-lbl">Nombre o Denominación</div><div class="field-val" style="font-size:14px">${esc(o.client||"—")}</div></td>
      <td style="width:25%"><div class="field-lbl">Agente</div><div class="field-val">${esc(o.client_agent||"—")}</div></td>
      <td style="width:20%"><div class="field-lbl">Teléfono</div><div class="field-val">${o.client_phone?esc((o.client_lada||"+52")+" "+o.client_phone):""}</div></td>
      <td style="width:20%"><div class="field-lbl">Email</div><div class="field-val" style="font-size:10px">${esc(o.client_email||"")}</div></td></tr></table>`;
    }

    // ═══ DATOS DE LA FORMA ═══
    const hasSpecs=!!(o.paper_type||o.ink_front||o.width_cm); // v10.34.2 fix #5 — standard_size solo no debe activar sección Impresión completa (queda casi vacía)
    const isAdvanced=!!(o.product&&!hasSpecs);
    h+=`<table style="margin-top:-1px"><tr><td colspan="4" class="section-title">Datos de la Forma</td></tr>
    <tr>
      <td style="width:15%"><div class="field-lbl">Cantidad</div><div class="field-val" style="font-size:16px;font-weight:800;color:#c00">${o.quantity?Number(o.quantity).toLocaleString():""}</div></td>
      <td style="width:35%"><div class="field-lbl">Tipo de Producto</div><div class="field-val" style="font-size:13px">${esc(o.product_type||"")}</div></td>
      ${!isAdvanced?`<td style="width:30%"><div class="field-lbl">Tamaño Final</div><div class="field-val">${o.standard_size?esc(ssLabel(o.standard_size)):(o.width_cm&&o.height_cm?o.width_cm+" × "+o.height_cm+" cm":"")}</div></td>`:`<td style="width:30%"><div class="field-lbl">Modo</div><div class="field-val" style="font-size:10px;color:#8b5cf6;font-weight:700">📖 Datos técnicos en descripción</div></td>`}
      <td style="width:20%"><div class="field-lbl">Tipo de Orden</div><div class="field-val">${isMaq?"Maquila":"Interna"}</div></td>
    </tr>
    ${o.product?`<tr><td colspan="4"><div class="field-lbl">${isAdvanced?"Datos Técnicos Completos":"Descripción del Producto"}</div><div class="field-val" style="font-size:${isAdvanced?"12":"12"}px;line-height:1.6;white-space:pre-wrap;min-height:${isAdvanced?"40":"24"}px;${isAdvanced?"padding:4px 0;":""}${isAdvanced?"border-top:1px dashed #ccc;padding-top:6px;":""}">${esc(o.product)}</div></td></tr>`:""}
    </table>`;

    // ═══ IMÁGENES DEL PRODUCTO (v10.52.0) ═══
    // Muestra image_url y/o image_url_2 si existen. Fallback a image (legacy) o file_url si es imagen.
    const isImgUrl=(u)=>u&&/\.(jpe?g|png|gif|webp)$/i.test(u);
    const imgs=[o.image_url, o.image_url_2,
      (!o.image_url&&!o.image_url_2&&o.image)?o.image:null,
      (!o.image_url&&!o.image_url_2&&!o.image&&isImgUrl(o.file_url||o.file_name))?o.file_url:null
    ].filter(Boolean);
    if(imgs.length>0){
      h+=`<div class="product-images">
        <div style="flex:1;text-align:center">
          <div class="ptitle">${imgs.length>1?"Imagen 1 (Frente)":"Imagen del Producto"}</div>
          <img src="${esc(imgs[0])}" alt="" onerror="this.style.display='none'"/>
        </div>
        ${imgs[1]?`<div style="flex:1;text-align:center">
          <div class="ptitle">Imagen 2 (Vuelta)</div>
          <img src="${esc(imgs[1])}" alt="" onerror="this.style.display='none'"/>
        </div>`:""}
      </div>`;
    }

    // ═══ IMPRESIÓN (solo si hay specs individuales) ═══
    if(!isMaq&&hasSpecs){
      h+=`<table class="imp-table" style="margin-top:-1px">
      <tr><td colspan="5" class="section-title">Impresión</td></tr>
      <tr class="hdr"><td class="hdr" style="width:28%">Tipo de Papel</td><td class="hdr" style="width:12%">Gramaje</td><td class="hdr" style="width:25%">Tintas Frente</td><td class="hdr" style="width:25%">Tintas Vuelta</td><td class="hdr" style="width:10%">Medidas</td></tr>
      <tr><td style="font-weight:600">${esc(o.paper_type||"")}</td><td style="text-align:center;font-weight:600">${o.paper_grammage?o.paper_grammage+" grs":""}</td><td style="font-weight:600">${esc(o.ink_front||o.colors||"")}</td><td style="font-weight:600">${esc(o.ink_back||"")}</td><td style="text-align:center">${o.standard_size?esc(ssLabel(o.standard_size)):(o.width_cm&&o.height_cm?o.width_cm+" × "+o.height_cm:"")}</td></tr>
      </table>`;
    }
    // v10.25.2 — Pantones en bloque independiente (aparece en modo Sencillo Y Avanzado, mientras haya pantones capturados)
    if(!isMaq&&((Array.isArray(o.pantone_front)&&o.pantone_front.length>0)||(Array.isArray(o.pantone_back)&&o.pantone_back.length>0))){
      h+=`<table class="imp-table" style="margin-top:-1px">
      <tr><td colspan="2" class="section-title">🎨 Pantones</td></tr>
      <tr class="hdr"><td class="hdr" style="width:50%">Frente</td><td class="hdr" style="width:50%">Vuelta</td></tr>
      <tr><td style="font-weight:600">${(o.pantone_front||[]).map(esc).join(", ")||"—"}</td><td style="font-weight:600">${(o.pantone_back||[]).map(esc).join(", ")||"—"}</td></tr>
      </table>`;
    }

    // ═══ PROCESOS ESPECIALES Y ACABADOS (solo si hay specs o acabados) ═══
    if(!isMaq&&(hasSpecs||o.finishes)){
      const acabados=(o.finishes||"").split(",").map(s=>s.trim()).filter(Boolean);
      // v10.72.48: solo los 3 SPECIAL_FIN (con sub-detalle) marcan casilla por prefijo;
      // el resto exige nombre EXACTO. Así "Doblez especial mariposa" (texto libre) NO palomea Doblez.
      const SPECIAL_LC=SPECIAL_FIN.map(s=>s.toLowerCase());
      const ac=a=>{const al=a.toLowerCase();const sp=SPECIAL_LC.includes(al);return acabados.some(x=>{const xl=x.toLowerCase();return xl===al||(sp&&xl.startsWith(al+" "));});};
      const acDetail=a=>{const e=acabados.find(x=>x.toLowerCase().startsWith(a.toLowerCase()+" "));return e?e.slice(a.length).trim():""};
      // v10.72.47: lo escrito en "Otro" es FIEL — NO se auto-mapea a casillas por sinónimo.
      // Antes (v10.58.61) "laminado"/"suaje"/"block" palomeaban Plastificado/Suajado/Blocks y se
      // ocultaban de "Otros", PERDIENDO el detalle (ej. "Laminado Mate" → Plastificado ✓ sin "mate").
      // Ahora esos términos salen LITERALES en "Otros"; las casillas solo se marcan con el nombre canónico.
      const ACABADO_ALIASES=["barniz brillante","barniz mate","barniz a registro","doblez","intercalado","grapado","perforado","plastificado","suajado","botado","forma suelta","blocks","folio","engomado superior","engomado lateral"];
      // v10.72.48: excluir de "Otros" SOLO el nombre canónico exacto (finBase ya cubre los SPECIAL con detalle);
      // un texto libre que solo EMPIECE con un canónico (ej. "Doblez especial mariposa") va LITERAL a "Otros".
      const customAcabados=acabados.filter(a=>!FINISHES.includes(finBase(a))&&!ACABADO_ALIASES.includes(a.toLowerCase()));
      if(acabados.length>0||hasSpecs){
      h+=`<table style="margin-top:-1px"><tr><td colspan="4" class="section-title">Procesos Especiales y Acabados</td></tr>
      <tr>
        <td style="width:25%"><span class="check${ac("barniz brillante")?" on":""}">✓</span> Barniz Brillante<br/><span class="check${ac("barniz mate")?" on":""}">✓</span> Barniz Mate<br/><span class="check${ac("barniz a registro")?" on":""}">✓</span> Barniz a Registro</td>
        <td style="width:25%"><span class="check${ac("doblez")?" on":""}">✓</span> Doblez<br/><span class="check${ac("intercalado")?" on":""}">✓</span> Intercalado<br/><span class="check${ac("grapado")?" on":""}">✓</span> Grapado</td>
        <td style="width:25%"><span class="check${ac("perforado")?" on":""}">✓</span> Perforado<br/><span class="check${ac("plastificado")?" on":""}">✓</span> Plastificado${(ac("plastificado")&&acDetail("plastificado"))?" <span class='fin-tag'>"+esc(acDetail("plastificado"))+"</span>":""}<br/><span class="check${ac("suajado")?" on":""}">✓</span> Suajado<br/><span class="check${ac("botado")?" on":""}">✓</span> Botado</td>
        <td style="width:25%"><span class="check${ac("forma suelta")?" on":""}">✓</span> Forma Suelta<br/><span class="check${ac("blocks")?" on":""}">✓</span> Blocks${(ac("blocks")&&acDetail("blocks"))?" <span class='fin-tag'>"+esc(acDetail("blocks"))+"</span>":""}<br/><span class="check${ac("folio")?" on":""}">✓</span> Folio${(ac("folio")&&acDetail("folio"))?" <span class='fin-tag'>"+esc(acDetail("folio"))+"</span>":""}<br/><span class="check${ac("engomado superior")?" on":""}">✓</span> Engomado Sup.<br/><span class="check${ac("engomado lateral")?" on":""}">✓</span> Engomado Lat.</td>
      </tr>
      ${customAcabados.length>0?`<tr><td colspan="4" class="otros-row"><strong>Otros:</strong> ${customAcabados.map(esc).join(", ")}</td></tr>`:""}
      </table>`;
      }
    }

    // ═══ MAQUILA (solo versión completa — proveedor + costo) ═══
    if(isMaq&&!isProd){
      h+=`<table style="margin-top:-1px"><tr><td colspan="3" class="section-title">🚚 Datos de Maquila</td></tr>
      <tr><td style="width:40%"><div class="field-lbl">Proveedor</div><div class="field-val" style="font-size:13px">${esc(o.maq_provider||"")}</div></td>
      <td style="width:30%"><div class="field-lbl">Costo Maquila</div><div class="field-val">${o.maq_cost?fmt(o.maq_cost):""}</div></td>
      <td style="width:30%"><div class="field-lbl">Precio Cliente</div><div class="field-val" style="font-weight:800;color:#16a34a">${o.maq_price?fmt(o.maq_price):""}</div></td></tr></table>`;
    }
    // v10.52.1 M-EXT — Maquila parcial (proveedor externo). Ahora visible EN AMBAS versiones
    // — el piso necesita saber dónde se envía el trabajo (encuadernación, acabado externo, etc.).
    // En versión producción se OCULTA email (PII innecesaria); se mantiene proveedor + teléfono.
    if(!isMaq&&o.maquila_provider){
      h+=`<table style="margin-top:-1px"><tr><td colspan="3" class="section-title">🚚 Maquila Externa (Proveedor)</td></tr>
      <tr><td style="width:40%"><div class="field-lbl">Proveedor</div><div class="field-val">${esc(o.maquila_provider)}</div></td>
      <td style="width:30%"><div class="field-lbl">Teléfono</div><div class="field-val">${esc(o.maquila_phone||"")}</div></td>
      <td style="width:30%"><div class="field-lbl">${isProd?"":"Email"}</div><div class="field-val">${isProd?"":esc(o.maquila_email||"")}</div></td></tr></table>`;
    }

    // ═══ INSTRUCCIONES ═══
    h+=`<table style="margin-top:-1px"><tr><td><div class="field-lbl">Instrucciones Complementarias / Notas</div><div class="field-val" style="min-height:28px;font-size:11px;line-height:1.5;white-space:pre-wrap">${esc(o.notes||"")}</div></td></tr></table>`;

    // ═══ DISTRIBUCIÓN (lista de lugares) — v10.72.0, ambas versiones + maquila ═══
    if(Array.isArray(o.distribution)){
      const _lug=o.distribution.map(x=>String(x||"").trim()).filter(Boolean);
      if(_lug.length){
        h+=`<table style="margin-top:-1px"><tr><td colspan="2" class="section-title">🚚 Distribución · ${_lug.length} ${_lug.length===1?"lugar":"lugares"}</td></tr>`;
        _lug.forEach((l,i)=>{h+=`<tr><td style="width:26px;text-align:center;font-weight:800">${i+1}</td><td style="font-size:11px;line-height:1.4">${esc(l)}</td></tr>`;});
        h+=`</table>`;
      }
    }

    // ═══ DATOS ADMINISTRATIVOS (solo versión completa) ═══
    if(!isProd){
      // v10.52.0 — badge de estado de pago (solo si tiene folio asignado)
      // v10.53.1 M1 — esc() en payment_method (display bug si contiene <>&)
      let payBadge="";
      if(o.invoice_folio){
        if(o.payment_status==="paid") payBadge=`<span class="pay-badge pay-paid">✓ Pagada${o.payment_method?" · "+esc(o.payment_method):""}</span>`;
        else if(o.payment_status==="partial") payBadge=`<span class="pay-badge pay-partial">⚠ Parcial${o.payment_amount?" · $"+Number(o.payment_amount).toLocaleString("es-MX",{minimumFractionDigits:2,maximumFractionDigits:2}):""}</span>`;
        else payBadge=`<span class="pay-badge pay-unpaid">⏳ Por cobrar</span>`;
      }
      h+=`<table style="margin-top:-1px"><tr><td colspan="4" class="section-title">Datos Administrativos</td></tr>
      <tr><td style="width:40%"><div class="field-lbl">Facturar a</div><div class="field-val">${esc(o.client_company||o.client||"")}</div></td>
      <td style="width:25%"><div class="field-lbl">R.F.C.</div><div class="field-val">${esc(o.client_rfc||"")}</div></td>
      <td style="width:20%"><div class="field-lbl">Agente / Vendedor</div><div class="field-val">${esc(o.agent||"")}</div></td>
      <td style="width:15%"><div class="field-lbl">Precio</div><div class="field-val" style="font-weight:800;font-size:14px">${(isMaq?o.maq_price:o.price)?fmt(isMaq?o.maq_price:o.price):""}</div></td></tr>
      <tr><td colspan="2"><div class="field-lbl">Email</div><div class="field-val">${esc(o.client_email||"")}</div></td>
      <td><div class="field-lbl">Cotización</div><div class="field-val"></div></td>
      <td><div class="field-lbl">Estado de Pago</div><div class="field-val">${payBadge||"—"}</div></td></tr>
      </table>`;
    } else {
      // Production copy: only agent, no price/RFC/email
      h+=`<table style="margin-top:-1px"><tr><td colspan="2" class="section-title">Información Adicional</td></tr>
      <tr><td style="width:50%"><div class="field-lbl">Agente / Vendedor</div><div class="field-val">${esc(o.agent||"")}</div></td>
      <td style="width:50%"><div class="field-lbl">Tipo de Orden</div><div class="field-val">${isMaq?"Maquila":"Producción Interna"}</div></td>
      </tr></table>`;
    }

    // ═══ FIRMAS ═══
    h+=`<div class="sig-row">
      <div class="sig-box">Diseño</div>
      <div class="sig-box">Preprensa</div>
      <div class="sig-box">Producción</div>
      <div class="sig-box">Calidad</div>
    </div>`;

    // v10.53.0 — Footer con versión, hash de contenido, autor y timestamp.
    // v10.53.2 — etiqueta clara "SIN REGISTRO" + warning si register_print falló.
    h+=`<div class="print-footer">
      <div>
        <strong>${pvVersionLabel}</strong>${isReprint?' <span class="pv-reprint-tag">· Reimpreso</span>':''}${pvFailed?' <span class="pv-reprint-tag" style="color:#a16207">· ⚠️ NO se incrementó (red caída o permiso)</span>':''} · Imp. ${esc(pvWho)} · ${pvWhenStr}
      </div>
      <div>
        Hash contenido: <span class="pv-hash">${pvHash}</span>
      </div>
    </div>`;

    h+=`</div></body></html>`;
    // v10.58.59 — sin auto-print: el usuario presiona "🖨️ Imprimir ahora" en la barra,
    // que es cuando se registra la versión (evita conteos por misclick).
    w.document.write(h);w.document.close();w.focus();
    } finally {
      // v10.53.1 C1 — siempre liberar el botón, incluso si el HTML build crashea o popup blocker
      if(mountedRef.current) setPrinting(false);
    }
  };

  // Roles that always get production version
  const isFloor=role==="produccion"||role==="preprensa"||role==="german";
  // Roles that can choose
  const canChoose=isSec(role)||role==="admin";

  // v10.53.0 — info de versión actual (para mostrar en el modal de print)
  const wasPrinted=(o.print_version||0)>0;
  const lastPrintWhen=o.last_printed_at?new Date(o.last_printed_at):null;
  const lastPrintStr=lastPrintWhen?(lastPrintWhen.getDate()+"-"+months[lastPrintWhen.getMonth()].slice(0,3).toLowerCase()+" "+String(lastPrintWhen.getHours()).padStart(2,"0")+":"+String(lastPrintWhen.getMinutes()).padStart(2,"0")):"";

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}>
    <div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:420,width:"90%",maxHeight:"90vh",overflowY:"auto",textAlign:"center"}}>
      <div style={{fontSize:28,fontWeight:800,marginBottom:4}}>{o.production_number||o.id}</div>
      <div style={{fontSize:12,color:C.t2,marginBottom:4}}>{o.client} · {o.product_type}</div>
      {isMaq&&<div style={{fontSize:10,color:C.maq,fontWeight:600,marginBottom:4}}><TruckIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Orden Maquila{o.maq_provider?" · "+o.maq_provider:""}</div>}

      {/* v10.53.0 — info de versión */}
      {o.needs_reprint && (
        <div style={{margin:"8px 0",padding:"8px 12px",background:"#fee2e2",border:"1.5px solid #dc2626",borderRadius:10,fontSize:11,color:"#991b1b",fontWeight:700,lineHeight:1.4}}>
          <WarningIcon size={12} weight="fill" style={{verticalAlign:"-2px",marginRight:3}}/>EDITADA DESPUÉS DE IMPRIMIR<br/>
          <span style={{fontWeight:500,fontSize:10}}>La copia física en planta está obsoleta. Reimprime y reemplaza.</span>
        </div>
      )}
      {wasPrinted && !o.needs_reprint && (
        <div style={{margin:"6px 0",padding:"4px 10px",background:"#dcfce7",border:"1px solid "+C.sal+"40",borderRadius:8,fontSize:10,color:"#15803d",lineHeight:1.4}}>
          <CheckIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Última impresión: v{o.print_version} · {lastPrintStr} · {o.last_printed_by}
        </div>
      )}
      {/* v10.58.63: el hint refleja versión-por-contenido — sin cambios reimprime la MISMA
          versión (no "será vN+1" engañoso); editada sí sube. */}
      {canChoose&&<div style={{fontSize:10,color:C.t3,marginBottom:12}}>Elige la versión a imprimir{wasPrinted&&(o.needs_reprint?" (cambió desde la última → será v"+((o.print_version||0)+1)+")":" (sin cambios → se reimprime v"+(o.print_version||0)+")")}</div>}
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {canChoose&&<button onClick={()=>printIt("full")} disabled={printing} style={{...bt(printing?"#9ca3af":C.fac),width:"100%",justifyContent:"center",padding:"12px 18px",borderRadius:12,cursor:printing?"wait":"pointer"}}>{printing?<><HourglassIcon size={14} weight="bold"/>Registrando...</>:<><PrinterIcon size={14} weight="bold"/>Imprimir — Administrativa (Completa)</>}<span style={{fontSize:10,fontWeight:400,opacity:.8}}>(con precio y contactos)</span></button>}
        {canChoose&&<button onClick={()=>printIt("production")} disabled={printing} style={{...bt(printing?"#9ca3af":C.ac),width:"100%",justifyContent:"center",padding:"12px 18px",borderRadius:12,cursor:printing?"wait":"pointer"}}>{printing?<><HourglassIcon size={14} weight="bold"/>Registrando...</>:<><FactoryIcon size={14} weight="bold"/>Imprimir — Copia Producción</>}<span style={{fontSize:10,fontWeight:400,opacity:.8}}>(sin precio ni datos fiscales)</span></button>}
        {isFloor&&<button onClick={()=>printIt("production")} disabled={printing} style={{...bt(printing?"#9ca3af":C.ac),width:"100%",justifyContent:"center",padding:"12px 18px",borderRadius:12,cursor:printing?"wait":"pointer"}}>{printing?<><HourglassIcon size={14} weight="bold"/>Registrando...</>:<><PrinterIcon size={14} weight="bold"/>Imprimir Orden</>}</button>}
        <button onClick={onClose} disabled={printing} style={{...bt(C.sf,C.t2),width:"100%",justifyContent:"center",border:"0.5px solid "+C.bd}}>Cerrar</button>
      </div>
    </div>
  </div>;
}
function DetailModal({order:o,onClose,onPrint,role,userLogin,onAction}) {
  useEscClose(onClose);
  // v10.72.42 — /impeccable: foco al abrir + restaurar al cerrar (a11y de modal; antes el foco quedaba huérfano).
  const dialogRef=useRef(null);const prevFocusRef=useRef(null);
  useEffect(()=>{prevFocusRef.current=document.activeElement;const t=requestAnimationFrame(()=>{try{dialogRef.current&&dialogRef.current.focus()}catch{}});return ()=>{cancelAnimationFrame(t);try{prevFocusRef.current&&prevFocusRef.current.focus&&prevFocusRef.current.focus()}catch{}}},[]);
  const hp=role==="produccion"||role==="preprensa"||role==="german";const isMaq=o.order_type==="maquila";const st=SM[o.stage];
  // v10.58.23: vendedor también es owner si es el agent (caso Lupita captura por él)
  const vOwns=role!=="vendedor"||!o.created_by||o.created_by===userLogin||isVendedorOwnerByAgent(role,userLogin,o);
  const [showDeletePrompt,setShowDeletePrompt]=useState(false);
  const [deleting,setDeleting]=useState(false);
  const deleteFile=async()=>{
    // v10.54.10 — defensa en profundidad: aunque el prompt solo se muestra a
    // preprensa/german/admin, validar también aquí por si llegan por otro path.
    if(!canExecuteAction("delete_file",o,role,userLogin)){return}
    setDeleting(true);
    try{const path=o.file_url.split("/order-files/")[1];if(path)await supabase.storage.from("order-files").remove([decodeURIComponent(path)]);await supabase.from("orders").update({file_url:null,file_name:null}).eq("id",o.id)}catch{}
    setDeleting(false);setShowDeletePrompt(false);
  };
  // v10.72.42 — /impeccable: filas semánticas (<dl>/<dt>/<dd>) para que el lector de pantalla asocie label↔valor. margin:0 porque la app va sin preflight.
  const Row=({l,v})=>v&&v!=="—"?<dl style={{display:"flex",padding:"7px 0",borderBottom:"0.5px solid "+C.bd,margin:0}}><dt style={{width:130,fontSize:10,fontWeight:600,color:C.t2,textTransform:"uppercase",flexShrink:0}}>{l}</dt><dd style={{flex:1,fontSize:13,color:C.tx,margin:0}}>{v}</dd></dl>:null;
  const printIt=()=>{onPrint(o);onClose()};

  // 🆕 v10.9.0 — Lógica de botones fiscales
  const isFinal=o.stage.includes("delivered")||o.stage.includes("cancelled")||o.stage==="web_pending"||o.stage==="web_rejected";
  const canPreInvoice=(role==="karla"||role==="admin")&&!o.invoice_folio&&!o.return_covered_by_folio&&!isFinal&&o.stage!=="salidas"&&o.stage!=="maq_received";
  const canCancelWithNC=role==="admin"&&o.invoice_folio&&!o.stage.includes("cancelled");
  const dispatch=(action)=>{onClose();if(onAction)onAction(o.id,action)};
  // v10.72.14 — mismo gate de ownership/etapa que OCard (L8525) para mostrar los botones de flujo en el modal.
  const _agentMatch=isVendedorOwnerByAgent(role,userLogin,o);
  const _secOwns=role==="secretaria"||!isSec(role)||!o.created_by||o.created_by===userLogin||_agentMatch;
  const canActFlow=_secOwns&&(st?.who===role||(st?.who==="secretaria"&&isSec(role))||(st?.who==="both"&&(role==="produccion"||role==="preprensa"))||role==="admin"||(o.stage==="proof_client"&&isSec(role)));
  // v10.73.27 — gate ESPECÍFICO para "Quitar espera": espeja isResp de la card (secretaria estricta, NO isSec que incluye vendedor) para no sobre-otorgar unsnooze de maquila a un vendedor
  const canUnsnooze=_secOwns&&(st?.who===role||(st?.who==="secretaria"&&role==="secretaria")||(st?.who==="both"&&(role==="produccion"||role==="preprensa"))||role==="admin"||(o.stage==="proof_client"&&role==="secretaria"));
  // cierra el modal y despacha (mismo patrón que dispatch, pero forwardea el 3er arg de advance)
  const flowDispatch=(id,action,arg)=>{onClose();if(onAction)onAction(id,action,arg)};
  // v10.72.28 — botón Editar TAMBIÉN en el modal para el DUEÑO (no solo admin). Genaro abría el detalle de su
  // maquila y no hallaba cómo capturar el costo: el botón "Editar Maquila" vivía solo en la card del tablero,
  // y aquí el costo salía como fila de solo-lectura. Mismos gates que OCard (maquila: isSec+owner; interna:
  // secretaria en draft / vendedor pre-producción). El handler update ya bloquea precios al cliente.
  const _ownEdit=role==="secretaria"||!o.created_by||o.created_by===userLogin||_agentMatch;
  const _canEditOwner=(isMaq&&isSec(role)&&_ownEdit&&!o.stage.includes("delivered")&&!o.stage.includes("cancelled")&&canEditWebOrder(o,role))
    ||(!isMaq&&isSec(role)&&_ownEdit&&o.stage==="draft"&&!(o.validated_by_production&&o.validated_by_preprensa)&&canEditWebOrder(o,role))
    ||(!isMaq&&role==="vendedor"&&canVendedorEditPreProd(role,userLogin,o)&&o.stage!=="draft");

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:998}} onClick={onClose}>
    <div ref={dialogRef} tabIndex={-1} role="dialog" aria-modal="true" aria-label={"Detalle de orden "+(o.production_number||o.id)} style={{background:C.bg,borderRadius:20,padding:24,maxWidth:600,width:"94%",maxHeight:"85vh",overflowY:"auto",outline:"none"}} onClick={e=>e.stopPropagation()}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
        <div>
          {o.cart_folio?<div style={{display:"flex",alignItems:"center",gap:6,fontSize:22,fontWeight:800,color:C.cart,letterSpacing:1,lineHeight:1.1}}><ShoppingCartIcon size={20} weight="bold"/>{o.cart_folio}</div>:null}
          {o.web_folio?<div style={{fontSize:12,fontWeight:700,color:C.t2,letterSpacing:0.5,marginTop:2}}>{o.web_folio}</div>:null}
          {o.invoice_folio?<div style={{fontSize:16,fontWeight:800,color:o.invoice_type==="factura"?C.fac:C.live,letterSpacing:0.5,marginTop:2}}>{o.invoice_pre_assigned?<LightningIcon size={13} weight="fill" color={C.amb} style={{verticalAlign:"-2px",marginRight:2}}/>:null}{o.invoice_type==="factura"?<FileTextIcon size={14} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>:<ReceiptIcon size={14} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>}{o.invoice_folio}</div>:null}
          <div style={{fontSize:(o.cart_folio||o.web_folio)?10:9,color:C.t3,marginTop:(o.cart_folio||o.web_folio)?2:0}}>{o.id}</div>
          <div style={{fontSize:20,fontWeight:800}}>{o.production_number||o.client}</div>
          <div style={{display:"flex",gap:4,marginTop:4,flexWrap:"wrap"}}>
            <Badge color={st?.c||C.t3}><StageLbl stage={o.stage} size={10}/></Badge>
            {o.source==="web"&&<Badge color={C.cart} icon={<GlobeIcon size={11} weight="bold"/>}>Web{o.web_order_ref?" · "+o.web_order_ref:""}</Badge>}
            {o.priority!=="normal"&&PM[o.priority]&&<Badge color={PM[o.priority].c}><PrioLbl priority={o.priority}/></Badge>}
            {o.has_post_invoice_edits&&<Badge tone="warn" title="Esta orden fue editada después de tener folio fiscal asignado" icon={<WarningIcon size={11} weight="fill"/>}>Editada post-factura</Badge>}
          </div>
        </div>
        <button onClick={onClose} aria-label="Cerrar" title="Cerrar" style={{background:"none",border:"none",cursor:"pointer",color:C.t3,padding:8,display:"inline-flex",alignItems:"center",justifyContent:"center",minWidth:40,minHeight:40}}><XIcon size={20} weight="bold"/></button>
      </div>
      {o.sin_empaque_sygma&&<div style={{display:"flex",alignItems:"center",gap:8,margin:"0 0 12px",padding:"9px 12px",background:C.dn+"10",border:"1.5px solid "+C.dn+"45",borderRadius:10}}><PackageIcon size={17} weight="bold" color={C.dn} style={{flexShrink:0}}/><div style={{fontSize:11.5,fontWeight:700,color:C.dn,lineHeight:1.35}}>Empaque SIN logo de SYGMA · trabajo white-label (imprenta externa). La orden impresa va sin logo.</div></div>}
      {(()=>{const imgs=[o.image_url,o.image_url_2,!o.image_url&&!o.image_url_2?o.image:null,!o.image_url&&!o.image_url_2&&!o.image&&o.file_url&&/\.(jpe?g|png|gif|webp)$/i.test(o.file_name||"")?o.file_url:null].filter(Boolean);if(imgs.length===0)return null;return <div style={{display:"grid",gridTemplateColumns:imgs.length>1?"1fr 1fr":"1fr",gap:8,marginBottom:12}}>{imgs.map((src,i)=><img key={i} src={src} alt={"Imagen "+(i+1)+" — "+(o.product_type||o.product||o.id)} onClick={()=>window.open(src,"_blank")} title="Click para ampliar" style={{width:"100%",maxHeight:280,objectFit:"contain",borderRadius:12,background:C.sf,cursor:"pointer"}}/>)}</div>})()}
      {o.plate_status&&<div style={{marginBottom:10}}><Badge color={o.plate_status==="existing"?C.live:C.ctp} strong icon={o.plate_status==="existing"?<ArrowsClockwiseIcon size={11} weight="bold"/>:<PlusIcon size={11} weight="bold"/>}>{o.plate_status==="existing"?"Placa ya existe (auto-salta CTP)":"Nueva placa CTP requerida"}</Badge></div>}
      <div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginBottom:4}}>Cliente</div>
      <Row l="Nombre" v={o.client}/>
      {o.client_id&&<ClientAliasManager clientId={o.client_id} role={role} userLogin={userLogin}/>}
      {!hp&&vOwns&&<><Row l="Contacto" v={o.client_agent}/><Row l="Email" v={o.client_email}/><Row l="Teléfono" v={o.client_phone?(o.client_lada||"+52")+" "+o.client_phone:null}/><Row l="RFC" v={o.client_rfc}/></>}
      <div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}>Producto</div>
      <Row l="Descripción" v={o.product}/><Row l="Tipo" v={o.product_type}/><Row l="Cantidad" v={o.quantity?Number(o.quantity).toLocaleString()+" pzas":null}/><Row l="Creada" v={o.created_at?fDT(o.created_at)+(o.created_by?" por "+(o.created_by==="secretaria"?"Lupita":o.created_by):""):null}/><Row l="Entrega" v={o.due_date?fD(o.due_date)+(o.delivery_calculated_at?" ⏱️ auto":""):null}/>
      {!isMaq&&(o.paper_type||o.ink_front||o.width_cm||o.standard_size||o.finishes)&&<><div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}>Especificaciones</div><Row l="Papel" v={o.paper_type}/><Row l="Gramaje" v={o.paper_grammage?o.paper_grammage+" grs":null}/><Row l="Medidas" v={o.standard_size?ssLabel(o.standard_size):(o.width_cm?o.width_cm+"×"+o.height_cm+" cm":null)}/><Row l="Tintas Frente" v={o.ink_front}/><Row l="Tintas Vuelta" v={o.ink_back}/>{Array.isArray(o.pantone_front)&&o.pantone_front.length>0&&<Row l="Pantones Frente" v={<PantoneChips codes={o.pantone_front}/>}/>}{Array.isArray(o.pantone_back)&&o.pantone_back.length>0&&<Row l="Pantones Vuelta" v={<PantoneChips codes={o.pantone_back}/>}/>}<Row l="Acabados" v={o.finishes}/></>}
      {o.agent&&<Row l={<span style={{display:"inline-flex",alignItems:"center",gap:4}}><UserIcon size={11} weight="bold"/>Vendedor</span>} v={o.agent}/>}
      {!hp&&vOwns&&!isMaq&&o.price&&<><div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}>Precio</div><Row l="Precio MXN" v={fmt(o.price)}/></>}
      {!hp&&vOwns&&isMaq&&<><div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}>Maquila</div><Row l="Proveedor" v={o.maq_provider}/><Row l="Costo" v={o.maq_cost?fmt(o.maq_cost):null}/><Row l="Precio" v={o.maq_price?fmt(o.maq_price):null}/></>}
      {vOwns&&o.maquila_provider&&<><div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",display:"flex",alignItems:"center",gap:6,marginTop:12,marginBottom:4}}><TruckIcon size={12} weight="bold" color={C.maq}/>Proveedor Maquila</div><Row l="Proveedor" v={o.maquila_provider}/>{o.maquila_phone&&<Row l={<span style={{display:"inline-flex",alignItems:"center",gap:4}}><WhatsappLogoIcon size={11} weight="bold"/>Teléfono</span>} v={o.maquila_phone}/>}{o.maquila_email&&<Row l={<span style={{display:"inline-flex",alignItems:"center",gap:4}}><EnvelopeIcon size={11} weight="bold"/>Email</span>} v={o.maquila_email}/>}</>}

      {/* 🆕 v10.9.0 — Sección INFO FISCAL */}
      {o.grouped_invoice_folio&&!o.invoice_folio&&!hp&&vOwns&&<Row l="Facturada agrupada en" v={<span style={{color:C.fac,fontWeight:700,fontFamily:"'Geist Mono',monospace"}}><LinkIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>{o.grouped_invoice_folio}</span>}/>}
      {(o.invoice_folio||o.cancellation_reason)&&!hp&&vOwns&&<>
        <div style={{display:"flex",alignItems:"center",gap:6,fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}><FilesIcon size={12} weight="bold" color={o.invoice_type==="factura"?C.fac:C.live}/>Info Fiscal</div>
        {o.invoice_folio&&<>
          <Row l="Folio" v={<>{o.invoice_pre_assigned?<LightningIcon size={11} weight="fill" color={C.amb} style={{verticalAlign:"-1px",marginRight:3}}/>:null}{o.invoice_folio}{o.invoice_pre_assigned?" (anticipado)":""}</>}/>
          <Row l="Tipo" v={o.invoice_type==="factura"?"Factura":(o.invoice_type==="remision"?"Remisión":null)}/>
          <Row l="Asignado por" v={o.invoiced_by}/>
          <Row l="Fecha asignación" v={o.invoiced_at?fDT(o.invoiced_at):null}/>
          {o.invoice_reason&&<Row l="Razón anticipo" v={o.invoice_reason}/>}
          {o.payment_status&&<Row l="Pago" v={o.payment_status==="paid"?<Badge color={C.ok} icon={<CheckCircleIcon size={11} weight="fill"/>}>{"Pagada ("+(o.payment_method||"—")+")"}</Badge>:o.payment_status==="partial"?<Badge color={C.fac} icon={<CircleHalfIcon size={11} weight="fill"/>}>{"Parcial · $"+Number(o.payment_amount||0).toLocaleString("es-MX",{minimumFractionDigits:2})+" ("+(o.payment_method||"—")+")"}</Badge>:<Badge color={C.t2} icon={<HourglassIcon size={11} weight="bold"/>}>No pagada (en cobranza)</Badge>}/>}
        </>}
        {o.cancellation_reason&&<>
          <Row l={<span style={{display:"inline-flex",alignItems:"center",gap:4}}><XIcon size={11} weight="bold"/>Cancelación</span>} v={o.cancellation_reason}/>
          <Row l="Cancelada por" v={o.cancelled_by}/>
          <Row l="Fecha cancelación" v={o.cancelled_at?fDT(o.cancelled_at):null}/>
          <Row l="NC emitida en SAT" v={o.nc_emitted?<><CheckCircleIcon size={12} weight="fill" color={C.ok} style={{verticalAlign:"-2px",marginRight:3}}/>Sí</>:<><HourglassIcon size={12} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Pendiente</>}/>
        </>}
      </>}

      {o.file_url&&vOwns&&<div style={{marginTop:12}}><div style={{display:"flex",alignItems:"center",gap:6,fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginBottom:4}}><FolderOpenIcon size={12} weight="bold"/>Archivo de Producción</div><a href={o.file_url} target="_blank" rel="noopener" download={o.file_name} onClick={()=>{if(canExecuteAction("delete_file",o,role,userLogin))setTimeout(()=>setShowDeletePrompt(true),500)}} style={{display:"flex",alignItems:"center",gap:8,background:C.sf,borderRadius:10,padding:"10px 14px",textDecoration:"none",border:"0.5px solid "+C.bd}}><FileTextIcon size={22} weight="bold" color={C.ios} style={{flexShrink:0}}/><div style={{flex:1}}><div style={{fontSize:12,fontWeight:600,color:C.tx}}>{o.file_name||"Archivo"}</div><div style={{fontSize:10,color:C.ios,fontWeight:500}}><DownloadSimpleIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:2}}/>Click para descargar</div></div></a></div>}
      {showDeletePrompt&&<div style={{marginTop:8,background:C.wn+"08",border:"1px solid "+C.wn+"25",borderRadius:12,padding:14}}>
        <div style={{display:"flex",alignItems:"center",gap:6,fontSize:12,fontWeight:600,color:C.wn,marginBottom:4}}><FloppyDiskIcon size={13} weight="bold"/>¿Ya descargaste el archivo?</div>
        <p style={{fontSize:11,color:C.t2,margin:"0 0 10px"}}>Bórralo para liberar espacio en almacenamiento</p>
        <div style={{display:"flex",gap:6}}>
          <button onClick={()=>setShowDeletePrompt(false)} style={{...bs(C.sf,C.t2),border:"0.5px solid "+C.bd}}>No, conservar</button>
          <button onClick={deleteFile} disabled={deleting} style={bs(C.dn)}>{deleting?<><HourglassIcon size={13} weight="bold"/>Borrando...</>:<><TrashIcon size={13} weight="bold"/>Sí, borrar archivo</>}</button>
        </div>
      </div>}
      {/* 🔒 v10.12.0.4 Phase 3 — Finding #12 (extensión): campo notes oculto para vendedor en órdenes ajenas (puede contener acuerdos verbales/descuentos/info comercial sensible) */}
      {vOwns&&o.notes&&<><div style={{fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}>Notas</div><div style={{fontSize:12,color:C.tx,padding:"8px 0",lineHeight:1.5,maxHeight:160,overflowY:"auto",whiteSpace:"pre-wrap",wordBreak:"break-word"}}>{o.notes}</div></>}
      {/* 🔒 v10.12.0.4 Phase 3 — Finding #12: quick_notes ocultos para vendedor en órdenes ajenas (mismo gate vOwns que precios/contactos) */}
      {vOwns&&(o.notes_log||[]).length>0&&<><div style={{display:"flex",alignItems:"center",gap:6,fontSize:10,fontWeight:600,color:C.ac,textTransform:"uppercase",marginTop:12,marginBottom:4}}><ChatCircleIcon size={12} weight="bold" color={C.ios}/>Notas Rápidas ({o.notes_log.length})</div><div style={{maxHeight:120,overflowY:"auto"}}>{(o.notes_log||[]).map((n,i)=>{return <div key={i} style={{padding:"4px 0",borderBottom:i<o.notes_log.length-1?"0.5px solid "+C.bd:"none"}}><span style={{fontSize:10,fontWeight:600,color:AUTHOR_COLOR[n.by]||C.t3}}>{AUTHOR_NAME[n.by]||n.by}</span> <span style={{fontSize:11}}>{n.text}</span> <span style={{fontSize:9,color:C.t3}}>{fDT(n.date)}</span></div>})}</div></>}
      {o.stage==="draft"&&<div style={{marginTop:12,padding:"8px 0",display:"flex",gap:6,fontSize:11,color:C.t2,borderTop:"0.5px solid "+C.bd}}><span style={{color:o.validated_by_production?C.ok:C.wn}}>{o.validated_by_production?<CheckCircleIcon size={11} weight="fill" style={{verticalAlign:"-2px",marginRight:3}}/>:<HourglassIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>}Producción</span><span style={{color:o.validated_by_preprensa?C.ok:C.wn}}>{o.validated_by_preprensa?<CheckCircleIcon size={11} weight="fill" style={{verticalAlign:"-2px",marginRight:3}}/>:<HourglassIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>}Pre-prensa</span></div>}

      {/* v10.73.19 (F2) — Historial de tiempos por etapa (cuánto en cada una, quién la movió, regresiones). */}
      {vOwns&&o.timeline?.length>0&&<div style={{marginTop:12,paddingTop:12,borderTop:"0.5px solid "+C.bd}}>
        <StageFlowHistory order={o}/>
      </div>}
      {/* 🆕 v10.58.41 — Historial campo-a-campo de cambios (antes/después/quién/cuándo).
          Mismo gate vOwns que precios/notas: un vendedor no ve el historial de órdenes ajenas. */}
      {vOwns&&<div style={{marginTop:12,paddingTop:12,borderTop:"0.5px solid "+C.bd}}>
        <OrderChangeHistory orderId={o.id}/>
      </div>}

      {/* v10.72.42 — las "Acciones de flujo" se movieron a la barra sticky de abajo (acción primaria del rol siempre visible sin scroll). */}

      {/* 🆕 v10.9.0 — Botón prominente "Facturar anticipado" para Karla/Admin */}
      {canPreInvoice&&<div style={{marginTop:14,padding:14,background:C.amb+"10",border:"1.5px solid "+C.amb+"40",borderRadius:12}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
          <LightningIcon size={24} weight="fill" color={C.amb} style={{flexShrink:0}}/>
          <div style={{flex:1}}>
            <div style={{fontSize:13,fontWeight:700,color:C.amb}}>Facturar Anticipadamente</div>
            <div style={{fontSize:11,color:C.t2,marginTop:2}}>Asigna folio fiscal antes de entregar (para clientes que pagan adelantado o solicitan anticipo)</div>
          </div>
        </div>
        <button onClick={()=>dispatch("pre_invoice")} style={{...bt(C.amb),width:"100%",justifyContent:"center",fontSize:14,padding:"12px"}}><LightningIcon size={15} weight="fill"/>Asignar Folio Anticipado</button>
      </div>}

      {/* 🆕 v10.9.0 — Botón "Cancelar con NC" prominente solo para Marcelo cuando hay folio */}
      {canCancelWithNC&&<div style={{marginTop:14,padding:14,background:C.dn+"08",border:"1.5px solid "+C.dn+"30",borderRadius:12}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
          <XIcon size={24} weight="bold" color={C.dn} style={{flexShrink:0}}/>
          <div style={{flex:1}}>
            <div style={{fontSize:13,fontWeight:700,color:C.dn}}>Cancelar con Nota de Crédito</div>
            <div style={{fontSize:11,color:C.t2,marginTop:2}}>Esta orden tiene folio {o.invoice_folio} asignado. Cancelarla genera una NC pendiente.</div>
          </div>
        </div>
        <button onClick={()=>dispatch("cancel_with_nc")} style={{...bt(C.dn),width:"100%",justifyContent:"center",fontSize:13,padding:"10px"}}><XIcon size={14} weight="bold"/>Cancelar Orden (con NC)</button>
      </div>}

      {/* v10.72.34/42 — barra de acciones STICKY al fondo. v10.72.42: las acciones de flujo del rol (avanzar/validar)
          viven aquí arriba (fila propia, siempre visibles) en vez de enterradas a media altura. marginLeft/Right
          negativos para abarcar todo el ancho bajo el padding; borde+sombra arriba para flotar sobre el scroll. */}
      <div style={{position:"sticky",bottom:0,marginTop:16,marginLeft:-24,marginRight:-24,padding:"12px 24px 0",background:C.bg,borderTop:"0.5px solid "+C.bd,boxShadow:"0 -6px 14px -10px rgba(26,26,31,.18)",zIndex:2}}>
        {canActFlow&&!snoozeActive(o)&&<div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap",marginBottom:10}}><span style={{fontSize:9.5,fontWeight:700,color:C.t3,textTransform:"uppercase",letterSpacing:".05em",display:"inline-flex",alignItems:"center",gap:4,marginRight:2}}><FlowArrowIcon size={11} weight="bold"/>Flujo</span><StageFlowButtons o={o} role={role} onAction={flowDispatch}/></div>}
        {/* v10.73.26 (#4) — orden En espera: banner + "Quitar espera" en el DetailModal (antes no había forma de reactivar desde el modal) */}
        {snoozeActive(o)&&<div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap",marginBottom:10,padding:"8px 12px",background:C.t3+"14",borderRadius:10,fontSize:11,color:C.t2}}><BellSlashIcon size={13} weight="bold" style={{flexShrink:0}}/><span style={{flex:1,minWidth:120}}>En espera: <b style={{color:C.tx}}>{o.snooze_reason}</b>{o.snoozed_by?" — "+(AUTHOR_NAME[o.snoozed_by]||o.snoozed_by):""}{o.snooze_until?" · hasta "+fD(o.snooze_until):""}</span>{canUnsnooze&&<button onClick={()=>dispatch("unsnooze")} style={{...bs(C.ac+"15",C.ac),border:"1px solid "+C.ac+"40",flexShrink:0}}><BellRingingIcon size={12} weight="bold"/>Quitar espera</button>}</div>}
        <div style={{display:"flex",gap:8}}>
          <button onClick={onClose} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cerrar</button>
          {role==="admin"&&!o.stage.includes("cancelled")&&(o.invoice_folio||!o.stage.includes("delivered")||o.created_by==="import-historico")&&<button onClick={()=>dispatch("edit")} style={{...bt(C.ios),flex:1,justifyContent:"center"}}><NotePencilIcon size={14} weight="bold"/>Editar</button>}
          {role!=="admin"&&_canEditOwner&&<button onClick={()=>dispatch("edit")} style={{...bt(isMaq?C.maq:C.fac),flex:1,justifyContent:"center"}}><NotePencilIcon size={14} weight="bold"/>{isMaq?"Editar Maquila":"Editar"}</button>}
          {/* v10.72.58 — folio histórico desde el detalle (las cards del Archivo son compactas, sin fila de botones) */}
          {(role==="admin"||role==="karla")&&o.created_by==="import-historico"&&o.stage.includes("delivered")&&!o.invoice_folio&&!o.grouped_invoice_folio&&!o.has_splits&&!o.has_matrix_lines&&<button onClick={()=>dispatch("apply_historic_folio")} style={{...bt(C.fac),flex:1,justifyContent:"center"}}><ReceiptIcon size={14} weight="bold"/>Aplicar folio</button>}
          {vOwns&&<button onClick={printIt} style={{...bt(C.ac),flex:1,justifyContent:"center"}}><PrinterIcon size={14} weight="bold"/>Imprimir</button>}
        </div>
      </div>
    </div>
  </div>;
}
function ClientHistory({clientName,orders,onClose,role,userLogin}) {
  useEscClose(onClose);
  const allCo=orders.filter(o=>o.client===clientName).sort((a,b)=>new Date(b.created_at)-new Date(a.created_at));
  const co=role==="vendedor"?allCo.filter(o=>!o.created_by||o.created_by===userLogin):allCo;
  // 🔧 scan jul-2026 #16/#17: excluir canceladas (no inflan el valor del cliente) + atribuir maq_price en maquila (canónico).
  const total=co.filter(o=>!String(o.stage||"").includes("cancelled")).reduce((s,o)=>s+(o.order_type==="maquila"?(Number(o.maq_price)||0):(Number(o.price)||0)),0);
  const byType={};co.forEach(o=>{const k=o.product_type||"?";byType[k]=(byType[k]||0)+1}); // v10.34.2 fix #7 — fallback consistente con línea 2391
  const hp=role==="produccion"||role==="preprensa"||role==="german";
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}} onClick={onClose}><div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:480,width:"90%",maxHeight:"80vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}><h3 style={{fontSize:18,fontWeight:800,letterSpacing:"-0.01em",margin:"0 0 4px",display:"flex",alignItems:"center",gap:6}}><UserIcon size={18} weight="bold"/>{clientName}</h3><p style={{fontSize:12,color:C.t2,margin:"0 0 14px"}}>{co.length} orden{co.length!==1?"es":""}{!hp?" · Total: "+fmt(total):""}</p>{Object.keys(byType).length>0&&<div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:12}}>{Object.entries(byType).sort((a,b)=>b[1]-a[1]).map(([t,c])=><span key={t} style={{background:C.sf,padding:"4px 10px",borderRadius:8,fontSize:11}}>{t} <strong>{c}</strong></span>)}</div>}{co.map(o=><div key={o.id} style={{padding:"8px 0",borderBottom:"0.5px solid "+C.bd,display:"flex",justifyContent:"space-between"}}><div>{o.cart_folio&&<div style={{fontSize:11,fontWeight:700,color:C.cart,letterSpacing:0.3,marginBottom:1,display:"flex",alignItems:"center",gap:4}}><ShoppingCartIcon size={11} weight="bold"/>{o.cart_folio}</div>}{o.web_folio&&<div style={{fontSize:10,fontWeight:600,color:C.t2,marginBottom:1}}>{o.web_folio}</div>}{o.invoice_folio&&<div style={{fontSize:11,fontWeight:700,color:o.invoice_type==="factura"?C.fac:C.live,marginBottom:1,display:"flex",alignItems:"center",gap:4}}>{o.invoice_type==="factura"?<FileTextIcon size={11} weight="bold"/>:<ClipboardTextIcon size={11} weight="bold"/>}{o.invoice_folio}</div>}<div style={{fontSize:9,color:C.t3}}>{o.id} · {fD(o.created_at)}</div><div style={{fontSize:12}}>{o.product||o.product_type}{o.quantity?" · "+Number(o.quantity).toLocaleString():""}</div><span style={{background:(SM[o.stage]?.c||C.t3)+"15",color:SM[o.stage]?.c,padding:"1px 6px",borderRadius:6,fontSize:9,fontWeight:600,display:"inline-flex",alignItems:"center"}}><StageLbl stage={o.stage} size={9}/></span></div>{!hp&&(o.order_type==="maquila"?(Number(o.maq_price)||0):(Number(o.price)||0))>0&&<div style={{fontSize:14,fontWeight:700,opacity:String(o.stage||"").includes("cancelled")?.4:1}} title={String(o.stage||"").includes("cancelled")?"Cancelada — no suma al total":""}>{fmt(o.order_type==="maquila"?(Number(o.maq_price)||0):(Number(o.price)||0))}</div>}</div>)}<button onClick={onClose} style={{...bt(C.sf,C.t2),width:"100%",justifyContent:"center",marginTop:14,border:"0.5px solid "+C.bd}}>Cerrar</button></div></div>;
}
function ConfirmModal({title,message,confirmLabel,confirmColor,onConfirm,onClose}) {
  useEscClose(onClose);
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div role="dialog" aria-modal="true" style={{background:C.bg,borderRadius:20,padding:28,maxWidth:380,width:"90%",textAlign:"center"}}><div style={{marginBottom:8,display:"flex",justifyContent:"center"}}><WarningIcon size={36} weight="fill" color={C.wn}/></div><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 8px"}}>{title}</h3><p style={{fontSize:13,color:C.t2,margin:"0 0 20px"}}>{message}</p><div style={{display:"flex",gap:8}}><button onClick={onClose} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>No, cancelar</button><button onClick={onConfirm} style={{...bt(confirmColor||C.ok),flex:1,justifyContent:"center"}}>{confirmLabel}</button></div></div></div>;
}
// v10.72.56 — capturar el folio fiscal REAL (Alpha) en órdenes históricas atrasadas (created_by='import-historico').
// Llama al RPC assign_historic_folio (acepta delivered solo para histórico, NO autogenera, dedup vía bridge).
// v10.73.18 — Modal "Poner en espera": razón (chips predefinidos + texto libre) + fecha opcional.
// Reemplaza el window.prompt de snoozeOrder; disponible para el responsable del área + admin.
const SNOOZE_PRESETS=[
  {kind:"client_correction",label:"Cliente enviará corrección / nuevo diseño",text:"El cliente enviará corrección o un nuevo diseño"},
  {kind:"far_due",label:"Entrega lejana — aún no entra a máquina",text:"Entrega lejana: aún no toca programar en máquina"},
  {kind:"material",label:"Esperando material / insumo",text:"Esperando material o insumo para continuar"},
  {kind:"authorization",label:"Esperando autorización del cliente",text:"Esperando autorización del cliente"},
];
// v10.73.40 — meta de los chips de filtro por MOTIVO en "En espera". __none = snooze genérico (texto libre sin preset). Etiquetas cortas + iconos ya importados.
const SNOOZE_KIND_META={material:{l:"Material",Icon:PackageIcon},authorization:{l:"Autorización",Icon:UserIcon},client_correction:{l:"Corrección",Icon:NotePencilIcon},far_due:{l:"Entrega lejana",Icon:CalendarDotsIcon},awaiting_client_invoice:{l:"Espera factura",Icon:ReceiptIcon},__none:{l:"Otro",Icon:BellSlashIcon}};
const SNOOZE_KIND_ORDER=["material","authorization","client_correction","far_due","awaiting_client_invoice","__none"];
function SnoozeModal({order,onConfirm,onClose}){
  useEscClose(onClose);
  const [kind,setKind]=useState(null);
  const [reason,setReason]=useState("");
  const [days,setDays]=useState("");
  const [saving,setSaving]=useState(false);
  // v10.73.44b — "entrega lejana" (far_due) se auto-reactiva si la entrega es ≤5 días hábiles o ya venció (v10.73.44): pausarla así
  // sería un no-op con toast de éxito engañoso. La ocultamos del modal cuando no aplica (el usuario usa otra razón real).
  // v10.73.46 (scan) — TAMBIÉN sin fecha de entrega: el auto-lift far_due depende de due_date, así que NUNCA dispararía → la orden
  // quedaría pausada indefinidamente, justo el "far_due olvidada" que v44 resolvió. Bloquear far_due también en ese caso.
  const farDueNoDate=!order?.due_date;
  const farDueSoon=!!(order?.due_date&&(isOverdue(order.due_date)||bizDaysUntil(order.due_date)<=5));
  const farDueBlocked=farDueNoDate||farDueSoon;
  const submit=async()=>{
    const r=reason.trim(); if(r.length<5)return;
    const d=parseInt(days,10);
    const until=Number.isFinite(d)&&d>0?localDayStr(new Date(Date.now()+d*86400000)):null;
    setSaving(true);
    try{ await onConfirm({reason:r,kind,until}); }finally{ setSaving(false); }
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999,padding:20}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:C.bg,borderRadius:20,padding:24,maxWidth:460,width:"100%",maxHeight:"85vh",overflowY:"auto"}}>
      <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,margin:"0 0 4px",color:C.ac}}><BellSlashIcon size={17} weight="bold"/>Poner en espera</h3>
      <p style={{fontSize:12,color:C.t2,margin:"0 0 14px",lineHeight:1.45}}>{order?.client||""} sale de la cola activa y deja de marcarse como estancada. Se reactiva sola al cambiar de etapa o al vencer la fecha.</p>
      <div style={{fontSize:11,fontWeight:700,color:C.t2,marginBottom:6}}>Razón</div>
      <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:10}}>
        {SNOOZE_PRESETS.filter(p=>!(p.kind==="far_due"&&farDueBlocked)).map(p=><button key={p.kind} onClick={()=>{setKind(p.kind);setReason(p.text);}} style={{display:"flex",alignItems:"center",gap:6,width:"100%",textAlign:"left",cursor:"pointer",fontSize:12,fontWeight:600,padding:"8px 11px",borderRadius:9,border:"1.5px solid "+(kind===p.kind?C.ac:C.bd),background:kind===p.kind?C.ac+"0e":C.bg,color:kind===p.kind?C.ac:C.tx,fontFamily:"'Geist',sans-serif"}}>{p.label}</button>)}
      </div>
      {farDueBlocked&&<div style={{fontSize:10.5,color:C.t3,margin:"-4px 0 10px",display:"flex",alignItems:"flex-start",gap:5,lineHeight:1.4}}><CalendarDotsIcon size={12} weight="bold" style={{flexShrink:0,marginTop:1}}/><span>{farDueNoDate?"\"Entrega lejana\" necesita una fecha de entrega para reactivarse sola; sin ella la orden quedaría pausada indefinidamente. Ponle fecha de entrega o usa la razón real de la pausa.":"\"Entrega lejana\" no está disponible: la entrega es ≤5 días hábiles o ya venció (se reactivaría al instante). Usa la razón real de la pausa."}</span></div>}
      <textarea value={reason} onChange={e=>setReason(e.target.value)} placeholder="Razón (mín. 5 caracteres) — edita el preset o escribe la tuya…" style={{...inp,minHeight:60,resize:"vertical",fontSize:12,marginBottom:10}}/>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
        <span style={{fontSize:11,color:C.t2,whiteSpace:"nowrap"}}>¿Por cuántos días?</span>
        <input type="number" min="1" value={days} onChange={e=>setDays(e.target.value)} placeholder="vacío = hasta que cambie de etapa" style={{...inp,fontSize:12,flex:1}}/>
      </div>
      <div style={{display:"flex",justifyContent:"flex-end",gap:8}}>
        <button onClick={onClose} disabled={saving} style={{...bt(C.sf,C.t2),fontSize:12,padding:"8px 14px",border:"0.5px solid "+C.bd}}>Cancelar</button>
        <button onClick={submit} disabled={saving||reason.trim().length<5} style={{...bt(reason.trim().length>=5?C.ac:C.bdSt),fontSize:12,padding:"8px 14px",cursor:reason.trim().length>=5&&!saving?"pointer":"default",opacity:saving?.6:1}}>{saving?"Guardando…":<><BellSlashIcon size={13} weight="bold"/>Poner en espera</>}</button>
      </div>
    </div>
  </div>;
}
function HistoricFolioModal({order,user,userLogin,onApplied,onClose,showToast}) {
  useEscClose(onClose);
  const [folio,setFolio]=useState("");
  const [busy,setBusy]=useState(false);
  const f=(folio||"").trim().toUpperCase();
  const isD=/^D-[0-9]+$/.test(f); const isR=/^R-[0-9]+$/.test(f);
  const valid=isD||isR;
  const base=order.order_type==="maquila"?Number(order.maq_price||0):Number(order.price||0);
  const total=isD?Math.round(base*1.16*100)/100:base;
  const submit=async()=>{
    if(!valid||busy||base<=0)return;
    setBusy(true);
    try{
      const {data,error}=await supabase.rpc("assign_historic_folio",{p_order_id:order.id,p_folio:f,p_user:userLogin||user});
      if(error)throw error;
      const tipo=data?.type==="factura"?"factura":"remisión";
      if(data?.result==="linked")showToast("✓ Folio "+f+" vinculado a la factura ya registrada en CobranzaFlow ("+fmt(data.linked_amount||data.amount||total)+")","info");
      else showToast("✓ Folio "+f+" aplicado — "+tipo+" creada en CobranzaFlow por "+fmt(data.amount||total));
      onApplied(order.id,{invoice_folio:f,invoice_type:data?.type,stage:["salidas","maq_received"].includes(order.stage)?(order.order_type==="maquila"?"maq_delivered":"delivered"):order.stage,delivered_at:new Date().toISOString()}); // v10.72.61 — merge optimista incluye stage (el RPC cierra a delivered al foliar desde salidas)
      onClose();
    }catch(e){showToast("❌ "+(e?.message||"No se pudo aplicar el folio"),"error")}
    finally{setBusy(false)}
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div role="dialog" aria-modal="true" style={{background:C.bg,borderRadius:20,padding:24,maxWidth:430,width:"90%",maxHeight:"90vh",overflowY:"auto"}}>
    <h3 style={{fontSize:16,fontWeight:700,margin:"0 0 4px",display:"flex",alignItems:"center",gap:6}}><ReceiptIcon size={17} weight="bold"/>Aplicar folio fiscal</h3>
    <p style={{fontSize:12,color:C.t2,margin:"0 0 14px"}}>Captura el folio <b>real</b> que ya emitió Alpha para esta orden. Si el cliente aún no la pide, no la captures todavía.</p>
    <div style={{background:C.sf,border:"1px solid "+C.bd,borderRadius:12,padding:"10px 12px",marginBottom:14,fontSize:12}}>
      <div style={{fontWeight:700,color:C.tx}}>{order.client}{order.client_company&&order.client_company!==order.client?" · "+order.client_company:""}</div>
      <div style={{color:C.t2,marginTop:2}}>{order.production_number} · {(order.product_type||"").replace("🔴 ATRASADA · ","")}</div>
      <div style={{color:C.t2,marginTop:2}}>Precio base: <b style={{color:base>0?C.tx:C.dn}}>{fmt(base)}</b>{base>0?"":<span style={{color:C.dn}}> · captura el precio primero (Editar)</span>}</div>
    </div>
    <label style={lbl}>Folio fiscal</label>
    <input style={{...inp,textTransform:"uppercase",fontWeight:700,letterSpacing:.5}} value={folio} onChange={e=>setFolio(e.target.value)} placeholder="D-5940 (factura) · R-1230 (remisión)" autoFocus onKeyDown={e=>{if(e.key==="Enter")submit()}}/>
    {f&&!valid&&<div style={{fontSize:11,color:C.dn,marginTop:6}}>Formato inválido. Usa D-#### (factura) o R-#### (remisión).</div>}
    {valid&&base>0&&<div style={{fontSize:12,color:C.t2,marginTop:8,background:C.sf,borderRadius:10,padding:"8px 12px"}}>
      Registra una <b style={{color:C.tx}}>{isD?"factura":"remisión"}</b> en CobranzaFlow por <b style={{color:C.ok}}>{fmt(total)}</b>{isD?<span style={{color:C.t3}}> (base + IVA 16%)</span>:<span style={{color:C.t3}}> (sin IVA)</span>}. Si el folio ya existe, solo se vincula (no se duplica).
    </div>}
    <div style={{display:"flex",gap:8,marginTop:18}}><button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cancelar</button><button onClick={submit} disabled={!valid||busy||base<=0} style={{...bt((valid&&base>0)?C.ok:"#9ca3af"),flex:1,justifyContent:"center",opacity:(valid&&base>0&&!busy)?1:.6,cursor:(valid&&base>0&&!busy)?"pointer":"not-allowed"}}>{busy?<><HourglassIcon size={14} weight="bold"/>Aplicando...</>:<><ReceiptIcon size={14} weight="bold"/>Aplicar folio</>}</button></div>
  </div></div>;
}
function MaqModal({onSend,onClose,providers=[]}) {
  useEscClose(onClose);
  const [p,setP]=useState("");const [ph,setPh]=useState("");const [em,setEm]=useState("");const [n,setN]=useState("");const [showAC,setShowAC]=useState(false);
  const matches=(p||"").length>=2?providers.filter(x=>x.name?.toLowerCase().includes(p.toLowerCase())).slice(0,5):[];
  const selProv=pv=>{setP(pv.name);setPh(pv.phone||"");setEm(pv.email||"");setShowAC(false)};
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:420,width:"90%",maxHeight:"90vh",overflowY:"auto"}}>
    <h3 style={{fontSize:16,fontWeight:700,margin:"0 0 14px",display:"flex",alignItems:"center",gap:6}}><TruckIcon size={17} weight="bold"/>Enviar a Maquila</h3>
    <div style={{marginBottom:10,position:"relative"}}>
      <label style={lbl}>Proveedor *</label>
      <input style={inp} value={p} onChange={e=>{setP(e.target.value);setShowAC(true)}} onFocus={()=>setShowAC(true)} onBlur={()=>setTimeout(()=>setShowAC(false),200)} placeholder="Nombre del proveedor"/>
      {showAC&&matches.length>0&&<div style={{position:"absolute",top:"100%",left:0,right:0,background:C.bg,borderRadius:10,boxShadow:C.sh3,zIndex:50,border:"0.5px solid "+C.bd,marginTop:4}}>
        <div style={{padding:"5px 12px",fontSize:10,color:C.t2,fontWeight:600,textTransform:"uppercase",borderBottom:"0.5px solid "+C.bd}}>Proveedores anteriores</div>
        {matches.map((pv,i)=><div key={i} onMouseDown={()=>selProv(pv)} style={{padding:"8px 12px",cursor:"pointer",borderBottom:i<matches.length-1?"0.5px solid "+C.bd:"none"}} onMouseEnter={e=>e.currentTarget.style.background=C.sf} onMouseLeave={e=>e.currentTarget.style.background=C.bg}>
          <div style={{fontSize:12,fontWeight:600}}>{pv.name}</div>
          <div style={{fontSize:10,color:C.t2}}>{[pv.phone,pv.email].filter(Boolean).join(" · ")||"Sin contacto"}</div>
        </div>)}
      </div>}
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
      <div><label style={lbl}><PhoneIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Teléfono</label><input style={inp} type="tel" value={ph} onChange={e=>setPh(e.target.value)} placeholder="55 1234 5678"/></div>
      <div><label style={lbl}><EnvelopeIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Email</label><input style={inp} type="email" value={em} onChange={e=>setEm(e.target.value)} placeholder="correo@ej.com"/></div>
    </div>
    <div style={{marginBottom:16}}><label style={lbl}>Notas (opcional)</label><input style={inp} value={n} onChange={e=>setN(e.target.value)} placeholder="Instrucciones..."/></div>
    <div style={{display:"flex",gap:8}}><button onClick={onClose} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cancelar</button><button onClick={()=>{if(p)onSend(p,ph,em,n)}} style={{...bt(C.maq),flex:1,justifyContent:"center"}}><TruckIcon size={14} weight="bold"/>Enviar</button></div>
  </div></div>;
}
function WasteModal({onSave,onClose}) {
  useEscClose(onClose);
  const [pl,setPl]=useState("");const [pz,setPz]=useState("");const [n,setN]=useState("");
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:400,width:"90%",maxHeight:"90vh",overflowY:"auto"}}><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 6px",display:"flex",alignItems:"center",gap:6}}><TrashIcon size={17} weight="bold"/>Registrar Merma</h3><p style={{fontSize:12,color:C.t2,margin:"0 0 14px"}}>¿Cuánto material se echó a perder?</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}><div><label style={lbl}><FileTextIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Pliegos (Impresión)</label><input style={inp} type="number" value={pl} onChange={e=>setPl(e.target.value)} placeholder="0"/></div><div><label style={lbl}><PackageIcon size={11} weight="bold" style={{verticalAlign:"-2px",marginRight:3}}/>Piezas (Acabados)</label><input style={inp} type="number" value={pz} onChange={e=>setPz(e.target.value)} placeholder="0"/></div></div><div style={{marginBottom:16}}><label style={lbl}>¿Qué pasó?</label><input style={inp} value={n} onChange={e=>setN(e.target.value)} placeholder="Motivo..."/></div><div style={{display:"flex",gap:8}}><button onClick={onClose} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cancelar</button><button onClick={()=>onSave(parseInt(pz,10)||0,parseInt(pl,10)||0,n)} style={{...bt(C.wn),flex:1,justifyContent:"center"}}>Guardar</button></div></div></div>;
}
function DevolverModal({onConfirm,onClose}) {
  useEscClose(onClose);
  const [reason,setReason]=useState("");
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:400,width:"90%",maxHeight:"90vh",overflowY:"auto"}}><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 6px",display:"flex",alignItems:"center",gap:6}}><ArrowUUpLeftIcon size={17} weight="bold"/>Devolver a Diseño</h3><p style={{fontSize:12,color:C.t2,margin:"0 0 14px"}}>Describe el fallo o motivo por el cual se regresa esta orden a Noemí (Diseño)</p><div style={{marginBottom:16}}><label style={lbl}>Motivo (obligatorio)</label><textarea style={{...inp,minHeight:80,resize:"vertical"}} value={reason} onChange={e=>setReason(e.target.value)} placeholder="Describe el problema..."/></div><div style={{display:"flex",gap:8}}><button onClick={onClose} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cancelar</button><button onClick={()=>{if(!reason.trim())return alert("Escribe el motivo");onConfirm(reason.trim())}} style={{...bt(C.dn),flex:1,justifyContent:"center"}}><ArrowUUpLeftIcon size={14} weight="bold"/>Devolver</button></div></div></div>;
}

// v10.38.0 — Modal para regresar orden a CTP (capturar razón).
// Las plates existentes se marcan como void (no se borran) — historial preservado.
function ReturnToCtpModal({order,onConfirm,onClose}) {
  useEscClose(onClose);
  const [reason,setReason]=useState("");
  // v10.54.7 — busy state previene duplicados por click múltiple
  const [busy,setBusy]=useState(false);
  const valid=!!reason.trim();
  const canSubmit=valid&&!busy;
  const submit=async()=>{
    if(!canSubmit) return;
    setBusy(true);
    try{ await onConfirm(reason.trim()); }
    finally{ setBusy(false); }
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:460,width:"90%",maxHeight:"90vh",overflowY:"auto"}}>
    <h3 style={{fontSize:16,fontWeight:700,margin:"0 0 6px",color:C.ctp,display:"flex",alignItems:"center",gap:6}}><ArrowUUpLeftIcon size={17} weight="bold"/>Regresar a CTP</h3>
    <p style={{fontSize:12,color:C.t2,margin:"0 0 12px"}}>La orden volverá a Germán para re-imprimir placas. Las placas existentes se marcarán como inválidas (se conserva el historial).</p>
    <div style={{background:C.sf,borderRadius:10,padding:12,marginBottom:14}}>
      <div style={{fontSize:13,fontWeight:700}}>{order?.client}</div>
      <div style={{fontSize:11,color:C.t2}}>{order?.product_type}{order?.quantity?" · "+Number(order.quantity).toLocaleString()+" pzas":""}</div>
      {order?.production_number&&<div style={{fontSize:10,color:C.ac,fontWeight:600,marginTop:2}}>{order.production_number}</div>}
      <div style={{fontSize:10,color:C.t3,marginTop:4}}>Stage actual: <StageLbl stage={order?.stage}/></div>
    </div>
    <div style={{marginBottom:16}}>
      <label style={lbl}>Razón del regreso (obligatorio)</label>
      <textarea
        style={{...inp,minHeight:80,resize:"vertical",border:"1.5px solid "+(reason.trim()?C.bd:"#f59e0b"+"40")}}
        value={reason}
        onChange={e=>setReason(e.target.value)}
        placeholder="ej. placa rayada, color incorrecto, archivo cambió..."
        autoFocus
        disabled={busy}
      />
    </div>
    <div style={{display:"flex",gap:8}}>
      <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,opacity:busy?.5:1,cursor:busy?"wait":"pointer"}}>Cancelar</button>
      <button onClick={submit} disabled={!canSubmit} style={{...bt(canSubmit?C.ctp:"#9ca3af"),flex:1,justifyContent:"center",opacity:canSubmit?1:.6,cursor:canSubmit?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Regresando...</>:<><ArrowUUpLeftIcon size={14} weight="bold"/>Regresar a CTP</>}</button>
    </div>
  </div></div>;
}

// v10.42.0 — Inventario Cuadra (producción a stock + venta desde stock).
// Lista client_products con stock_actual, permite ADJUST (semilla / corrección),
// venta directa desde stock (RPC sell_from_stock) y agregar producto nuevo al catálogo.
function InventoryModal({onClose, user, userLogin, clients, showToast, onOpenInvoice}) {
  useEscClose(onClose);
  const [products,setProducts]=useState([]);
  const [movements,setMovements]=useState([]);
  const [history,setHistory]=useState([]); // v10.46.0 — historial órdenes Cuadra
  const [stockClients,setStockClients]=useState([]); // v10.42.1
  const [loading,setLoading]=useState(true);
  const [tab,setTab]=useState("products"); // products | movements | history (v10.46.0)
  const [editing,setEditing]=useState(null); // {mode:"new"|"adjust"|"sell", product?}
  // v10.46.8 — filtros independientes por tab (antes era uno solo y confundía al cambiar tab)
  const [filterProducts,setFilterProducts]=useState("");
  const [filterHistory,setFilterHistory]=useState("");

  const reload=async()=>{
    setLoading(true);
    try{
      // v10.42.1 — RPC list_stock_clients evita exponer schema cobranza vía PostgREST
      // v10.46.0 — Cargar historial de órdenes Cuadra (production + sale)
      // v10.46.2 FIX — Si historial falla, avisamos al usuario en lugar de silenciar (tab quedaba vacío sin explicación).
      const [prods,movs,scsRes,hist]=await Promise.all([
        db.loadClientProducts(),
        db.loadStockMovements(null,80),
        supabase.rpc("list_stock_clients"),
        db.loadCuadraOrdersHistory(80).catch(e=>{console.warn("[InventoryModal] history:",e);showToast("⚠️ No se pudo cargar el historial Cuadra: "+e.message,"error");return null})
      ]);
      setProducts(prods);setMovements(movs);setStockClients(scsRes.data||[]);setHistory(hist||[]);
    }catch(e){console.error("[InventoryModal] load:",e);showToast("❌ Error cargando inventario: "+e.message,"error")}
    finally{setLoading(false)}
  };
  useEffect(()=>{reload()},[]);

  // v10.48.0 — para productos pooled, mostrar nombre del pool en lugar de cliente individual.
  const clientName=cid=>{const c=stockClients.find(x=>x.id===cid);return c?.name||"—"};
  const productOwner=p=>{
    if(p.stock_pool_id){
      // Buscar pool_name desde stockClients (cualquier cliente del pool tiene pool_name)
      const memberWithName=stockClients.find(x=>x.stock_pool_id===p.stock_pool_id&&x.pool_name);
      return "📦 Pool "+(memberWithName?.pool_name||"compartido");
    }
    return clientName(p.client_id);
  };
  const filtered=products.filter(p=>{
    if(!filterProducts.trim())return true;
    const q=filterProducts.toLowerCase();
    return (p.name||"").toLowerCase().includes(q)||(p.sku||"").toLowerCase().includes(q)||productOwner(p).toLowerCase().includes(q);
  });

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}>
    <div style={{background:C.bg,borderRadius:20,padding:0,maxWidth:780,width:"94%",maxHeight:"90vh",display:"flex",flexDirection:"column"}}>
      <div style={{padding:"18px 22px",borderBottom:"0.5px solid "+C.bd,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div>
          <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:17,fontWeight:800,margin:0}}><PackageIcon size={18} weight="bold"/>Inventario Cuadra</h3>
          <div style={{fontSize:11,color:C.t2,marginTop:2}}>Productos en stock · {products.length} SKUs</div>
        </div>
        <button onClick={onClose} style={{...bt(C.sf,C.t2),padding:"8px",border:"0.5px solid "+C.bd,minWidth:40,minHeight:40,justifyContent:"center"}}><XIcon size={15} weight="bold"/></button>
      </div>
      <div style={{padding:"10px 22px",borderBottom:"0.5px solid "+C.bd,display:"flex",gap:8,alignItems:"center"}}>
        {[{id:"products",ic:PackageIcon,l:"Productos"},{id:"movements",ic:ListBulletsIcon,l:"Movimientos"},{id:"history",ic:BooksIcon,l:"Historial"}].map(t=>
          <button key={t.id} onClick={()=>setTab(t.id)} style={{display:"inline-flex",alignItems:"center",gap:6,padding:"8px 14px",borderRadius:10,border:"none",cursor:"pointer",background:tab===t.id?C.emr+"15":"transparent",color:tab===t.id?C.emr:C.t2,fontWeight:700,fontSize:12,fontFamily:"'Geist',sans-serif"}}>{(()=>{const TI=t.ic;return <TI size={13} weight="bold"/>})()}{t.l}</button>
        )}
        <div style={{flex:1}}/>
        {/* v10.55.0 — Carrito de venta batch (sustituye el flujo individual sell_from_stock con folio compartido) */}
        {/* v10.58.30 BUG #2: gatear a admin/karla (alineado con backend bulk_sell_from_stock). Antes
            usaba canExecuteAction("sell_from_stock") que incluía secretaria/vendedor, pero el backend
            rechaza con 42501 → UX broken. */}
        {tab==="products"&&(user==="admin"||user==="karla")&&<button onClick={()=>setEditing({mode:"bulk_sell"})} style={{...bt(C.sal),padding:"8px 12px"}}><ShoppingCartIcon size={14} weight="bold"/>Carrito de venta</button>}
        {tab==="products"&&<button onClick={()=>setEditing({mode:"new"})} style={{...bt(C.emr),padding:"8px 12px"}}><PlusIcon size={14} weight="bold"/>Nuevo Producto</button>}
      </div>
      {loading?<SkelRows n={6}/>:
        <div style={{overflowY:"auto",padding:"14px 22px",flex:1}}>
          {tab==="products"&&<>
            <SearchInput wrapStyle={{marginBottom:10}} style={{...inp}} value={filterProducts} onChange={e=>setFilterProducts(e.target.value)} placeholder="Filtrar por nombre, SKU o cliente" aria-label="Filtrar productos del catálogo"/>
            {filtered.length===0?(products.length===0?<EmptyState icon={PackageIcon} title="Sin productos en stock" hint="Da de alta tu primer producto con Nuevo Producto, o cárgalo desde una orden Cuadra de producción." action={{label:"Nuevo Producto",icon:PlusIcon,onClick:()=>setEditing({mode:"new"})}}/>:<div style={{textAlign:"center",padding:30,color:C.t2,fontSize:12}}>Sin coincidencias</div>):
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {filtered.map(p=>
                  <div key={p.id} style={{padding:"12px 14px",borderRadius:12,background:C.sf,border:"0.5px solid "+C.bd}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"start",gap:10}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:13,fontWeight:700,overflow:"hidden",textOverflow:"ellipsis"}}>{p.name}</div>
                        <div style={{fontSize:10,color:p.stock_pool_id?C.emr:C.t2,marginTop:2,fontWeight:p.stock_pool_id?600:400}}>{productOwner(p)}{p.sku?" · "+p.sku:""}{p.unit_price?" · $"+Number(p.unit_price).toLocaleString():""}</div>
                      </div>
                      <div style={{textAlign:"right"}}>
                        <div style={{fontSize:18,fontWeight:800,color:p.stock_actual>0?C.emr:C.dn}}>{p.stock_actual}</div>
                        <div style={{fontSize:9,color:C.t2,textTransform:"uppercase"}}>en stock</div>
                        {kgEquiv(p.stock_actual,p.specs)&&<div style={{fontSize:10,color:C.emr,fontWeight:700,marginTop:1}}>≈{kgEquiv(p.stock_actual,p.specs)}</div>}
                      </div>
                    </div>
                    <div style={{display:"flex",gap:6,marginTop:10}}>
                      {/* v10.54.9 — botones gated por role. Gerardo (produccion) puede load_stock pero NO ajustar/vender/eliminar */}
                      {/* v10.55.0 — "🛒 Vender" individual eliminado: ahora todo va por el Carrito de venta (header) con folio compartido */}
                      {canExecuteAction("adjust_stock",null,user,userLogin)&&<button onClick={()=>setEditing({mode:"adjust",product:p})} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,padding:"6px 10px",fontSize:11}}><ChartBarIcon size={12} weight="bold"/>Ajustar</button>}
                      {/* v10.46.0 — Eliminar producto vacío (stock=0) creado por error */}
                      {p.stock_actual===0&&canExecuteAction("delete_client_product",null,user,userLogin)&&<button onClick={async()=>{
                        if(!confirm("¿Eliminar producto \""+p.name+"\" del catálogo?\n\nSolo se permite porque stock=0. Esta acción no se puede deshacer."))return;
                        try{await db.deleteClientProduct(p.id);showToast("🗑️ Producto eliminado");await reload()}
                        catch(e){showToast("❌ No se pudo eliminar: "+e.message,"error")}
                      }} title="Eliminar producto (solo si stock=0)" style={{...bt(C.dn+"15",C.dn),justifyContent:"center",border:"0.5px solid "+C.dn+"40",padding:"6px 10px",fontSize:11}}><TrashIcon size={13} weight="bold"/></button>}
                    </div>
                  </div>
                )}
              </div>
            }
          </>}
          {tab==="movements"&&(movements.length===0?<EmptyState icon={ListBulletsIcon} title="Sin movimientos todavía" hint="Aquí verás cada entrada y salida de stock cuando cargues producción o registres una venta del catálogo."/>:
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {movements.map(m=>{
                const prod=products.find(p=>p.id===m.client_product_id);
                const color=m.kind==="PRODUCED"?C.emr:m.kind==="SOLD"?C.sal:"#f59e0b";
                const MIcon=m.kind==="PRODUCED"?DownloadSimpleIcon:m.kind==="SOLD"?ExportIcon:ChartBarIcon;
                return <div key={m.id} style={{padding:"10px 12px",borderRadius:10,background:C.sf,border:"0.5px solid "+C.bd,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",alignItems:"center",gap:5,fontSize:12,fontWeight:700,color}}><MIcon size={12} weight="bold"/>{m.kind}</div>
                    <div style={{fontSize:11,marginTop:2}}>{prod?.name||"(producto)"}</div>
                    {m.notes&&<div style={{fontSize:10,color:C.t2,marginTop:2}}>{m.notes}</div>}
                    <div style={{fontSize:9,color:C.t3,marginTop:2}}>{new Date(m.created_at).toLocaleString()}{m.created_by?" · "+m.created_by:""}</div>
                  </div>
                  <div style={{textAlign:"right",marginLeft:10}}>
                    <div style={{fontSize:14,fontWeight:800,color}}>{m.qty>0?"+":""}{m.qty}</div>
                    {kgEquiv(m.qty,prod?.specs)&&<div style={{fontSize:9,color:C.t2}}>≈{kgEquiv(m.qty,prod?.specs)}</div>}
                    <div style={{fontSize:9,color:C.t2}}>saldo: {m.balance_after}</div>
                  </div>
                </div>;
              })}
            </div>
          )}
          {/* v10.46.0 — Tab Historial: órdenes Cuadra (production + sale), filtrables por cliente + búsqueda */}
          {tab==="history"&&<>
            <SearchInput wrapStyle={{marginBottom:10}} style={{...inp}} value={filterHistory} onChange={e=>setFilterHistory(e.target.value)} placeholder="Filtrar por cliente, P-folio o producto" aria-label="Filtrar historial de órdenes Cuadra"/>
            {history.length===0?<EmptyState icon={BooksIcon} title="Sin órdenes Cuadra todavía" hint="Cuando captures órdenes de stock Cuadra (a stock o desde stock) aparecerán aquí con su folio P y fiscal."/>:(()=>{
              // v10.46.2 FIX — accent-insensitive (Dipticos == Dípticos), consistente con OrderForm.normForSearch
              const norm=s=>(s||"").toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g,"");
              const q=norm(filterHistory.trim());
              const filt=q?history.filter(o=>norm(o.client).includes(q)||norm(o.production_number).includes(q)||norm(o.product).includes(q)):history;
              if(filt.length===0)return <div style={{textAlign:"center",padding:30,color:C.t2,fontSize:12}}>Sin coincidencias</div>;
              return <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {filt.map(o=>{
                  const _hpSpecs=products.find(p=>p.id===o.client_product_id)?.specs; // v10.73.4 — equiv kg si es producto vendido por kilo
                  const isProd=o.stock_role==="production";
                  const isSale=o.stock_role==="sale";
                  const color=isProd?C.emr:isSale?C.sal:C.t2;
                  const HIcon=isProd?PackageIcon:isSale?ShoppingCartIcon:null;
                  const label=isProd?(o.stock_loaded?"a Stock":"a Stock (pendiente)"):(isSale?"desde Stock":"—");
                  return <div key={o.id} style={{padding:"10px 12px",borderRadius:10,background:C.sf,border:"0.5px solid "+C.bd}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"start",gap:10}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                          <span style={{display:"inline-flex",alignItems:"center",gap:5,fontSize:12,fontWeight:700,color}}>{HIcon?<HIcon size={12} weight="bold"/>:"·"}{label}</span>
                          <span style={{fontSize:11,color:C.ac,fontWeight:700,fontFamily:"'Geist Mono',monospace"}}>{o.production_number||"—"}</span>
                          {o.invoice_folio&&<span style={{fontSize:10,fontWeight:700,color:o.invoice_type==="factura"?C.fac:C.live}}>{o.invoice_folio}</span>}
                        </div>
                        <div style={{fontSize:11,marginTop:3}}>{o.client||"—"}</div>
                        {(o.client_agent||"").trim()&&<div style={{marginTop:2}}><span style={{display:"inline-flex",alignItems:"center",gap:3,fontSize:10,fontWeight:600,color:C.ac,background:C.ac+"12",border:"1px solid "+C.ac+"22",padding:"1px 6px",borderRadius:20}}><UserIcon size={10} weight="bold" style={{opacity:.8}}/>{o.client_agent}</span></div>}
                        <div style={{fontSize:10,color:C.t2,marginTop:2}}>{o.product||"—"}{o.quantity?" · "+o.quantity+" pzas":""}{kgEquiv(o.quantity,_hpSpecs)?" ≈ "+kgEquiv(o.quantity,_hpSpecs):""}</div>
                        <div style={{fontSize:9,color:C.t3,marginTop:3}}>Stage: <StageLbl stage={o.stage} size={9}/> · {new Date(o.created_at).toLocaleDateString()}{o.invoiced_by?" · "+o.invoiced_by:""}</div>
                      </div>
                      {/* v10.46.2 FIX — null check explícito permite mostrar ventas $0 (regalos/cortesía) */}
                      {o.price!==null&&o.price!==undefined&&<div style={{textAlign:"right",marginLeft:8}}>
                        <div style={{fontSize:13,fontWeight:800}}>${Number(o.price).toLocaleString("es-MX",{minimumFractionDigits:0})}</div>
                      </div>}
                    </div>
                  </div>;
                })}
              </div>;
            })()}
          </>}
        </div>
      }
    </div>
    {editing?.mode==="new"&&<ProductFormModal clients={clients} userLogin={userLogin} onSave={async row=>{
      try{await db.saveClientProduct(row);showToast("✅ Producto agregado al catálogo");setEditing(null);await reload()}
      catch(e){showToast("❌ "+e.message,"error")}
    }} onClose={()=>setEditing(null)}/>}
    {editing?.mode==="adjust"&&<AdjustStockModal product={editing.product} userLogin={userLogin} onSave={async(qty,notes)=>{
      try{await db.recordStockMovement({client_product_id:editing.product.id,kind:"ADJUST",qty,notes,created_by:userLogin||user});showToast("✅ Ajuste registrado");setEditing(null);await reload()}
      catch(e){showToast(humanizeStockError(e),"error")}
    }} onClose={()=>setEditing(null)}/>}
    {/* v10.55.0 — Carrito de venta batch: N productos + folio fiscal compartido */}
    {editing?.mode==="bulk_sell"&&<BulkSellModal products={products} userLogin={userLogin} showToast={showToast} onSuccess={()=>{setEditing(null);reload().catch(e=>console.warn("[InventoryModal] post-bulk reload:",e))}} onClose={()=>setEditing(null)}/>}
    {editing?.mode==="sell"&&<SellFromStockModal product={editing.product} userLogin={userLogin} onSell={async args=>{
      try{
        // v10.46.0 — sell_from_stock RETURNS orders (la orden creada).
        // Auto-abrir InvoiceModal para que Karla asigne Factura/Remisión inmediatamente.
        const order=await db.sellFromStock({...args,client_product_id:editing.product.id,created_by:userLogin||user});
        showToast("✅ Venta creada — selecciona Factura o Remisión");
        setEditing(null);
        // v10.46.7 C6 — abrir InvoiceModal ANTES del reload(): si reload() falla por red,
        // Karla aún ve el modal para asignar folio.
        // v10.46.10 M3 — el reload interno solo si el modal sigue abierto (sin onOpenInvoice).
        // Cuando hay onOpenInvoice, se desmonta el InventoryModal y el padre (App) hace su
        // propio reload de orders al setInventoryOpen(false) — evita reload doble.
        if(order&&onOpenInvoice){
          onOpenInvoice(order);
          onClose();
        }else{
          reload().catch(e=>console.warn("[InventoryModal] post-sell reload:",e));
        }
      }
      catch(e){showToast(humanizeStockError(e),"error")}
    }} onClose={()=>setEditing(null)}/>}
  </div>;
}

function ProductFormModal({clients, userLogin, onSave, onClose}) {
  useEscClose(onClose);
  const [clientId,setClientId]=useState("");
  const [name,setName]=useState("");
  const [sku,setSku]=useState("");
  // v10.46.0 — Quitado campo "Precio unitario" del form (poco usado, lo captura SellFromStockModal).
  // v10.42.1 — `clients` del App se deriva de las órdenes (no incluye id ni billing_mode).
  // Cargamos los clientes stock vía RPC list_stock_clients (schema cobranza no expuesto a PostgREST).
  const [stockClients,setStockClients]=useState([]);
  const [loadingClients,setLoadingClients]=useState(true);
  useEffect(()=>{
    let alive=true;
    (async()=>{
      try{
        const {data,error}=await supabase.rpc("list_stock_clients");
        if(!alive)return;
        if(error){console.warn("[ProductFormModal] stock clients:",error.message);setStockClients([])}
        else setStockClients(data||[]);
      }finally{if(alive)setLoadingClients(false)}
    })();
    return ()=>{alive=false};
  },[]);
  const canSave=clientId&&name.trim();
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
    <div style={{background:C.bg,borderRadius:20,padding:22,maxWidth:440,width:"94%"}}>
      <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,margin:"0 0 14px"}}><PlusIcon size={17} weight="bold"/>Nuevo Producto al Catálogo</h3>
      <div style={{marginBottom:10}}>
        <label style={lbl}>Cliente (stock) *</label>
        <select style={inp} value={clientId} onChange={e=>setClientId(e.target.value)} disabled={loadingClients||stockClients.length===0}>
          <option value="">{loadingClients?"Cargando…":(stockClients.length===0?"— sin clientes stock —":"Selecciona cliente…")}</option>
          {stockClients.map(c=><option key={c.id} value={c.id}>{c.name}{c.pool_name?" · pool "+c.pool_name:""}</option>)}
        </select>
        {!loadingClients&&stockClients.length===0&&<div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,color:C.wn,marginTop:4}}><WarningIcon size={11} weight="fill"/>No hay clientes con billing_mode=stock.</div>}
        {/* v10.48.0 — Aviso si el cliente seleccionado comparte stock con otros del mismo pool */}
        {(()=>{const sel=stockClients.find(c=>c.id===clientId);if(!sel?.stock_pool_id)return null;
          const others=stockClients.filter(c=>c.stock_pool_id===sel.stock_pool_id&&c.id!==sel.id);
          if(others.length===0)return null; // v10.72.21 — pool con 1 solo cliente (post-limpieza Cuadra) ya no es "compartido"; evita el aviso "0 clientes más"
          return <div style={{display:"flex",alignItems:"flex-start",gap:5,fontSize:10,color:C.emr,marginTop:4,padding:"4px 8px",background:C.emr+"08",borderRadius:6,lineHeight:1.4}}><PackageIcon size={11} weight="bold" style={{flexShrink:0,marginTop:1}}/><span>Producto compartido con pool <b>{sel.pool_name}</b> · {others.length} clientes más usan este stock</span></div>;
        })()}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
        <div><label style={lbl}>Nombre *</label><input style={inp} value={name} onChange={e=>setName(e.target.value)} placeholder="ej. Tarjeta Presentación A"/></div>
        <div><label style={lbl}>SKU</label><input style={inp} value={sku} onChange={e=>setSku(e.target.value.toUpperCase())} placeholder="CUA-001"/></div>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={onClose} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cancelar</button>
        <button onClick={()=>{
          if(!canSave)return;
          // v10.48.0 — Si el cliente seleccionado pertenece a un pool, crear el SKU en el pool
          // (client_id queda NULL). Si no, crear con client_id directo (modelo legacy individual).
          const sel=stockClients.find(c=>c.id===clientId);
          const payload=sel?.stock_pool_id
            ? {client_id:null,stock_pool_id:sel.stock_pool_id,name:name.trim(),sku:sku.trim()||null,unit_price:null,created_by:userLogin||null}
            : {client_id:clientId,stock_pool_id:null,name:name.trim(),sku:sku.trim()||null,unit_price:null,created_by:userLogin||null};
          onSave(payload);
        }} disabled={!canSave} style={{...bt(C.emr),flex:1,justifyContent:"center",opacity:canSave?1:.4,cursor:canSave?"pointer":"not-allowed"}}><FloppyDiskIcon size={14} weight="bold"/>Guardar</button>
      </div>
    </div>
  </div>;
}

function AdjustStockModal({product, userLogin, onSave, onClose}) {
  useEscClose(onClose);
  const [qty,setQty]=useState("");
  const [notes,setNotes]=useState("");
  // v10.54.7 — busy state previene duplicados por click múltiple (mismo patrón CreditAdjustModal)
  const [busy,setBusy]=useState(false);
  const n=parseInt(qty,10);
  const valid=Number.isFinite(n)&&n!==0;
  const preview=valid?(product.stock_actual+n):product.stock_actual;
  const canSubmit=valid&&preview>=0&&!busy;
  const submit=async()=>{
    if(!canSubmit) return;
    setBusy(true);
    try{ await onSave(n, notes.trim()||null); }
    finally{ setBusy(false); }
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
    <div style={{background:C.bg,borderRadius:20,padding:22,maxWidth:420,width:"94%"}}>
      <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,letterSpacing:"-0.008em",margin:"0 0 4px"}}><ChartBarIcon size={17} weight="bold"/>Ajuste de Stock</h3>
      <div style={{fontSize:12,color:C.t2,marginBottom:14}}>{product.name}</div>
      <div style={{background:C.sf,borderRadius:10,padding:10,marginBottom:12,display:"flex",justifyContent:"space-between"}}>
        <div><div style={{fontSize:10,color:C.t2,textTransform:"uppercase"}}>Actual</div><div style={{fontSize:18,fontWeight:800}}>{product.stock_actual}</div></div>
        <div style={{fontSize:24,color:C.t2,alignSelf:"center"}}>→</div>
        <div><div style={{fontSize:10,color:C.t2,textTransform:"uppercase"}}>Nuevo saldo</div><div style={{fontSize:18,fontWeight:800,color:preview<0?C.dn:C.ok}}>{preview}</div></div>
      </div>
      <div style={{marginBottom:10}}>
        <label style={lbl} htmlFor="adjust-qty">Cantidad (positiva o negativa) *</label>
        <input id="adjust-qty" aria-label="Cantidad de ajuste (positiva suma, negativa resta)" style={inp} type="number" value={qty} onChange={e=>setQty(e.target.value)} placeholder="ej. +100 (sumar) o -50 (restar)" autoFocus disabled={busy}/>
        <div style={{fontSize:10,color:C.t2,marginTop:3}}>Positiva: sumar inventario · Negativa: restar (merma, error)</div>
      </div>
      <div style={{marginBottom:16}}>
        <label style={lbl} htmlFor="adjust-notes">Motivo (recomendado)</label>
        <input id="adjust-notes" aria-label="Motivo del ajuste" style={inp} value={notes} onChange={e=>setNotes(e.target.value)} placeholder="ej. Carga inicial vs conteo Gerardo" disabled={busy}/>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,opacity:busy?.5:1,cursor:busy?"wait":"pointer"}}>Cancelar</button>
        <button onClick={submit} disabled={!canSubmit} style={{...bt(canSubmit?"#f59e0b":"#9ca3af"),flex:1,justifyContent:"center",opacity:canSubmit?1:.6,cursor:canSubmit?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Aplicando...</>:<><ChartBarIcon size={14} weight="bold"/>Aplicar</>}</button>
      </div>
    </div>
  </div>;
}

// v10.55.1 — Carrito de venta batch desde stock Cuadra con folio fiscal compartido + multi-pago.
// Karla captura UN total (no precios unitarios). Estado de pago + N referencias bancarias.
// Reemplaza el flujo individual sell_from_stock.
function BulkSellModal({products, userLogin, onSuccess, onClose, showToast}) {
  const busyRef = useRef(false);
  // v10.56.1 F-M1: ESC no cierra durante busy (evita cancelación visual con RPC corriendo)
  useEscClose(useCallback(()=>{ if(!busyRef.current) onClose(); }, [onClose]));
  const [search, setSearch] = useState("");
  const [cart, setCart] = useState([]);
  const [poolClients, setPoolClients] = useState([]);
  const [destClientId, setDestClientId] = useState("");
  const [invoiceType, setInvoiceType] = useState("factura");
  const [folio, setFolio] = useState("");
  const [folioEdited, setFolioEdited] = useState(false); // M2: tracking si Karla editó manualmente
  const [suggestionByType, setSuggestionByType] = useState({factura:"", remision:""});
  const [totalAmount, setTotalAmount] = useState("");
  const [paymentStatus, setPaymentStatus] = useState("unpaid");
  const [paymentRefs, setPaymentRefs] = useState([]);
  const [agent, setAgent] = useState("");
  // v10.59.2 C3 — AGENTE (contacto del cliente comprador, ej. Eva/Jorge). Distinto del Vendedor SYGMA (agent).
  const [clientAgent, setClientAgent] = useState("");
  const [clientAgents, setClientAgents] = useState([]);
  const [notes, setNotes] = useState("");
  const [busy, setBusy] = useState(false);
  // sync ref con state para que ESC handler lea el valor actual sin re-binding
  useEffect(()=>{ busyRef.current = busy; }, [busy]);

  useEffect(()=>{
    let alive = true;
    Promise.all([db.getNextFolioSuggestion("factura"), db.getNextFolioSuggestion("remision")])
      .then(([f,r])=>{
        if (!alive) return;
        setSuggestionByType({factura:f||"", remision:r||""});
        setFolio(invoiceType==="factura"?(f||""):(r||""));
      })
      .catch(e=>console.warn("[BulkSellModal] suggestions:",e));
    return ()=>{alive=false};
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // M2: solo auto-rellenar folio si Karla NO lo editó manualmente
  useEffect(()=>{
    if (folioEdited) return;
    setFolio(invoiceType==="factura"?suggestionByType.factura:suggestionByType.remision);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [invoiceType, suggestionByType]);

  // v10.56.1 F-C1/F-C3: al cambiar invoiceType, la base IVA cambia → resetear total + pagos.
  // Si Karla había capturado 1000 pensando "remisión SIN IVA" y cambia a factura, el monto se
  // reinterpretaría como CON IVA silenciosamente (ledger queda corto). Mejor recapturar.
  const firstTypeChangeRef = useRef(true);
  useEffect(()=>{
    if (firstTypeChangeRef.current) { firstTypeChangeRef.current = false; return; }
    if (totalAmount || paymentRefs.length>0) {
      setTotalAmount("");
      setPaymentStatus("unpaid");
      setPaymentRefs([]);
      if (showToast) showToast("ℹ️ Recaptura el total: cambió la base IVA del documento","info");
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [invoiceType]);

  const hasPooled = cart.some(c=>c.stock_pool_id);
  const firstPoolId = cart.find(c=>c.stock_pool_id)?.stock_pool_id;
  // M1 visual: detecta items de pools mezclados
  const mixedPools = cart.filter(c=>c.stock_pool_id).some(c=>c.stock_pool_id !== firstPoolId);
  const noPoolClientIds = cart.filter(c=>!c.stock_pool_id).map(c=>c.client_id);
  const mixedClientsNoPool = noPoolClientIds.length>0 && noPoolClientIds.some(id=>id!==noPoolClientIds[0]);
  // v10.56.1 F-M7: edge case durante migración — productos pooled + no-pool mezclados
  const mixedPooledAndNonPooled = cart.some(c=>c.stock_pool_id) && cart.some(c=>!c.stock_pool_id);

  useEffect(()=>{
    if (!hasPooled) { setPoolClients([]); setDestClientId(""); return; }
    let alive = true;
    supabase.rpc("list_stock_clients").then(({data,error})=>{
      if (!alive || error) return;
      const list = (data||[]).filter(c=>c.stock_pool_id===firstPoolId);
      setPoolClients(list);
      if (list.length===1) setDestClientId(list[0].id);
    });
    return ()=>{alive=false};
  }, [hasPooled, firstPoolId]);

  // v10.59.2 C3 — agentes (contactos) del cliente efectivo del carrito: destClientId si hay
  // pool, si no el client_id compartido del 1er item (los guards mixedClientsNoPool garantizan
  // que todos los items sin pool comparten cliente).
  useEffect(()=>{
    const effId = hasPooled ? destClientId : (cart[0]?.client_id||null);
    if(!effId){ setClientAgents([]); return; }
    let alive=true;
    supabase.rpc("list_client_agents",{p_client_id:effId}).then(({data})=>{if(alive)setClientAgents(data||[])}).catch(()=>{if(alive)setClientAgents([])});
    return ()=>{alive=false};
  // v10.59.6 — dep por el client_id primitivo (no el array cart): evita re-fetch en cada tecla de cantidad
  }, [hasPooled, destClientId, cart[0]?.client_id]);

  const addToCart = (p) => {
    if (cart.find(c=>c.client_product_id===p.id)) return;
    // 🆕 v10.73.3 — venta por KILOS (china blanco): si el producto trae specs.sell_unit='kg',
    // Karla captura kilos y se convierte a unidades (qty) con units_per_kg (ej. 25kg=2000u → ×80).
    // El resto de productos sigue en piezas/unidades como hoy. Default seguro: sin specs → unidades.
    const _kg = p.specs?.sell_unit==="kg";
    setCart([...cart, {
      client_product_id: p.id,
      name: p.name,
      sku: p.sku,
      stock_actual: p.stock_actual,
      sellUnit: _kg ? "kg" : "u",
      unitsPerKg: Number(p.specs?.units_per_kg)||null,
      qtyKg: "",
      qty: _kg ? 0 : 1,
      stock_pool_id: p.stock_pool_id,
      client_id: p.client_id
    }]);
  };
  const removeFromCart = (id) => setCart(cart.filter(c=>c.client_product_id!==id));
  const updateItem = (id, patch) => setCart(cart.map(c=>c.client_product_id===id?{...c,...patch}:c));

  const parseFolio = (f) => {
    const m = String(f||"").toUpperCase().match(/^[DR]-(\d+)$/);
    if (!m) return null;
    if (m[1].length>1 && m[1].startsWith("0")) return null;
    return parseInt(m[1], 10);
  };
  const pref = invoiceType==="factura"?"D-":"R-";
  const folioOK = parseFolio(folio) !== null && folio.toUpperCase().startsWith(pref);
  const totalNum = parseFloat(totalAmount);
  const totalOK = Number.isFinite(totalNum) && totalNum > 0;
  // MultiPaymentPicker espera SUBTOTAL SIN IVA (lo multiplica × 1.16 si factura).
  // Karla captura el total CON IVA si factura, SIN IVA si remisión.
  // v10.58.5 F10: NO pre-redondear el subtotal. Si pre-redondeamos, el picker
  // luego hace round((round(X/1.16))*116)/100 y puede diferir 1¢ vs round(X*100)
  // → bloquea facturas grandes con "Cubierto" verde pero sumCents !== totalCents.
  // Pasamos el cociente exacto y dejamos que el picker haga UN solo redondeo final.
  const subtotalSinIVA = invoiceType==="factura" ? (totalNum/1.16) : totalNum;

  const validCart = cart.length>0 && cart.every(c=>c.qty>0 && c.qty<=c.stock_actual);
  const validDest = !hasPooled || !!destClientId;
  // v10.56.1 F-C2: ternaria muerta eliminada. totalAmount ya viene CON IVA si factura
  // (el label de captura lo aclara). La suma de paymentRefs se compara directo contra él.
  const sumCents = paymentRefs.reduce((s,r)=>s+Math.round((Number(r.amount)||0)*100), 0);
  const totalCents = Math.round((totalNum||0)*100);
  const refValid = (r) => {
    if (!r.method) return false;
    if (!(Number(r.amount) > 0)) return false;
    // v10.72.11 — ref bancaria opcional (recomendada): ya no bloquea el guardado
    return true;
  };
  const allRefsValid = paymentRefs.length===0 || paymentRefs.every(refValid);
  const validPayments = paymentStatus==="unpaid"
    ? true
    : (allRefsValid && paymentRefs.length>0
        && (paymentStatus==="paid" ? sumCents===totalCents : (sumCents>0 && sumCents<totalCents)));

  const canSubmit = !busy && validCart && folioOK && validDest && totalOK
    && !mixedPools && !mixedClientsNoPool && !mixedPooledAndNonPooled && validPayments;

  const submit = async()=>{
    if (!canSubmit) return;
    setBusy(true);
    try {
      // v10.72.29 — helper toBackendRef incluye bank_ref_omitted_intentional
      // (CRÍTICO: sin esto la marca de "cliente no proporciono folio" se pierde
      // y Lucero ve "Sin folio (revisar)" siempre).
      const refsForBackend = paymentStatus==="unpaid" ? null
        : paymentRefs.map(toBackendRef);
      const result = await db.bulkSellFromStock({
        items: cart.map(c=>({client_product_id:c.client_product_id, qty:c.qty})),
        total_amount: totalNum,
        dest_client_id: hasPooled ? destClientId : null,
        invoice_type: invoiceType,
        folio: folio.toUpperCase(),
        payment_status: paymentStatus,
        payment_refs: refsForBackend,
        due_date: null,
        agent: agent || null, // v10.64.3 — "Sin asignar" NO se atribuye al captador (era agent||userLogin)
        notes: notes.trim() || null,
        actor: userLogin || "sistema",
        client_agent: clientAgent.trim() || null // v10.59.2 C3 — contacto del cliente comprador
      });
      showToast(`✅ ${result.folio} · OC ${result.oc_id} · ${result.items_count} productos · $${Number(result.total_amount).toLocaleString("es-MX",{minimumFractionDigits:2})}`);
      onSuccess(result);
    } catch(e) {
      showToast("❌ "+(e?.message||"error desconocido"), "error");
    } finally {
      setBusy(false);
    }
  };

  const filtered = products.filter(p=>p.stock_actual>0 && (!search || (p.name||"").toLowerCase().includes(search.toLowerCase()) || (p.sku||"").toLowerCase().includes(search.toLowerCase())));

  return <div onClick={busy?undefined:onClose} role="dialog" aria-modal="true" aria-busy={busy} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:20}}>
    <div onClick={e=>e.stopPropagation()} style={{background:C.bg,borderRadius:20,padding:0,maxWidth:980,width:"100%",maxHeight:"94vh",display:"flex",flexDirection:"column"}}>
      <div style={{padding:"16px 20px",borderBottom:"0.5px solid "+C.bd,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:17,fontWeight:800,margin:0}}><ShoppingCartIcon size={18} weight="bold"/>Carrito de venta — Stock Cuadra</h3>
          <div style={{fontSize:11,color:C.t2,marginTop:2}}>Agrega productos, captura el total de la venta y registra los pagos en un solo paso</div>
        </div>
        <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),padding:"8px",border:"0.5px solid "+C.bd,minWidth:40,minHeight:40,justifyContent:"center"}}><XIcon size={15} weight="bold"/></button>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1.15fr",flex:1,minHeight:0,overflow:"hidden"}}>
        {/* Catálogo */}
        <div style={{borderRight:"0.5px solid "+C.bd,display:"flex",flexDirection:"column",overflow:"hidden"}}>
          <div style={{padding:"10px 14px",borderBottom:"0.5px solid "+C.bd}}>
            <SearchInput style={{...inp,fontSize:12}} placeholder="Buscar producto..." value={search} onChange={e=>setSearch(e.target.value)} disabled={busy}/>
          </div>
          <div style={{flex:1,overflowY:"auto",padding:"10px 14px"}}>
            {filtered.length===0 ? <div style={{padding:30,textAlign:"center",color:C.t2,fontSize:12}}>Sin productos con stock disponible</div> :
            filtered.map(p=>{
              const inCart = !!cart.find(c=>c.client_product_id===p.id);
              return <div key={p.id} style={{padding:10,borderRadius:8,background:inCart?C.sal+"10":C.sf,border:"1px solid "+(inCart?C.sal:C.bd),marginBottom:6,display:"flex",alignItems:"center",gap:8}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:12,fontWeight:700,color:C.tx,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name}</div>
                  <div style={{fontSize:10,color:C.t2,marginTop:2}}>{p.sku?p.sku+" · ":""}stock: <b style={{color:C.emr}}>{p.stock_actual}</b>{kgEquiv(p.stock_actual,p.specs)?<> · ≈<b style={{color:C.emr}}>{kgEquiv(p.stock_actual,p.specs)}</b></>:null}</div>
                </div>
                {inCart
                  ? <button onClick={()=>removeFromCart(p.id)} disabled={busy} style={{...bt(C.dn+"15",C.dn),padding:"4px 8px",fontSize:10,border:"0.5px solid "+C.dn+"40"}}>Quitar</button>
                  : <button onClick={()=>addToCart(p)} disabled={busy} style={{...bt(C.sal),padding:"4px 10px",fontSize:11}}>+ Agregar</button>
                }
              </div>;
            })}
          </div>
        </div>

        {/* Carrito + captura */}
        <div style={{display:"flex",flexDirection:"column",overflow:"hidden",background:"#fafafa"}}>
          <div style={{padding:"10px 14px",borderBottom:"0.5px solid "+C.bd,fontSize:11,fontWeight:800,color:C.t2,textTransform:"uppercase",letterSpacing:.5,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{display:"inline-flex",alignItems:"center",gap:5}}><ShoppingCartIcon size={12} weight="bold"/>Carrito ({cart.length})</span>
            {cart.length>0 && <button onClick={()=>setCart([])} disabled={busy} style={{...bt(C.sf,C.t2),padding:"2px 8px",fontSize:9,border:"0.5px solid "+C.bd}}>Vaciar</button>}
          </div>
          <div style={{flex:1,overflowY:"auto",padding:"10px 14px"}}>
            {cart.length===0 ? <div style={{padding:30,textAlign:"center",color:C.t2,fontSize:12}}>Agrega productos del catálogo →</div> :
            <>
              {/* M1/M3: warnings de mezcla */}
              {mixedPools && <div style={{display:"flex",alignItems:"flex-start",gap:6,padding:10,background:C.dn+"15",border:"1px solid "+C.dn+"40",borderRadius:8,marginBottom:8,fontSize:11,color:C.dn,fontWeight:600}}>
                <WarningIcon size={13} weight="fill" style={{flexShrink:0,marginTop:1}}/>Hay productos de pools distintos. Solo puedes vender productos del mismo pool en una sola venta.
              </div>}
              {mixedClientsNoPool && <div style={{display:"flex",alignItems:"flex-start",gap:6,padding:10,background:C.dn+"15",border:"1px solid "+C.dn+"40",borderRadius:8,marginBottom:8,fontSize:11,color:C.dn,fontWeight:600}}>
                <WarningIcon size={13} weight="fill" style={{flexShrink:0,marginTop:1}}/>Hay productos de clientes distintos. Solo puedes vender productos de un mismo cliente en una sola venta.
              </div>}
              {mixedPooledAndNonPooled && <div style={{display:"flex",alignItems:"flex-start",gap:6,padding:10,background:C.dn+"15",border:"1px solid "+C.dn+"40",borderRadius:8,marginBottom:8,fontSize:11,color:C.dn,fontWeight:600}}>
                <WarningIcon size={13} weight="fill" style={{flexShrink:0,marginTop:1}}/>Hay productos de pool junto con productos individuales (sin pool). Solo se permite uno u otro en la misma venta.
              </div>}
              {cart.map(c=>{
                const qtyOk = c.qty>0 && c.qty<=c.stock_actual;
                return <div key={c.client_product_id} style={{padding:10,borderRadius:8,background:C.bg,border:"1px solid "+(qtyOk?C.bd:C.amb),marginBottom:8}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6,gap:6}}>
                    <div style={{fontSize:12,fontWeight:700,color:C.tx,flex:1,minWidth:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.name}</div>
                    <button onClick={()=>removeFromCart(c.client_product_id)} disabled={busy} style={{...bt(C.sf,C.dn),padding:"2px 8px",fontSize:11,border:"0.5px solid "+C.dn+"40"}}><XIcon size={12} weight="bold"/></button>
                  </div>
                  {c.sellUnit==="kg" ? <div style={{display:"flex",alignItems:"center",gap:8,fontSize:11}}>
                    <div style={{flex:1}}>
                      <div style={{color:C.t2,fontSize:9,textTransform:"uppercase",fontWeight:600}}>Kilos</div>
                      <input style={{...inp,padding:"4px 6px",fontSize:12,border:"1.5px solid "+(qtyOk?C.bd:C.amb+"60")}} type="number" step="0.5" min="0" value={c.qtyKg} placeholder="kg" onChange={e=>{const kg=parseFloat(e.target.value)||0;updateItem(c.client_product_id,{qtyKg:e.target.value,qty:Math.round(kg*(c.unitsPerKg||0))})}} disabled={busy}/>
                    </div>
                    <div style={{flex:1.4,fontSize:10,color:c.qty>c.stock_actual?C.dn:C.t3,paddingTop:5,lineHeight:1.4}}>{c.qty>0?<>= <b>{c.qty.toLocaleString()}</b> u · {(c.qty/1000).toLocaleString(undefined,{maximumFractionDigits:2})} millares<br/></>:null}de ~<b>{(c.stock_actual/(c.unitsPerKg||1)).toLocaleString(undefined,{maximumFractionDigits:1})}</b> kg disp.</div>
                  </div>
                  : <div style={{display:"flex",alignItems:"center",gap:8,fontSize:11}}>
                    <div style={{flex:1}}>
                      <div style={{color:C.t2,fontSize:9,textTransform:"uppercase",fontWeight:600}}>Cantidad</div>
                      <input style={{...inp,padding:"4px 6px",fontSize:12,border:"1.5px solid "+(qtyOk?C.bd:C.amb+"60")}} type="number" step="1" min="1" max={c.stock_actual} value={c.qty} onChange={e=>updateItem(c.client_product_id,{qty:parseInt(e.target.value,10)||0})} disabled={busy}/>
                    </div>
                    <div style={{flex:1,fontSize:10,color:c.qty>c.stock_actual?C.dn:C.t3,paddingTop:14}}>de <b>{c.stock_actual}</b> disp.</div>
                  </div>}
                </div>;
              })}
            </>}
          </div>

          {/* Footer: captura */}
          <div style={{borderTop:"0.5px solid "+C.bd,padding:"12px 14px",background:C.bg,maxHeight:"55vh",overflowY:"auto"}}>
            {hasPooled && (
              <div style={{marginBottom:10}}>
                <label style={{...lbl,marginTop:0,fontSize:10}}>Cliente destino *</label>
                <select style={{...inp,fontSize:12}} value={destClientId} onChange={e=>setDestClientId(e.target.value)} disabled={busy||poolClients.length===0}>
                  <option value="">{poolClients.length===0?"— Sin clientes en pool —":"— Selecciona cliente —"}</option>
                  {poolClients.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
            )}
            <div style={{display:"grid",gridTemplateColumns:"100px 1fr",gap:8,marginBottom:8}}>
              <div>
                <label style={{...lbl,marginTop:0,fontSize:10}}>Tipo *</label>
                <div style={{display:"flex",gap:3}}>
                  {["factura","remision"].map(t=>{
                    const sel = invoiceType===t;
                    const c = t==="factura"?C.fac:C.live;
                    return <button key={t} onClick={()=>setInvoiceType(t)} disabled={busy} style={{flex:1,padding:"6px 4px",fontSize:10,fontWeight:700,borderRadius:6,border:"1.5px solid "+(sel?c:C.bd),background:sel?c:C.bg,color:sel?"#fff":C.t2,cursor:busy?"wait":"pointer"}}>{t==="factura"?"D-":"R-"}</button>;
                  })}
                </div>
              </div>
              <div>
                <label style={{...lbl,marginTop:0,fontSize:10}}>Folio fiscal * <span style={{color:C.t3,fontWeight:400}}>(sugerido — modificable)</span></label>
                <input style={{...inp,fontSize:13,fontFamily:"'Geist Mono',monospace",fontWeight:700,letterSpacing:.5,border:"1.5px solid "+(folioOK?C.bd:C.dn+"40")}} value={folio} onChange={e=>{const v=e.target.value; setFolio(v); setFolioEdited(v.length>0);}} placeholder={pref+"XXXX"} disabled={busy}/>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
              <div>
                <label style={{...lbl,marginTop:0,fontSize:10}}>Vendedor</label>
                <select style={{...inp,fontSize:11}} value={agent} onChange={e=>setAgent(e.target.value)} disabled={busy}>
                  <option value="">— Sin asignar —</option>
                  {AGENTS.map(a=><option key={a} value={a}>{a}</option>)}
                </select>
              </div>
              <div>
                <label style={{...lbl,marginTop:0,fontSize:10}}>Notas</label>
                <input style={{...inp,fontSize:11}} value={notes} onChange={e=>setNotes(e.target.value)} placeholder="Opcional" disabled={busy} maxLength={200}/>
              </div>
            </div>
            {/* v10.59.2 C3 — Agente (contacto del cliente comprador) */}
            <div style={{marginBottom:10}}>
              <label style={{...lbl,marginTop:0,fontSize:10}}>Agente <span style={{color:C.t3,fontWeight:400}}>(quién compró — contacto del cliente, opcional)</span></label>
              <input style={{...inp,fontSize:11}} value={clientAgent} onChange={e=>setClientAgent(e.target.value)} placeholder="ej. Eva, Jorge" list="cuadra-client-agents" autoComplete="off" disabled={busy}/>
              <datalist id="cuadra-client-agents">{clientAgents.map(a=><option key={a.id} value={a.name}/>)}</datalist>
            </div>

            {/* Total venta */}
            <div style={{background:C.sal+"08",border:"1.5px solid "+(totalOK?C.sal+"40":C.amb+"60"),borderRadius:10,padding:12,marginBottom:10}}>
              <label style={{...lbl,display:"flex",alignItems:"center",gap:5,marginTop:0,fontSize:10,color:C.sal,fontWeight:700}}><CurrencyDollarIcon size={11} weight="bold"/>Total de venta * <span style={{color:C.t3,fontWeight:400}}>({invoiceType==="factura"?"CON IVA":"SIN IVA"})</span></label>
              <input style={{...inp,fontSize:18,fontWeight:800,fontFamily:"'Geist Mono',monospace",color:C.sal,textAlign:"right",border:"1.5px solid "+(totalOK?C.bd:C.amb+"60")}} type="number" step="0.01" value={totalAmount} onChange={e=>setTotalAmount(e.target.value)} placeholder="0.00" disabled={busy}/>
              {invoiceType==="factura" && totalOK && <div style={{fontSize:10,color:C.t3,marginTop:4,textAlign:"right"}}>Subtotal sin IVA: <b>${(Math.round(subtotalSinIVA*100)/100).toLocaleString("es-MX",{minimumFractionDigits:2})}</b></div>}
            </div>

            {/* MultiPaymentPicker: estado de pago + multi-pago */}
            {totalOK && <div style={{marginBottom:10}}>
              <MultiPaymentPicker
                status={paymentStatus}
                refs={paymentRefs}
                orderTotal={subtotalSinIVA}
                invoiceType={invoiceType}
                onChange={(st, rs)=>{setPaymentStatus(st); setPaymentRefs(rs);}}
              />
            </div>}

            <button onClick={submit} disabled={!canSubmit} style={{...bt(canSubmit?C.sal:"#9ca3af"),width:"100%",justifyContent:"center",padding:"12px",fontSize:13,opacity:canSubmit?1:.6,cursor:canSubmit?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Procesando...</>:<><ShoppingCartIcon size={14} weight="bold"/>Vender y facturar todo</>}</button>
            {!folioOK && folio && <div style={{fontSize:10,color:C.dn,marginTop:6,textAlign:"center"}}>Folio inválido. Formato: {pref}NNNN</div>}
            {!totalOK && totalAmount && <div style={{fontSize:10,color:C.dn,marginTop:6,textAlign:"center"}}>Captura un total mayor a 0</div>}
            {cart.length>0 && !validCart && <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:4,fontSize:10,color:C.amb,marginTop:6}}><WarningIcon size={11} weight="fill"/>Revisa las cantidades de los items</div>}
            {hasPooled && !destClientId && cart.length>0 && <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:4,fontSize:10,color:C.amb,marginTop:6}}><WarningIcon size={11} weight="fill"/>Selecciona el cliente destino del pool</div>}
            {totalOK && !validPayments && <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:4,fontSize:10,color:C.amb,marginTop:6}}><WarningIcon size={11} weight="fill"/>Revisa el estado de pago y los montos</div>}
          </div>
        </div>
      </div>
    </div>
  </div>;
}

function SellFromStockModal({product, userLogin, onSell, onClose}) {
  useEscClose(onClose);
  const [qty,setQty]=useState("");
  // v10.42.2 — Toggle precio: "total" (default, captura monto total de la venta) o "unit" (precio unitario)
  const [priceMode,setPriceMode]=useState("total");
  const [unitPrice,setUnitPrice]=useState(product.unit_price?String(product.unit_price):"");
  const [totalAmount,setTotalAmount]=useState("");
  const [priority,setPriority]=useState("normal");
  const [dueDate,setDueDate]=useState("");
  const [notes,setNotes]=useState("");
  // v10.58.3 — busy state previene doble venta + decremento de stock x2 por double-click.
  // Patrón v10.54.7 (try/finally + disable buttons).
  const [busy,setBusy]=useState(false);
  // v10.48.0 — Si el producto pertenece a un pool compartido, Karla debe elegir qué cliente del pool recibe.
  const [poolClients,setPoolClients]=useState([]);
  const [destClientId,setDestClientId]=useState("");
  const isPooled=!!product.stock_pool_id;
  useEffect(()=>{
    if(!isPooled)return;
    let alive=true;
    supabase.rpc("list_stock_clients").then(({data,error})=>{
      if(!alive||error)return;
      const list=(data||[]).filter(c=>c.stock_pool_id===product.stock_pool_id);
      setPoolClients(list);
      if(list.length===1)setDestClientId(list[0].id);
    }).catch(e=>console.warn("[SellFromStockModal] pool clients:",e));
    return ()=>{alive=false};
  },[isPooled,product.stock_pool_id]);
  const n=parseInt(qty,10);
  // v10.73.4 — ruta legacy (HOY inalcanzable desde la UI). Guard defensivo: bloquear venta de productos
  // vendidos por KILO aquí — este flujo manda qty crudo sin conversión kg→unidades. Forzar el Carrito de venta.
  const isKgSell=product.specs?.sell_unit==="kg";
  const validQty=!isKgSell&&Number.isFinite(n)&&n>0&&n<=product.stock_actual;
  const validDestClient=!isPooled||!!destClientId;
  // Resuelve los dos valores según el modo activo
  const computedUnit=priceMode==="unit"
    ?(unitPrice?parseFloat(unitPrice):NaN)
    :(validQty&&totalAmount?parseFloat(totalAmount)/n:NaN);
  const computedTotal=priceMode==="total"
    ?(totalAmount?parseFloat(totalAmount):NaN)
    :(validQty&&unitPrice?n*parseFloat(unitPrice):NaN);
  const showUnit=Number.isFinite(computedUnit)?computedUnit.toFixed(2):"—";
  const showTotal=Number.isFinite(computedTotal)?computedTotal.toFixed(2):"0.00";
  const valid=validQty&&validDestClient;
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
    <div style={{background:C.bg,borderRadius:20,padding:22,maxWidth:460,width:"94%"}}>
      <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,letterSpacing:"-0.008em",margin:"0 0 4px"}}><ShoppingCartIcon size={17} weight="bold"/>Vender desde Stock</h3>
      <div style={{fontSize:12,color:C.t2,marginBottom:10}}>{product.name}</div>
      <div style={{background:C.sf,borderRadius:10,padding:10,marginBottom:12,fontSize:11}}>Saldo disponible: <b style={{color:C.emr,fontSize:14}}>{product.stock_actual}</b></div>
      {isKgSell&&<div style={{display:"flex",alignItems:"flex-start",gap:6,padding:10,background:C.amb+"15",border:"1px solid "+C.amb+"50",borderRadius:8,marginBottom:10,fontSize:11,color:C.amb,fontWeight:600,lineHeight:1.4}}><WarningIcon size={13} weight="fill" style={{flexShrink:0,marginTop:1}}/>Este producto se vende por KILOS (con conversión a unidades). Usa el <b>Carrito de venta</b> del inventario, no esta venta individual.</div>}
      {/* v10.48.0 — Dropdown obligatorio cliente destino para productos pooled */}
      {isPooled&&<div style={{marginBottom:10,padding:10,background:C.emr+"08",borderRadius:10,border:"1px solid "+C.emr+"30"}}>
        <label style={{...lbl,marginTop:0}} htmlFor="sell-dest-client">Cliente que recibe la venta *</label>
        <select id="sell-dest-client" aria-label="Cliente destino de la venta" style={inp} value={destClientId} onChange={e=>setDestClientId(e.target.value)} disabled={poolClients.length===0}>
          <option value="">{poolClients.length===0?"— Sin clientes activos en el pool —":"— Selecciona cliente del pool —"}</option>
          {poolClients.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
        {/* v10.48.1 F3 — mensaje claro cuando pool no tiene clientes activos */}
        {poolClients.length===0
          ?<div style={{display:"flex",alignItems:"flex-start",gap:5,fontSize:10,color:C.dn,marginTop:6,padding:"4px 8px",background:C.dn+"08",borderRadius:6,lineHeight:1.4}}><WarningIcon size={11} weight="fill" style={{flexShrink:0,marginTop:1}}/>No hay clientes activos en este pool. Contacta admin para activar al menos uno antes de vender.</div>
          :<div style={{display:"flex",alignItems:"flex-start",gap:5,fontSize:10,color:C.t2,marginTop:4,lineHeight:1.4}}><PackageIcon size={11} weight="bold" style={{flexShrink:0,marginTop:1}}/><span>Este producto es del pool compartido. La orden creada quedará a nombre del cliente seleccionado pero descontará del inventario común.</span></div>}
      </div>}
      <div style={{marginBottom:10}}>
        <label style={lbl} htmlFor="sell-qty">Cantidad *</label>
        <input id="sell-qty" aria-label="Cantidad a vender desde stock" style={inp} type="number" value={qty} onChange={e=>setQty(e.target.value)} placeholder={"1 a "+product.stock_actual} autoFocus/>
      </div>
      <div style={{marginBottom:10}}>
        <label style={lbl}>Modo de precio</label>
        <div style={{display:"flex",gap:0,borderRadius:10,overflow:"hidden",border:"1px solid "+C.bd,marginBottom:8}}>
          {[{id:"total",ic:CurrencyDollarIcon,l:"Monto total"},{id:"unit",ic:RulerIcon,l:"Precio unitario"}].map(m=>
            <button key={m.id} onClick={()=>setPriceMode(m.id)} style={{display:"inline-flex",alignItems:"center",justifyContent:"center",gap:5,flex:1,padding:"8px 12px",border:"none",background:priceMode===m.id?C.sal:"transparent",color:priceMode===m.id?"#fff":C.t2,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Geist',sans-serif"}}>{(()=>{const MI=m.ic;return <MI size={12} weight="bold"/>})()}{m.l}</button>
          )}
        </div>
        {priceMode==="total"
          ?<><input style={inp} type="number" step="0.01" value={totalAmount} onChange={e=>setTotalAmount(e.target.value)} placeholder="0.00"/>
            <div style={{fontSize:10,color:C.t2,marginTop:4}}>Precio unitario calculado: <b>${showUnit}</b>{validQty&&totalAmount?" · "+n+" pzas × $"+showUnit:""}</div></>
          :<><input style={inp} type="number" step="0.01" value={unitPrice} onChange={e=>setUnitPrice(e.target.value)} placeholder="0.00"/>
            <div style={{fontSize:10,color:C.t2,marginTop:4}}>Total calculado: <b>${showTotal}</b>{validQty&&unitPrice?" · "+n+" pzas × $"+unitPrice:""}</div></>
        }
      </div>
      <div style={{background:C.sal+"10",borderRadius:8,padding:8,marginBottom:10,textAlign:"right",fontSize:13,fontWeight:700,color:C.sal}}>Total venta: ${showTotal}</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
        <div><label style={lbl} htmlFor="sell-priority">Prioridad</label>
          <select id="sell-priority" aria-label="Prioridad de la venta" style={inp} value={priority} onChange={e=>setPriority(e.target.value)}>
            {PRIOS.map(p=><option key={p.id} value={p.id}>{p.l}</option>)}
          </select>
        </div>
        <div><label style={lbl} htmlFor="sell-due">Fecha entrega</label><input id="sell-due" aria-label="Fecha de entrega" style={inp} type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)}/></div>
      </div>
      <div style={{marginBottom:16}}>
        <label style={lbl}>Notas</label>
        <input style={inp} value={notes} onChange={e=>setNotes(e.target.value)} placeholder="Instrucciones de entrega…"/>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,opacity:busy?.5:1,cursor:busy?"wait":"pointer"}}>Cancelar</button>
        <button onClick={async()=>{
          if(!valid||busy)return;
          setBusy(true);
          try{
            await onSell({qty:n,unit_price:Number.isFinite(computedUnit)?Number(computedUnit.toFixed(2)):null,priority,due_date:dueDate||null,notes:notes.trim()||null,agent:userLogin||null,dest_client_id:isPooled?destClientId:null});
          }finally{
            setBusy(false);
          }
        }} disabled={!valid||busy} style={{...bt(valid&&!busy?C.sal:"#9ca3af"),flex:1,justifyContent:"center",opacity:valid&&!busy?1:.5,cursor:valid&&!busy?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Vendiendo...</>:<><ShoppingCartIcon size={14} weight="bold"/>Crear Venta</>}</button>
      </div>
    </div>
  </div>;
}

// v10.45.0 — Modal "Replicar de orden anterior".
// Lupita o admin pueden escoger una orden pasada del mismo cliente como plantilla.
// Lista las últimas 60 órdenes del cliente con thumbnail (si tiene imagen),
// detalles del producto y specs. Click → replica en el form actual (no toca cliente).
function ReplicateFromOrderModal({clientId, clientName, onReplicate, onClose}) {
  useEscClose(onClose);
  const [orders,setOrders]=useState([]);
  const [loading,setLoading]=useState(true);
  const [search,setSearch]=useState("");
  // v10.45.1 — track imágenes fallidas en state (evita DOM manipulation que pelea con React)
  const [failedImgs,setFailedImgs]=useState(new Set());
  // v10.45.1 — prevenir double-click rápido en cards (evita doble setF y doble toast)
  const [replicating,setReplicating]=useState(false);
  const handleSelect=(o)=>{if(replicating)return;setReplicating(true);onReplicate(o)};
  useEffect(()=>{
    let alive=true;
    (async()=>{
      try{
        let q=supabase.from("orders").select("id, production_number, client, client_id, product, product_type, quantity, paper_type, paper_grammage, width_cm, height_cm, standard_size, colors, ink_front, ink_back, finishes, price, maq_price, maq_cost, maq_provider, estimated_hours, image_url, image_url_2, image, file_url, file_name, stage, stock_role, client_product_id, notes, pantone_front, pantone_back, distribution, created_at, invoice_folio").order("created_at",{ascending:false}).limit(100);
        if(clientId)q=q.eq("client_id",clientId);
        else if(clientName?.trim()){
          // v10.45.1 FIX: escapar comodines % _ \ en LIKE para evitar matches inesperados con nombres tipo "ABC%Corp"
          const escaped=clientName.trim().replace(/[%_\\]/g,m=>"\\"+m);
          q=q.ilike("client",escaped+"%");
        }
        const {data,error}=await q;
        if(!alive)return;
        if(error){console.warn("[ReplicateModal]",error.message);setOrders([])}
        else setOrders(data||[]);
      }finally{if(alive)setLoading(false)}
    })();
    return ()=>{alive=false};
  },[clientId,clientName]);
  const normS=s=>(s||"").toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g,"");
  const sq=normS(search.trim());
  const filtered=sq?orders.filter(o=>
    normS(o.production_number||"").includes(sq)||
    normS(o.product||"").includes(sq)||
    normS(o.product_type||"").includes(sq)||
    normS(o.invoice_folio||"").includes(sq)||
    normS(o.paper_type||"").includes(sq)
  ):orders;
  const fmtN=n=>n===null||n===undefined||n===""?"":Number(n).toLocaleString("es-MX");
  return <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:16}}>
    <div onClick={e=>e.stopPropagation()} style={{background:C.bg,borderRadius:20,padding:0,maxWidth:780,width:"96%",maxHeight:"90vh",display:"flex",flexDirection:"column"}}>
      <div style={{padding:"18px 22px",borderBottom:"0.5px solid "+C.bd,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div>
          <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:17,fontWeight:800,margin:0}}><ArrowsClockwiseIcon size={18} weight="bold"/>Replicar de orden anterior</h3>
          <div style={{fontSize:11,color:C.t2,marginTop:2}}>{clientName||"—"} · {orders.length} órdenes históricas</div>
        </div>
        <button onClick={onClose} style={{...bt(C.sf,C.t2),padding:"8px",border:"0.5px solid "+C.bd,minWidth:40,minHeight:40,justifyContent:"center"}}><XIcon size={15} weight="bold"/></button>
      </div>
      <div style={{padding:"10px 22px",borderBottom:"0.5px solid "+C.bd}}>
        <SearchInput style={{...inp,fontSize:12,padding:"7px 12px"}} placeholder="Buscar por P-XXXX, producto, papel o folio fiscal..." value={search} onChange={e=>setSearch(e.target.value)}/>
      </div>
      {loading?<SkelRows n={5}/>
      :orders.length===0?<div style={{padding:"40px 20px",textAlign:"center",color:C.t2,fontSize:12}}>
        <TrayIcon size={38} color={C.ph}/>
        <div style={{fontWeight:700,color:C.tx,marginTop:8,marginBottom:4,fontSize:13}}>Sin órdenes previas para este cliente</div>
        <div>Cuando captures órdenes para <b>{clientName||"este cliente"}</b>, aparecerán aquí como plantillas.</div>
      </div>
      :filtered.length===0?<div style={{padding:30,textAlign:"center",color:C.t2,fontSize:12}}>
        <MagnifyingGlassIcon size={26} color={C.ph}/>
        <div style={{marginTop:6}}>Sin resultados con "{search}"</div>
      </div>
      :<div style={{overflowY:"auto",padding:"14px 22px",flex:1,display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(340px,1fr))",gap:10}}>
        {filtered.map(o=>{
          const img=o.image_url||o.image_url_2||o.image||o.file_url||null;
          const isCancelled=o.stage?.includes("cancelled");
          const isDelivered=o.stage?.includes("delivered")||o.stock_loaded;
          const isCorona=o.stock_role==="production"||o.stock_role==="sale";
          const imgFailed=failedImgs.has(o.id);
          return <div key={o.id} onClick={()=>handleSelect(o)} style={{display:"flex",gap:10,padding:10,borderRadius:12,border:"1px solid "+C.bd,background:C.sf,cursor:replicating?"wait":"pointer",opacity:replicating?0.6:1,transition:"background 0.12s, border-color 0.12s"}}
            onMouseEnter={e=>{if(!replicating){e.currentTarget.style.background=C.ac+"08";e.currentTarget.style.borderColor=C.ac+"40"}}}
            onMouseLeave={e=>{if(!replicating){e.currentTarget.style.background=C.sf;e.currentTarget.style.borderColor=C.bd}}}>
            {/* Thumbnail — v10.45.1: fallback via React state (no DOM manipulation) */}
            <div style={{width:72,height:72,borderRadius:8,background:C.bg,border:"0.5px solid "+C.bd,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
              {img&&!imgFailed?<img src={img} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={()=>setFailedImgs(prev=>{const n=new Set(prev);n.add(o.id);return n})}/>:<FileTextIcon size={26} color={C.ph}/>}
            </div>
            {/* Detalles */}
            <div style={{flex:1,minWidth:0,display:"flex",flexDirection:"column",gap:2}}>
              <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                <span style={{fontSize:12,fontWeight:800,color:C.ac}}>{o.production_number||"sin P-#"}</span>
                {o.invoice_folio&&<span style={{fontSize:9,fontWeight:700,color:C.fac,background:C.fac+"15",padding:"1px 6px",borderRadius:4}}>{o.invoice_folio}</span>}
                {isCorona&&<span style={{display:"inline-flex",alignItems:"center",gap:3,fontSize:9,fontWeight:700,color:C.emr,background:C.emr+"15",padding:"1px 6px",borderRadius:4}}><PackageIcon size={9} weight="bold"/>stock</span>}
                {isCancelled&&<span style={{fontSize:9,fontWeight:700,color:C.dn,background:C.dn+"15",padding:"1px 6px",borderRadius:4}}>CANCELADA</span>}
                {!isCancelled&&isDelivered&&<span style={{display:"inline-flex",alignItems:"center",gap:3,fontSize:9,fontWeight:700,color:C.ok,background:C.ok+"15",padding:"1px 6px",borderRadius:4}}><CheckIcon size={9} weight="bold"/>entregada</span>}
              </div>
              <div style={{fontSize:13,fontWeight:700,color:C.tx,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{o.product||"(sin nombre de producto)"}</div>
              <div style={{fontSize:11,color:C.t2,display:"flex",flexWrap:"wrap",gap:6}}>
                {o.product_type&&<span><b>{o.product_type}</b></span>}
                {o.quantity&&<span>· {fmtN(o.quantity)} pzas</span>}
              </div>
              <div style={{fontSize:10,color:C.t3,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                {o.paper_type?o.paper_type+(o.paper_grammage?" "+o.paper_grammage+"g":""):""}
                {o.width_cm&&o.height_cm?(o.paper_type?" · ":"")+o.width_cm+"×"+o.height_cm+"cm":""}
                {o.colors?" · "+o.colors+" tintas":""}
              </div>
              <div style={{fontSize:10,color:C.t3,marginTop:2}}>
                {o.price?<span style={{color:C.ok,fontWeight:700}}>${fmtN(o.price)}</span>:""}
                {o.created_at?<span> · {fDT(o.created_at)}</span>:""}
              </div>
            </div>
          </div>;
        })}
      </div>}
      <div style={{padding:"10px 22px",borderTop:"0.5px solid "+C.bd,fontSize:10,color:C.t2,background:C.sf,display:"flex",justifyContent:"space-between",alignItems:"center",gap:8,flexWrap:"wrap"}}>
        <span style={{display:"inline-flex",alignItems:"flex-start",gap:5}}><LightbulbIcon size={12} weight="fill" style={{flexShrink:0,marginTop:1}}/><span>Al hacer click en una orden, sus datos (producto, papel, medidas, tintas, acabados, precio) se copian al formulario. <b>Los datos del cliente no se tocan</b>.</span></span>
      </div>
    </div>
  </div>;
}

// v10.43.0 — Apartado Corona (saldo a favor / anticipo abierto).
// Lista clientes con billing_mode='anticipo', su saldo y el ledger de cada uno.
// Karla/Admin/Secretaria pueden ver historial; los DEPOSITOS los registra Lucero en CobranzaFlow.
function CoronaModal({onClose, user, userLogin, showToast}) {
  useEscClose(onClose);
  const [clients,setClients]=useState([]);
  const [selectedId,setSelectedId]=useState(null);
  const [ledger,setLedger]=useState([]);
  const [loadingClients,setLoadingClients]=useState(true);
  const [loadingLedger,setLoadingLedger]=useState(false);
  const [adjusting,setAdjusting]=useState(false); // modal interno para AJUSTE manual (solo admin)
  const [registering,setRegistering]=useState(false); // v10.43.11 — modal nuevo: registrar OC a crédito Corona

  // v10.58.12 F18: alive ref + cleanup. Antes: si Marcelo cerraba el modal mientras
  // listAnticipoClients seguía cargando, setClients/setSelectedId corrían sobre
  // componente desmontado → warning React + ledger vacío en próximo render.
  const reloadAliveRef = useRef(true);
  const reloadClients=async()=>{
    setLoadingClients(true);
    try{
      const list=await db.listAnticipoClients();
      if(!reloadAliveRef.current)return;
      const leadersOnly=(list||[]).filter(c=>c.is_pool_leader);
      setClients(leadersOnly);
      if(leadersOnly.length>0&&!selectedId)setSelectedId(leadersOnly[0].id);
    }catch(e){
      if(!reloadAliveRef.current)return;
      console.error("[CoronaModal] clients:",e);showToast("❌ Error: "+e.message,"error");
    }
    finally{ if(reloadAliveRef.current) setLoadingClients(false); }
  };
  useEffect(()=>{
    reloadAliveRef.current=true;
    reloadClients();
    return()=>{ reloadAliveRef.current=false; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[]);

  useEffect(()=>{
    if(!selectedId)return;
    let alive=true;
    setLoadingLedger(true);
    db.loadCreditLedger(selectedId,200).then(l=>{if(alive)setLedger(l)}).catch(e=>{if(alive){console.error("[CoronaModal] ledger:",e);showToast("❌ "+e.message,"error")}}).finally(()=>{if(alive)setLoadingLedger(false)});
    return ()=>{alive=false};
  },[selectedId]);

  const selected=clients.find(c=>c.id===selectedId);
  const canAdjust=user==="admin";

  const tipoColor=t=>t==="DEPOSITO"?C.emr:t==="CONSUMO"?"#dc2626":t==="REVERSO"?C.ctp:"#f59e0b";
  const TipoIcon=t=>t==="DEPOSITO"?CurrencyDollarIcon:t==="CONSUMO"?ExportIcon:t==="REVERSO"?ArrowUUpLeftIcon:ChartBarIcon;

  // v10.58.15 — role=dialog para accessibility
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}>
    <div role="dialog" aria-modal="true" aria-label="Saldos a favor Corona" style={{background:C.bg,borderRadius:20,padding:0,maxWidth:820,width:"96%",maxHeight:"92vh",display:"flex",flexDirection:"column"}}>
      <div style={{padding:"18px 22px",borderBottom:"0.5px solid "+C.bd,display:"flex",alignItems:"center",justifyContent:"space-between",gap:10}}>
        <div>
          <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:17,fontWeight:800,margin:0}}><DiamondIcon size={17} weight="fill"/>Apartado Corona — Saldo a favor</h3>
          <div style={{fontSize:11,color:C.t2,marginTop:2}}>{clients.length} cliente{clients.length===1?"":"s"} con saldo · {clients.reduce((s,c)=>s+(Array.isArray(c.pool_members)?c.pool_members.length:0),0)} sub-cuentas en pools</div>
        </div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          {/* v10.43.11 — Karla/Lupita/admin pueden registrar OC a crédito desde PrintFlow */}
          {(user==="admin"||user==="karla"||user==="secretaria")&&<button onClick={()=>setRegistering(true)} style={{...bt(C.emr),padding:"7px 12px",fontSize:12}}><DiamondIcon size={13} weight="fill"/>+ Nueva OC a Crédito</button>}
          <button onClick={onClose} style={{...bt(C.sf,C.t2),padding:"8px",border:"0.5px solid "+C.bd,minWidth:40,minHeight:40,justifyContent:"center"}}><XIcon size={15} weight="bold"/></button>
        </div>
      </div>

      {loadingClients?<SkelRows n={6}/>:
       clients.length===0?<EmptyState icon={WalletIcon} title="Aún no hay clientes con saldo a favor" hint="Aparecen aquí cuando Lucero registra un depósito en CobranzaFlow o se activa el modo a crédito del cliente."/>:
       <div style={{display:"grid",gridTemplateColumns:"260px 1fr",flex:1,minHeight:0}}>
         <div style={{borderRight:"0.5px solid "+C.bd,overflowY:"auto",padding:"10px 0"}}>
           {clients.map(c=>{
             const sel=c.id===selectedId;
             const negative=Number(c.current_balance)<0;
             const hasMembers=Array.isArray(c.pool_members)&&c.pool_members.length>0;
             // v10.56.2: sidebar SIEMPRE muestra líderes (filtrados en reloadClients).
             return <button key={c.id} onClick={()=>setSelectedId(c.id)} style={{display:"block",width:"100%",textAlign:"left",padding:"10px 14px",border:"none",background:sel?C.ctp+"10":"transparent",cursor:"pointer",borderLeft:sel?"3px solid "+C.ctp:"3px solid transparent",fontFamily:"'Geist',sans-serif"}}>
               <div style={{fontSize:12,fontWeight:700,color:sel?C.ctp:C.tx,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.name}</div>
               <div style={{fontSize:10,color:C.t2,marginTop:2}}>{c.rfc||"sin RFC"}</div>
               {hasMembers&&<div style={{display:"flex",alignItems:"center",gap:3,fontSize:9,color:C.ctp,marginTop:2,fontWeight:600}}><LinkIcon size={9} weight="bold"/>incluye sub-cuentas: {c.pool_members.join(", ")}</div>}
               <div style={{fontSize:14,fontWeight:800,marginTop:4,color:negative?C.dn:C.emr}}>${Number(c.current_balance||0).toLocaleString("es-MX",{minimumFractionDigits:2})}</div>
             </button>;
           })}
         </div>
         <div style={{overflowY:"auto",padding:"14px 18px",display:"flex",flexDirection:"column"}}>
           {selected?(()=>{
             const selIsMember=!selected.is_pool_leader;
             // v10.56.1: usar pool_balance para mostrar el saldo real del pool aún cuando se ve un miembro
             const displayBalance=Number(selected.pool_balance||selected.current_balance||0);
             return <>
             <div style={{display:"flex",justifyContent:"space-between",alignItems:"start",marginBottom:14}}>
               <div>
                 <h4 style={{fontSize:15,fontWeight:800,margin:0}}>{selected.name}</h4>
                 <div style={{fontSize:11,color:C.t2,marginTop:2}}>{selected.rfc||"sin RFC"} · billing_mode=<b>{selected.billing_mode}</b></div>
               </div>
               <div style={{textAlign:"right"}}>
                 <div style={{fontSize:10,color:C.t2,textTransform:"uppercase"}}>Saldo {selIsMember?"del pool":"actual"} (sin IVA)</div>
                 <div style={{fontSize:20,fontWeight:800,color:displayBalance<0?C.dn:C.emr}}>${displayBalance.toLocaleString("es-MX",{minimumFractionDigits:2})}</div>
                 <div style={{fontSize:9,color:C.t3,marginTop:2}}>≈ ${(displayBalance*1.16).toLocaleString("es-MX",{minimumFractionDigits:2})} con IVA</div>
               </div>
             </div>
             {selIsMember && <div style={{padding:"8px 12px",background:C.ctp+"10",border:"1px solid "+C.ctp+"40",borderRadius:8,fontSize:11,color:C.ctp,marginBottom:12,lineHeight:1.5}}>
               <PaperclipIcon size={12} weight="bold" style={{verticalAlign:"-2px",marginRight:4}}/>Estás viendo el saldo y movimientos del <b>pool de {selected.leader_name}</b>. {selected.name} comparte este saldo con las otras sub-cuentas. Cualquier movimiento aquí afecta a todo el pool.
             </div>}
             <div style={{display:"flex",gap:8,marginBottom:12}}>
               {canAdjust&&<button onClick={()=>setAdjusting(true)} style={{...bt(C.sf,C.t2),border:"0.5px solid "+C.bd,padding:"6px 12px",fontSize:11}}><ChartBarIcon size={12} weight="bold"/>Ajuste manual</button>}
               <button onClick={()=>{setLedger([]);setSelectedId(s=>s);db.loadCreditLedger(selectedId,200).then(l=>setLedger(l))}} style={{...bt(C.sf,C.t2),border:"0.5px solid "+C.bd,padding:"6px 12px",fontSize:11}}><ArrowsClockwiseIcon size={12} weight="bold"/>Recargar</button>
               <div style={{flex:1}}/>
               <div style={{fontSize:10,color:C.t2,alignSelf:"center"}}>Lucero registra depósitos y cobra facturas Corona pendientes en CobranzaFlow</div>
             </div>
             <div style={{fontSize:10,fontWeight:700,color:C.t2,textTransform:"uppercase",marginBottom:6}}>Historial (últimos 200)</div>
             {loadingLedger?<div style={{padding:20,textAlign:"center",color:C.t2}}>Cargando ledger…</div>:
              ledger.length===0?<EmptyState icon={ClockCounterClockwiseIcon} title="Sin movimientos todavía" hint="Aquí se listarán los depósitos, cargos por factura Corona y ajustes en cuanto haya movimiento en el saldo de este cliente."/>:
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {ledger.map(m=>{
                  const color=tipoColor(m.tipo);
                  return <div key={m.id} style={{padding:"10px 12px",borderRadius:10,background:C.sf,border:"0.5px solid "+C.bd,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{display:"flex",alignItems:"center",gap:5,fontSize:12,fontWeight:700,color}}>{(()=>{const TI=TipoIcon(m.tipo);return <TI size={12} weight="bold"/>})()}{m.tipo}</div>
                      {m.referencia&&<div style={{fontSize:11,marginTop:2}}>{m.referencia}</div>}
                      {m.notas&&<div style={{fontSize:10,color:C.t2,marginTop:2,fontStyle:"italic"}}>{m.notas}</div>}
                      <div style={{fontSize:9,color:C.t3,marginTop:2}}>{new Date(m.created_at).toLocaleString()}{m.created_by?" · "+m.created_by:""}{m.periodo?" · "+m.periodo:""}</div>
                    </div>
                    <div style={{textAlign:"right",marginLeft:10}}>
                      <div style={{fontSize:14,fontWeight:800,color}}>{m.monto>0?"+":""}${Number(m.monto).toLocaleString("es-MX",{minimumFractionDigits:2})}</div>
                      <div style={{fontSize:9,color:C.t2}}>saldo: ${Number(m.balance_despues).toLocaleString("es-MX",{minimumFractionDigits:2})}</div>
                    </div>
                  </div>;
                })}
              </div>
             }
           </>;
           })():<EmptyState icon={HandPointingIcon} title="Selecciona un cliente" hint="Elige un cliente de la lista para ver su saldo a favor y el historial de movimientos del apartado Corona."/>}
         </div>
       </div>
      }
    </div>
    {adjusting&&<CreditAdjustModal client={selected} userLogin={userLogin} onSave={async(monto,motivo)=>{
      try{await db.creditAdjust({client_id:selected.id,monto,motivo,user:userLogin||user});showToast("✅ Ajuste registrado");setAdjusting(false);await reloadClients();const fresh=await db.loadCreditLedger(selected.id,200);setLedger(fresh)}
      catch(e){showToast("❌ "+e.message,"error")}
    }} onClose={()=>setAdjusting(false)}/>}
    {registering&&<RegisterCoronaPOModal user={user} userLogin={userLogin} showToast={showToast} onClose={()=>setRegistering(false)} onSaved={async()=>{
      setRegistering(false);
      showToast("✅ OC a Crédito registrada · Tesorería notificada");
      await reloadClients();
      // v10.43.14 FIX M13 — refrescar ledger del cliente seleccionado si lo había
      if(selectedId){try{const fresh=await db.loadCreditLedger(selectedId,200);setLedger(fresh)}catch(e){console.warn("[CoronaModal] refresh ledger:",e)}}
    }}/>}
  </div>;
}

// v10.43.11 — Sub-modal para que Karla/Lupita/admin registren OCs a Crédito desde PrintFlow.
// Mismo RPC credit_deposit que CobranzaFlow; notifica a tesoreria automáticamente vía la RPC.
function RegisterCoronaPOModal({user, userLogin, showToast, onClose, onSaved}) {
  useEscClose(onClose);
  const [clientId,setClientId]=useState("");
  const [externalPoRef,setExternalPoRef]=useState("");
  const [folioFiscal,setFolioFiscal]=useState("");
  const [amount,setAmount]=useState(""); // v10.43.26 — SUBTOTAL sin IVA (sistema multiplica × 1.16 para cobranza)
  const [dueDate,setDueDate]=useState("");
  const [notas,setNotas]=useState("");
  const [busy,setBusy]=useState(false);
  const [stockClients,setStockClients]=useState([]);
  const [loadingClients,setLoadingClients]=useState(true);
  // v10.43.28 — sugerencias del siguiente folio fiscal (mismo patrón que InvoiceModal)
  const [suggestion,setSuggestion]=useState({factura:null,remision:null});
  useEffect(()=>{
    let alive=true;
    db.listAnticipoClients().then(list=>{if(alive)setStockClients(list||[])}).catch(e=>console.warn("[RegisterCoronaPOModal]",e)).finally(()=>{if(alive)setLoadingClients(false)});
    Promise.all([db.getNextFolioSuggestion("factura"),db.getNextFolioSuggestion("remision")])
      .then(([f,r])=>{if(alive)setSuggestion({factura:f,remision:r})})
      .catch(e=>console.warn("[RegisterCoronaPOModal] suggestions:",e));
    return ()=>{alive=false};
  },[]);

  const amountNum=parseFloat(amount);
  const folioClean=folioFiscal.trim().toUpperCase();
  const isFactura=folioClean.startsWith("D-");
  const isRemision=folioClean.startsWith("R-");
  const folioValid=(isFactura||isRemision)&&/^[DR]-[1-9]\d*$/.test(folioClean); // v10.64.3 — sin cero a la izquierda (consistente con Invoice/Split/Matrix)
  // v10.43.28 — determinar qué sugerencia mostrar (default D- si aún no escribió nada)
  const suggestedType=isRemision?"remision":"factura";
  const suggestedFolio=suggestion[suggestedType];
  // Avisar si el folio es menor al sugerido (caso huecos retroactivos)
  const folioNum=folioValid?parseInt(folioClean.split("-")[1],10):0;
  const suggestedNum=suggestedFolio?parseInt(suggestedFolio.split("-")[1],10):0;
  const folioIsLower=folioValid&&suggestedNum>0&&folioNum<suggestedNum;
  const dueDateValid=dueDate&&new Date(dueDate+"T12:00:00")>new Date();
  const valid=clientId&&externalPoRef.trim()&&folioValid&&Number.isFinite(amountNum)&&amountNum>0&&dueDateValid;

  const submit=async()=>{
    if(!valid||busy)return;
    setBusy(true);
    try{
      // v10.43.26 — Ledger SIN IVA. Captura subtotal, RPC calcula × 1.16 para la invoice en cobranza.
      await db.creditDeposit({
        client_id:clientId,external_po_ref:externalPoRef.trim(),folio_fiscal:folioClean,
        subtotal_no_iva:amountNum,due_date:dueDate,user:userLogin||user,notas:notas.trim()||null
      });
      if(onSaved)await onSaved();
    }catch(e){
      console.error("[RegisterCoronaPOModal] Error:",e);
      // v10.43.13 FIX M10 — showToast en lugar de alert nativo
      if(showToast)showToast("❌ "+(e?.message||"No se pudo registrar"),"error");
      setBusy(false);
    }
  };

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
    <div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:560,width:"96%",maxHeight:"90vh",overflowY:"auto"}}>
      <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,letterSpacing:"-0.008em",margin:"0 0 4px"}}><DiamondIcon size={17} weight="fill"/>Registrar OC a Crédito Corona</h3>
      <p style={{fontSize:11,color:C.t2,margin:"0 0 14px"}}>Captura una nueva OC a crédito con su folio fiscal ya emitido. Tesorería será notificada automáticamente.</p>

      <div style={{marginBottom:12}}>
        <label style={lbl}>Cliente *</label>
        <select style={inp} value={clientId} onChange={e=>setClientId(e.target.value)} disabled={loadingClients||stockClients.length===0}>
          <option value="">{loadingClients?"Cargando…":(stockClients.length===0?"— sin clientes anticipo —":"Selecciona…")}</option>
          {stockClients.map(c=><option key={c.id} value={c.id}>{c.is_pool_leader?"🎱":"↳"} {c.name}{!c.is_pool_leader&&c.leader_name?" (sub-cuenta de "+c.leader_name+")":""} · saldo {c.is_pool_leader?"":"compartido "}(sin IVA): ${Number(c.current_balance||0).toLocaleString("es-MX",{minimumFractionDigits:2})}</option>)}
        </select>
        {!loadingClients&&stockClients.length===0&&<div style={{display:"flex",alignItems:"flex-start",gap:4,fontSize:10,color:C.wn,marginTop:4}}><WarningIcon size={11} weight="fill" style={{flexShrink:0,marginTop:1}}/>Aún no hay clientes anticipo configurados. Pide a admin que active el cliente o que lo agregue a un pool existente.</div>}
      </div>

      <div style={{marginBottom:10}}>
        <label style={lbl}>PO Corona (ref del cliente) *</label>
        <input style={inp} value={externalPoRef} onChange={e=>setExternalPoRef(e.target.value)} placeholder="ej. 1234567890 (10 dígitos)"/>
      </div>

      {/* v10.43.28 — Folio fiscal con sugerencia + botón "Usar" (mismo patrón que InvoiceModal) */}
      <div style={{marginBottom:10}}>
        <label style={lbl}>Folio fiscal emitido *</label>
        <div style={{display:"flex",gap:6}}>
          <input
            style={{...inp,fontFamily:"'Geist Mono',monospace",fontWeight:700,textTransform:"uppercase",fontSize:14,letterSpacing:0.5,border:"1.5px solid "+(folioFiscal&&!folioValid?C.dn+"60":(folioIsLower?C.amb:C.bd))}}
            value={folioFiscal}
            onChange={e=>setFolioFiscal(e.target.value.toUpperCase().trim())}
            placeholder={(suggestedFolio||"D-XXXX").replace(/\d+$/,"XXXX")+" o R-XXXX"}
          />
          <button type="button" onClick={()=>{if(suggestedFolio)setFolioFiscal(suggestedFolio)}} disabled={!suggestedFolio} style={{...bt(C.sf,C.tx),padding:"0 14px",border:"0.5px solid "+C.bd,whiteSpace:"nowrap",opacity:suggestedFolio?1:0.5,cursor:suggestedFolio?"pointer":"not-allowed"}}>→ Usar {suggestedFolio||"…"}</button>
        </div>
        {folioFiscal&&!folioValid&&<div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,color:C.dn,marginTop:4}}><WarningIcon size={11} weight="fill"/>Formato inválido. Esperado: D-XXXX o R-XXXX</div>}
        {folioIsLower&&<div style={{display:"flex",alignItems:"flex-start",gap:4,fontSize:10,color:C.amb,marginTop:4,fontWeight:600}}><WarningIcon size={11} weight="fill" style={{flexShrink:0,marginTop:1}}/>Este folio es menor al último registrado ({suggestedFolio}). Continuará válido si está realmente emitido.</div>}
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
        <div>
          <label style={lbl}>Subtotal SIN IVA *</label>
          {/* v10.43.28 — onWheel=blur evita cambios accidentales por scroll del mouse */}
          <input style={inp} type="number" step="0.01" value={amount} onChange={e=>setAmount(e.target.value)} onWheel={e=>e.target.blur()} placeholder="300000.00 (el sistema agrega IVA)"/>
        </div>
        <div><label style={lbl}>Fecha programada de pago *</label><input style={inp} type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)}/></div>
      </div>

      {folioValid&&Number.isFinite(amountNum)&&amountNum>0&&(()=>{
        // v10.58.45: el preview debe espejar credit_deposit — ×1.16 SOLO si el folio
        // es factura (D-); una remisión (R-) cruza a cobranza SIN IVA.
        const isFacturaFolio=(folioClean||"").toUpperCase().startsWith("D-");
        const ivaPortion=isFacturaFolio?Math.round(amountNum*0.16*100)/100:0;
        const withIva=isFacturaFolio?Math.round(amountNum*1.16*100)/100:amountNum;
        return <div style={{padding:"12px 14px",background:C.emr+"10",border:"1px solid "+C.emr+"40",borderRadius:8,marginBottom:10}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:6}}>
          <div><div style={{fontSize:9,color:C.t2,textTransform:"uppercase",fontWeight:600}}>Subtotal (ledger)</div><div style={{fontSize:14,fontWeight:800,color:C.emr}}>${amountNum.toLocaleString("es-MX",{minimumFractionDigits:2})}</div></div>
          <div><div style={{fontSize:9,color:C.t2,textTransform:"uppercase",fontWeight:600}}>{isFacturaFolio?"+ IVA 16%":"Sin IVA (remisión)"}</div><div style={{fontSize:14,fontWeight:700,color:C.t2}}>${ivaPortion.toLocaleString("es-MX",{minimumFractionDigits:2})}</div></div>
          <div><div style={{fontSize:9,color:C.t2,textTransform:"uppercase",fontWeight:600}}>Total cobranza</div><div style={{fontSize:14,fontWeight:800,color:C.ac}}>${withIva.toLocaleString("es-MX",{minimumFractionDigits:2})}</div></div>
        </div>
        <div style={{fontSize:10,color:C.t2,lineHeight:1.4}}>Se crea {isFacturaFolio?"factura":"remisión"} <b>{folioClean}</b> en cobranza por <b>${withIva.toLocaleString("es-MX",{minimumFractionDigits:2})}</b> {isFacturaFolio?"con IVA":"sin IVA"} (lo que Cervecería paga). El saldo a favor interno se lleva en subtotal: <b>${amountNum.toLocaleString("es-MX",{minimumFractionDigits:2})}</b>. Vence {dueDateValid?new Date(dueDate+"T12:00:00").toLocaleDateString("es-MX",{day:"2-digit",month:"short",year:"numeric"}):"(fecha inválida)"}.</div>
      </div>;
      })()}

      {!dueDateValid&&dueDate&&<div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,color:C.dn,marginBottom:8}}><WarningIcon size={11} weight="fill"/>La fecha de pago debe ser futura.</div>}

      <div style={{marginBottom:14}}>
        <label style={lbl}>Notas (opcional)</label>
        <input style={inp} value={notas} onChange={e=>setNotas(e.target.value)} placeholder="Observaciones de la OC"/>
      </div>

      <div style={{display:"flex",gap:8}}>
        <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd}}>Cancelar</button>
        <button onClick={submit} disabled={!valid||busy} style={{...bt(C.emr),flex:1,justifyContent:"center",opacity:(valid&&!busy)?1:.4,cursor:(valid&&!busy)?"pointer":"not-allowed"}}>{busy?"Guardando…":<><FloppyDiskIcon size={14} weight="bold"/>Registrar OC a Crédito</>}</button>
      </div>
    </div>
  </div>;
}

function CreditAdjustModal({client, userLogin, onSave, onClose}) {
  useEscClose(onClose);
  const [monto,setMonto]=useState("");
  const [motivo,setMotivo]=useState("");
  // v10.54.7 — busy state + try/finally previene duplicados por click múltiple
  // (caso real 02-jun: Marcelo dio click 3 veces porque "no respondía" → 3 AJUSTEs duplicados en ledger).
  const [busy,setBusy]=useState(false);
  const n=parseFloat(monto);
  const valid=Number.isFinite(n)&&n!==0&&motivo.trim().length>=3;
  const canSubmit=valid&&!busy;
  // v10.56.1 I-C2: preview usa pool_balance (saldo real del pool) en lugar de current_balance,
  // que para miembros es 0. Sin esto, admin ajusta sobre EVA y ve "$0 → $5,000" cuando en
  // realidad el saldo del pool es $32k → $37k.
  const baseBalance=Number(client?.pool_balance||client?.current_balance||0);
  // v10.64.1 fix — el caller (CoronaModal) SIEMPRE pasa un LÍDER, así que el viejo
  // is_pool_leader===false era siempre false → banner muerto. Lo correcto: avisar cuando el
  // líder TIENE sub-cuentas (el ajuste afecta a todo el pool, no solo a este cliente).
  const affectsPool=client && Array.isArray(client.pool_members) && client.pool_members.length>0;
  const preview=valid?(baseBalance+n):baseBalance;
  const submit=async()=>{
    if(!canSubmit) return;
    setBusy(true);
    try{ await onSave(n, motivo.trim()); }
    finally{ setBusy(false); }
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
    <div style={{background:C.bg,borderRadius:20,padding:22,maxWidth:460,width:"94%"}}>
      <h3 style={{display:"flex",alignItems:"center",gap:8,fontSize:16,fontWeight:800,letterSpacing:"-0.008em",margin:"0 0 4px"}}><ChartBarIcon size={17} weight="bold"/>Ajuste manual de saldo</h3>
      <div style={{fontSize:12,color:C.t2,marginBottom:14}}>{client?.name}</div>
      {affectsPool && <div style={{padding:"10px 12px",background:C.amb+"15",border:"1.5px solid "+C.amb+"50",borderRadius:8,marginBottom:12,fontSize:11,color:"#a85a00",lineHeight:1.5}}>
        <WarningIcon size={13} weight="fill" style={{verticalAlign:"-2px",marginRight:4}}/>Este ajuste afecta a <b>TODO el pool</b>, NO solo a {client?.name}: comparte saldo con {client?.pool_members?.join(", ")}. Todas las sub-cuentas verán el mismo nuevo saldo (es compartido).
      </div>}
      <div style={{background:C.sf,borderRadius:10,padding:10,marginBottom:12,display:"flex",justifyContent:"space-between"}}>
        <div><div style={{fontSize:10,color:C.t2,textTransform:"uppercase"}}>{affectsPool?"Saldo del pool":"Actual"}</div><div style={{fontSize:16,fontWeight:800}}>${baseBalance.toLocaleString("es-MX",{minimumFractionDigits:2})}</div></div>
        <div style={{fontSize:24,color:C.t2,alignSelf:"center"}}>→</div>
        <div><div style={{fontSize:10,color:C.t2,textTransform:"uppercase"}}>Después</div><div style={{fontSize:16,fontWeight:800,color:preview<0?C.dn:C.ok}}>${preview.toLocaleString("es-MX",{minimumFractionDigits:2})}</div></div>
      </div>
      <div style={{marginBottom:10}}>
        <label style={lbl}>Monto (positivo suma, negativo resta) *</label>
        <input style={inp} type="number" step="0.01" value={monto} onChange={e=>setMonto(e.target.value)} placeholder="ej. +500 o -200" autoFocus disabled={busy}/>
      </div>
      <div style={{marginBottom:16}}>
        <label style={lbl}>Motivo (obligatorio, mínimo 3 caracteres) *</label>
        <input style={inp} value={motivo} onChange={e=>setMotivo(e.target.value)} placeholder="ej. Reverso de cobro duplicado" disabled={busy}/>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,opacity:busy?.5:1,cursor:busy?"wait":"pointer"}}>Cancelar</button>
        <button onClick={submit} disabled={!canSubmit} style={{...bt(canSubmit?"#f59e0b":"#9ca3af"),flex:1,justifyContent:"center",opacity:canSubmit?1:.6,cursor:canSubmit?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Aplicando...</>:<><ChartBarIcon size={14} weight="bold"/>Aplicar</>}</button>
      </div>
    </div>
  </div>;
}

// v10.41.0 — Chips redondos para filtrar "Mis Pendientes" con icono Phosphor + label + counter.
// Multi-select OR: si N chips activos, muestra órdenes que matchean al menos uno.
// Si 0 activos, muestra todos. Cuenta se calcula sobre las tasks PRE-filter para
// que el usuario siempre vea cuántas hay potencialmente en cada categoría.
function TaskFilterChips({filters,tasks,activeFilters,onToggle}){
  if(!filters||filters.length===0)return null;
  return <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:14}}>
    {filters.map(f=>{
      const count=tasks.filter(o=>{try{return f.predicate(o)}catch{return false}}).length;
      const isActive=activeFilters.has(f.key);
      const FIcon=f.Icon;
      return <button key={f.key} onClick={()=>onToggle(f.key)}
        style={{
          display:"inline-flex",alignItems:"center",gap:6,
          padding:"6px 14px",borderRadius:999,
          border:"1.5px solid "+(isActive?f.color:C.bd),
          background:isActive?f.color+"15":C.bg,
          color:isActive?f.color:C.t2,
          fontSize:12,fontWeight:isActive?700:500,
          cursor:"pointer",fontFamily:"'Geist',sans-serif",
          transition:"all .15s ease",
          opacity:count===0&&!isActive?.5:1,
        }}
        title={count===0?"Sin órdenes en esta categoría":f.label+" — "+count+" orden"+(count!==1?"es":"")}>
        {FIcon?<FIcon size={14} weight={isActive?"fill":"bold"}/>:null}
        <span>{f.label}</span>
        <span style={{
          background:isActive?f.color:C.bd+"60",
          color:isActive?"#fff":C.t2,
          padding:"1px 7px",borderRadius:999,
          fontSize:10,fontWeight:700,
          minWidth:18,textAlign:"center",
        }}>{count}</span>
      </button>;
    })}
  </div>;
}

// v10.40.0 — Modal unificado de "Regresar". Sustituye ReturnToCtpModal y DevolverModal.
// Opciones: 1 o 2 stages destino. Captura razón obligatoria. Side effects por stage destino
// se manejan en el handler revertOrder (no aquí).
function RevertOrderModal({order,options,onConfirm,onClose}){
  useEscClose(onClose);
  // options = [{value: 'ctp', label: '💿 CTP'}, ...] preformateadas con label legible
  const [target,setTarget]=useState(options?.[0]?.value||"");
  const [reason,setReason]=useState("");
  // v10.54.7 — busy state previene duplicados por click múltiple
  const [busy,setBusy]=useState(false);
  if(!options||options.length===0)return null;
  const valid=reason.trim()&&target;
  const canSubmit=valid&&!busy;
  const submit=async()=>{
    if(!canSubmit) return;
    setBusy(true);
    try{ await onConfirm(target, reason.trim()); }
    finally{ setBusy(false); }
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}>
    <div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:480,width:"90%",maxHeight:"90vh",overflowY:"auto"}}>
      <h3 style={{fontSize:16,fontWeight:700,margin:"0 0 6px",color:C.ctp,display:"flex",alignItems:"center",gap:6}}><ArrowUUpLeftIcon size={17} weight="bold"/>Regresar Orden</h3>
      <p style={{fontSize:12,color:C.t2,margin:"0 0 12px"}}>Elige el stage destino y captura la razón. El área responsable del destino será notificada.</p>
      <div style={{background:C.sf,borderRadius:10,padding:12,marginBottom:14}}>
        <div style={{fontSize:13,fontWeight:700}}>{order?.client}</div>
        <div style={{fontSize:11,color:C.t2}}>{order?.product_type}{order?.quantity?" · "+Number(order.quantity).toLocaleString()+" pzas":""}</div>
        {order?.production_number&&<div style={{fontSize:10,color:C.ac,fontWeight:600,marginTop:2}}>{order.production_number}</div>}
        <div style={{fontSize:10,color:C.t3,marginTop:4}}>Stage actual: <strong><StageLbl stage={order?.stage}/></strong></div>
      </div>

      {options.length===1?(
        <div style={{marginBottom:14,padding:"10px 12px",background:C.ctp+"10",border:"1px solid "+C.ctp+"30",borderRadius:8,fontSize:13}}>
          La orden regresará a: <strong style={{color:C.ctp}}>{options[0].label}</strong>
        </div>
      ):(
        <div style={{marginBottom:14}}>
          <label style={lbl}>Stage destino *</label>
          <div style={{display:"flex",flexDirection:"column",gap:6,marginTop:6}}>
            {options.map(o=>(
              <label key={o.value} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 12px",background:target===o.value?C.ctp+"10":C.sf,border:"1.5px solid "+(target===o.value?C.ctp:C.bd),borderRadius:8,cursor:"pointer",transition:"all .15s"}}>
                <input type="radio" name="revert-target" value={o.value} checked={target===o.value} onChange={()=>setTarget(o.value)} style={{cursor:"pointer"}}/>
                <span style={{fontSize:13,fontWeight:target===o.value?700:500,color:target===o.value?C.ctp:C.tx}}>{o.label}</span>
                {o.hint&&<span style={{fontSize:10,color:C.t3,marginLeft:"auto"}}>{o.hint}</span>}
              </label>
            ))}
          </div>
        </div>
      )}

      <div style={{marginBottom:16}}>
        <label style={lbl}>Razón del regreso *</label>
        <textarea
          style={{...inp,minHeight:80,resize:"vertical",border:"1.5px solid "+(reason.trim()?C.bd:"#f59e0b"+"40")}}
          value={reason}
          onChange={e=>setReason(e.target.value)}
          placeholder="Explica por qué se regresa (ej. placa rayada, archivo cambió, falta empaque, defecto detectado...)"
          autoFocus
        />
      </div>

      <div style={{display:"flex",gap:8}}>
        <button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,opacity:busy?.5:1,cursor:busy?"wait":"pointer"}}>Cancelar</button>
        <button onClick={submit} disabled={!canSubmit} style={{...bt(canSubmit?C.ctp:"#9ca3af"),flex:1,justifyContent:"center",opacity:canSubmit?1:.6,cursor:canSubmit?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Regresando...</>:<><ArrowUUpLeftIcon size={14} weight="bold"/>Regresar Orden</>}</button>
      </div>
    </div>
  </div>;
}

function CancelOrderModal({order,onConfirm,onClose}) {
  useEscClose(onClose);
  const [reason,setReason]=useState("");
  // v10.54.7 — busy state previene duplicados por click múltiple
  const [busy,setBusy]=useState(false);
  const valid=!!reason.trim();
  const canSubmit=valid&&!busy;
  const submit=async()=>{
    if(!canSubmit) return;
    setBusy(true);
    try{ await onConfirm(reason.trim()); }
    finally{ setBusy(false); }
  };
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:999}}><div style={{background:C.bg,borderRadius:20,padding:24,maxWidth:420,width:"90%",maxHeight:"90vh",overflowY:"auto"}}>
    <h3 style={{fontSize:16,fontWeight:700,margin:"0 0 6px",color:C.dn,display:"flex",alignItems:"center",gap:6}}><XCircleIcon size={17} weight="bold"/>Cancelar Orden</h3>
    <div style={{background:C.sf,borderRadius:10,padding:12,marginBottom:14}}>
      <div style={{fontSize:13,fontWeight:700}}>{order?.client}</div>
      <div style={{fontSize:11,color:C.t2}}>{order?.product_type}{order?.quantity?" · "+Number(order.quantity).toLocaleString()+" pzas":""}</div>
      {order?.production_number&&<div style={{fontSize:10,color:C.ac,fontWeight:600,marginTop:2}}>{order.production_number}</div>}
    </div>
    <p style={{fontSize:12,color:C.t2,margin:"0 0 14px"}}>Esta acción es permanente. La orden quedará marcada como cancelada y no se podrá revertir.</p>
    <div style={{marginBottom:16}}><label style={lbl}>Motivo de cancelación (obligatorio)</label><textarea style={{...inp,minHeight:80,resize:"vertical",border:"1.5px solid "+(reason.trim()?C.bd:C.dn+"40")}} value={reason} onChange={e=>setReason(e.target.value)} placeholder="¿Por qué se cancela esta orden?" disabled={busy}/></div>
    <div style={{display:"flex",gap:8}}><button onClick={onClose} disabled={busy} style={{...bt(C.sf,C.t2),flex:1,justifyContent:"center",border:"0.5px solid "+C.bd,opacity:busy?.5:1,cursor:busy?"wait":"pointer"}}>No, conservar</button><button onClick={submit} disabled={!canSubmit} style={{...bt(canSubmit?C.dn:"#9ca3af"),flex:1,justifyContent:"center",opacity:canSubmit?1:.6,cursor:canSubmit?"pointer":(busy?"wait":"not-allowed")}}>{busy?<><HourglassIcon size={14} weight="bold"/>Cancelando...</>:<><XCircleIcon size={14} weight="bold"/>Sí, Cancelar Orden</>}</button></div>
  </div></div>;
}

