            {!inEsperaView&&!compact&&o.paper_type&&<div style={{color:C.t3,fontSize:F.meta,marginTop:2}}><FileTextIcon size={10} weight="bold" style={{verticalAlign:"-1px",marginRight:3}}/>{o.paper_type}{o.paper_grammage?" "+o.paper_grammage+"g":""}{o.standard_size?" | "+ssLabel(o.standard_size):(o.width_cm?" | "+o.width_cm+"×"+o.height_cm+"cm":"")}{o.ink_front?" | F:"+o.ink_front:""}{o.ink_back?" V:"+o.ink_back:""}</div>}
